		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0517_1.html',
		'<p>תהלים קיט119: &quot;סִגִים הִשְׁבַּתָּ כָל רִשְׁעֵי אָרֶץ לָכֵן אָהַבְתִּי עֵדֹתֶיךָ&quot;</p><p>משלי כה4: &quot;הָגוֹ סִיגִים מִכָּסֶף וַיֵּצֵא לַצֹּרֵף כֶּלִי&quot;</p><p>משלי כה4-5: &quot;הָגוֹ סִיגִים מִכָּסֶף וַיֵּצֵא לַצֹּרֵף כֶּלִי הָגוֹ רָשָׁע לִפְנֵי מֶלֶךְ וְיִכּוֹן בַּצֶּדֶק כִּסְאוֹ&quot;</p><p>על כן.......</p><p>משלי כ8: &quot;מֶלֶךְ יוֹשֵׁב עַל כִּסֵּא דִין מְזָרֶה בְעֵינָיו כָּל רָע&quot; ----- להשבית כָל רִשְׁעֵי אָרֶץ</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-02-19 18:13:17'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>ספר הנביא ישעיהו פרק א כתוב:</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים.  </p><p>כב כַּסְפֵּךְ הָיָה לְסִיגִים סָבְאֵךְ מָהוּל בַּמָּיִם.  </p><p>כג שָׂרַיִךְ סוֹרְרִים וְחַבְרֵי גַּנָּבִים כֻּלּוֹ אֹהֵב שֹׁחַד וְרֹדֵף שַׁלְמֹנִים יָתוֹם לֹא יִשְׁפֹּטוּ וְרִיב אַלְמָנָה לֹא-יָבוֹא אֲלֵיהֶם.  </p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל  הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי.  </p><p>כה וְאָשִׁיבָה יָדִי עָלַיִךְ וְאֶצְרֹף כַּבֹּר סִיגָיִךְ וְאָסִירָה כָּל-בְּדִילָיִךְ.  </p><p>כו וְאָשִׁיבָה שֹׁפְטַיִךְ כְּבָרִאשֹׁנָה וְיֹעֲצַיִךְ כְּבַתְּחִלָּה אַחֲרֵי-כֵן יִקָּרֵא לָךְ עִיר הַצֶּדֶק קִרְיָה נֶאֱמָנָה. </p><p>כז צִיּוֹן בְּמִשְׁפָּט תִּפָּדֶה וְשָׁבֶיהָ בִּצְדָקָה.  </p><p>כח וְשֶׁבֶר פֹּשְׁעִים וְחַטָּאִים יַחְדָּו וְעֹזְבֵי יְהוָה יִכְלוּ.</p><p>-</p><p>עמוס ט10: &quot;בַּחֶרֶב יָמוּתוּ כֹּל חַטָּאֵי עַמִּי הָאֹמְרִים לֹא תַגִּישׁ וְתַקְדִּים בַּעֲדֵינוּ הָרָעָה&quot;</p><p>מיכה ד8: &quot;וְאַתָּה מִגְדַּל עֵדֶר עֹפֶל בַּת צִיּוֹן עָדֶיךָ תֵּאתֶה וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים&quot;</p><p>-</p><p>עתה באור לפרש לכם</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים. --- זאת הממשלה האחרונה ממשלת ימין שקר</p><p>תהלים קמד8: &quot;אֲשֶׁר פִּיהֶם דִּבֶּר שָׁוְא וִימִינָם יְמִין שָׁקֶר&quot; אלה הם אנשי הממשלה האחרונה ממשלת ימין שקר וכל תומכיהם הרשעים כולל כל הרבנים אשר חרפו את משיח יהוה</p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי. --- לאמור כי תהיה נקמה באויבי יהוה</p><p>ואחרי כן ---  וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-02-22 06:18:01'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>ספר הנביא ישעיהו פרק א כתוב:</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים.</p><p>כב כַּסְפֵּךְ הָיָה לְסִיגִים סָבְאֵךְ מָהוּל בַּמָּיִם.</p><p>כג שָׂרַיִךְ סוֹרְרִים וְחַבְרֵי גַּנָּבִים כֻּלּוֹ אֹהֵב שֹׁחַד וְרֹדֵף שַׁלְמֹנִים יָתוֹם לֹא יִשְׁפֹּטוּ וְרִיב אַלְמָנָה לֹא-יָבוֹא אֲלֵיהֶם.</p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי.</p><p>כה וְאָשִׁיבָה יָדִי עָלַיִךְ וְאֶצְרֹף כַּבֹּר סִיגָיִךְ וְאָסִירָה כָּל-בְּדִילָיִךְ.</p><p>כו וְאָשִׁיבָה שֹׁפְטַיִךְ כְּבָרִאשֹׁנָה וְיֹעֲצַיִךְ כְּבַתְּחִלָּה אַחֲרֵי-כֵן יִקָּרֵא לָךְ עִיר הַצֶּדֶק קִרְיָה נֶאֱמָנָה.</p><p>כז צִיּוֹן בְּמִשְׁפָּט תִּפָּדֶה וְשָׁבֶיהָ בִּצְדָקָה.</p><p>כח וְשֶׁבֶר פֹּשְׁעִים וְחַטָּאִים יַחְדָּו וְעֹזְבֵי יְהוָה יִכְלוּ.</p><p>-</p><p>עמוס ט10: &quot;בַּחֶרֶב יָמוּתוּ כֹּל חַטָּאֵי עַמִּי הָאֹמְרִים לֹא תַגִּישׁ וְתַקְדִּים בַּעֲדֵינוּ הָרָעָה&quot;</p><p>מיכה ד8: &quot;וְאַתָּה מִגְדַּל עֵדֶר עֹפֶל בַּת צִיּוֹן עָדֶיךָ תֵּאתֶה וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים&quot;</p><p>-</p><p>עתה באור לפרש לכם</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים. --- זאת הממשלה האחרונה ממשלת ימין שקר</p><p>תהלים קמד8: &quot;אֲשֶׁר פִּיהֶם דִּבֶּר שָׁוְא וִימִינָם יְמִין שָׁקֶר&quot; אלה הם אנשי הממשלה האחרונה ממשלת ימין שקר וכל תומכיהם הרשעים כולל כל הרבנים אשר חרפו את יהוה ומשיחו</p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי. --- לאמור כי תהיה נקמה באויבי יהוה</p><p>ואחרי כן --- וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-02-22 06:20:06'
		)
		;

