		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2821_2.html',
		'<p>אחיי הקדושים כל עם-יהוה</p><p>המלחמה בגוג מארץ המגוג תהיה צבאית-רוחנית</p><p>חיל-צבאו של גוג וכל המונו לא יבואו בחרבות ברזל כי אם בחרבות בשפתותיהם</p><p>תהלים נט8: &quot;הִנֵּה יַבִּיעוּן בְּפִיהֶם חֲרָבוֹת בְּשִׂפְתוֹתֵיהֶם כִּי מִי שֹׁמֵעַ&quot;</p><p>הם יבואו בליל שבת יעמדו על רגליהם ויקללו את עם הקודש בחירי-יהוה</p><p>כי ראו כי הצלחת עם-יהוה בזכות שמירתו את הקודש ואין להכריעו בכלי מלחמה</p><p>אם בימי קדם בא בלעם בן-בעור הקוסם לקלל ויצא מברך את ישראל</p><p>הפעם הזאת נביאי-הגוים אֵין פַּחַד אֱלֹהִים לְנֶגֶד עֵינָיו ויעמדו לקלל את עם-הקודש </p><p>תהלים לו2: &quot;נְאֻם פֶּשַׁע לָרָשָׁע בְּקֶרֶב לִבִּי אֵין פַּחַד אֱלֹהִים לְנֶגֶד עֵינָיו&quot;</p><p>עתה אמליץ לכם להסיר כל רשע מקרב לבכם למען תהיה לכם יראת אלהים</p><p>הבדילו בין הטמא לטהור ושמרו את הקודש וכן את יום שבת קודש</p><p>גברו על כל פיתוי וניסיון אשר ינסה אותכם אלהים כי יבחנכם למען לברור הצדיקים</p><p>ישעיהו ד3: &quot;וְהָיָה הַנִּשְׁאָר בְּצִיּוֹן וְהַנּוֹתָר בִּירוּשָׁלַים קָדוֹשׁ יֵאָמֶר לוֹ כָּל הַכָּתוּב לַחַיִּים בִּירוּשָׁלַים&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-02 07:26:55'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

