		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/kma/hvdlim1/jal-bqj.html',
		'<p>ההבדל הוא</p><p>כשאתה שואל ממישהו משהו עליך להחזיר להשיב את הפיקדון ששאלת מאיתו-מעמו אך כשאתה מבקש משהו זה לתמיד</p><p>למשל--- אם הבן פונה לאביו ואומר אבא תשאיל לי את הרכב לכמה שעות או למספר ימים ואשיב לך את הרכב</p><p>או אם הבן אומר לאביו אבא אני מבקש את הרכב --- אז בשפה התנכית זה לתמיד מבלי צורך להחזיר</p><p>-</p><p> תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי</p><p> תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי ------- כי את נפשי עלי להשיב לאלהים בבוא העת</p><p> וְעַמִּי בְּבַקָּשָׁתִי ------- כי עמי ישראל זה לנצח ישאר עמי</p><p>-</p><p>שמואל א א20: &quot;וַיְהִי לִתְקֻפוֹת הַיָּמִים וַתַּהַר חַנָּה וַתֵּלֶד בֵּן וַתִּקְרָא אֶת שְׁמוֹ שְׁמוּאֵל כִּי מיהוה שְׁאִלְתִּיו&quot;</p><p>שמואל א א27: &quot;אֶל הַנַּעַר הַזֶּה הִתְפַּלָּלְתִּי וַיִּתֵּן יהוה לִי אֶת שָׁאַלְתִּי אֲשֶׁר שְׁאֵלָתִי מֵעִמּוֹ&quot; [לאמור כי עלי להשיבו לאלהים בבוא העת-במותו]</p><p>שמואל א א27-28: &quot;אֶל הַנַּעַר הַזֶּה הִתְפַּלָּלְתִּי וַיִּתֵּן יהוה לִי אֶת שָׁאַלְתִּי אֲשֶׁר שְׁאֵלָתִי מֵעִמּוֹ וְגַם אָנֹכִי הִשְׁאִלְתִּהוּ ליהוה כָּל הַיָּמִים אֲשֶׁר הָיָה הוּא שָׁאוּל ליהוה וַיִּשְׁתַּחוּ שָׁם ליהוה&quot;</p><p> </p><p>לשאול ממך משהו זה זמני לתקופת זמן מה ועלי להשיב בבוא העת</p><p>לבקש ממך משהו זה על פי רוב לתמיד</p><p>לדרוש ממך משהו זה תובעני בנחרצות בתוקף וכמובן לתמיד</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-03 21:40:22'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/ljon_jorj_ed2_0.html',
		'<p>מעניין אם אפשר לפרש באופן דומה את  שופטים ה7-8: &quot;חָדֵלּוּ פְרָזוֹן בְּיִשְׂרָאֵל *חָדֵלּוּ עַד* שַׁקַּמְתִּי דְּבוֹרָה שַׁקַּמְתִּי אֵם בְּיִשְׂרָאֵל&quot;.</p>',
		'117606350813040384070',
