		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0529_4.html',
		'<p>כשהיה גן-העדן לאדם הראשון הוא לא שמע בקול אלהים לבלתי אכול מפרי עץ הדעת</p><p>ובדור של היום כשהארץ נחרבה וגן-העדן אבוד דווקא עתה יש הרבה דעת</p><p>לאמור כי יש יחס כזה </p><p>כי ככל שגן-העדן אבוד אנשים משתוקקים לשוב לאלהים</p><p>וככל שהארץ דומה לגן-עדן יש סיכוי גדול לחטאים</p><p>בראשית יג10: &quot;וַיִּשָּׂא לוֹט אֶת עֵינָיו וַיַּרְא אֶת כָּל כִּכַּר הַיַּרְדֵּן כִּי כֻלָּהּ מַשְׁקֶה לִפְנֵי שַׁחֵת יהוה אֶת סְדֹם וְאֶת עֲמֹרָה כְּגַן יהוה כְּאֶרֶץ מִצְרַיִם בֹּאֲכָה צֹעַר&quot;</p><p>כשהארץ דומה לגן־עדן — האדם עלול לשכוח את רגישותו.</p><p>וכשהארץ נהרסת — האדם מתעורר ומחפש את אלוהיו.</p><p>המקרא מציג קשר הדוק בין מצב הארץ לבין מצב האדם:</p><p>כשיש שפע ויופי — האדם עלול להתגאות, לשכוח, להתנתק.</p><p>כשיש חורבן, בצורת, שבר — האדם מתעורר, מתכנס, מחפש תיקון.</p><p>גן עדן — יופי מושלם → חטא.</p><p>כיכר הירדן — “כְּגַן יהוה” → סדום.</p><p>ובדור שבימינו כשנחרבה הארץ ואין חי וצומח בערים הזעקה של האדם אמיתית וזה מה שמוביל לדעת-אלהים</p><p>וכשתהיה דעת אלהים זה יוביל לגן עדן ועושר הגן-עדן יוביל לחטא כי לא לנבונים עושר</p><p>כל זה הוא מחזור טבע ביקום ובאנושות</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-13 04:57:15'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
