		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0103_4.html',
		'<p>כשהיה גן-העדן לאדם הראשון הוא לא שמע בקול אלהים לבלתי אכול מפרי עץ הדעת</p><p>ובדור של היום כשהארץ נחרבה וגן-העדן אבוד דווקא עתה יש הרבה דעת</p><p>לאמור כי יש יחס כזה</p><p>כי ככל שגן-העדן אבוד אנשים משתוקקים לשוב לאלהים</p><p>וככל שהארץ דומה לגן-עדן יש סיכוי גדול לחטאים</p><p>בראשית יג10: &quot;וַיִּשָּׂא לוֹט אֶת עֵינָיו וַיַּרְא אֶת כָּל כִּכַּר הַיַּרְדֵּן כִּי כֻלָּהּ מַשְׁקֶה לִפְנֵי שַׁחֵת יהוה אֶת סְדֹם וְאֶת עֲמֹרָה כְּגַן יהוה כְּאֶרֶץ מִצְרַיִם בֹּאֲכָה צֹעַר&quot;</p><p>כשהארץ דומה לגן־עדן — האדם עלול לשכוח את רגישותו.</p><p>וכשהארץ נהרסת — האדם מתעורר ומחפש את אלוהיו.</p><p>המקרא מציג קשר הדוק בין מצב הארץ לבין מצב האדם:</p><p>כשיש שפע ויופי — האדם עלול להתגאות, לשכוח, להתנתק.</p><p>כשיש חורבן, בצורת, שבר — האדם מתעורר, מתכנס, מחפש תיקון.</p><p>גן עדן — יופי מושלם → חטא.</p><p>כיכר הירדן — “כְּגַן יהוה” → סדום.</p><p>ובדור שבימינו כשנחרבה הארץ ואין חי וצומח בערים הזעקה של האדם אמיתית וזה מה שמוביל לדעת-אלהים</p><p>וכשתהיה דעת אלהים זה יוביל לגן עדן ועושר הגן-עדן יוביל לחטא כי לא לנבונים עושר</p><p>כל זה הוא מחזור טבע ביקום ובאנושות</p><p>-</p><p>לכן העשירים באותיות רשעים</p><p>והעניים המה אשר יהללו את האלהים ---------- ממש כמו בדור העוני הסביבתי הזה של חורבן הארץ</p><p>תהלים עד21: &quot;אַל יָשֹׁב דַּךְ נִכְלָם עָנִי וְאֶבְיוֹן יְהַלְלוּ שְׁמֶךָ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-13 05:07:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0108_1.html',
		'<p>ויקרא כג14: &quot;וְלֶחֶם וְקָלִי וְכַרְמֶל....... לֹא תֹאכְלוּ עַד עֶצֶם הַיּוֹם הַזֶּה עַד הֲבִיאֲכֶם אֶת קָרְבַּן אֱלֹהֵיכֶם חֻקַּת עוֹלָם לְדֹרֹתֵיכֶם בְּכֹל מֹשְׁבֹתֵיכֶם&quot;</p><p>יהושע ה11-12: &quot;וַיֹּאכְלוּ מֵעֲבוּר הָאָרֶץ מִמָּחֳרָת הַפֶּסַח מַצּוֹת וְקָלוּי.......בְּעֶצֶם הַיּוֹם הַזֶּה וַיִּשְׁבֹּת הַמָּן מִמָּחֳרַת בְּאָכְלָם מֵעֲבוּר הָאָרֶץ וְלֹא הָיָה עוֹד לִבְנֵי יִשְׂרָאֵל מָן וַיֹּאכְלוּ מִתְּבוּאַת אֶרֶץ כְּנַעַן בַּשָּׁנָה הַהִיא&quot;</p><p>בני ישראל קצרו קציר-שעורים לאפיית מצות לפני פסח</p><p>לאמור כי יום הנפת העומר הוא לפני פסח</p><p>הוא הדבר אשר אמרתי כי יום הנפת העומר ממחרת השבת הראשונה לאחר ראש חודש האביב [סביבות] יום השיויון ולפני חג הפסח וזאת כדי שיוכלו לאכול מצות מקציר השעורים מן התבואה של השנה החדשה ואם יום הנפת העומר היה אחרי חג המצות איכה יוכלו בני ישראל לאכול מצות בפסח מן התבואה של השנה החדשה</p><p>ואם התשובה תהיה שעליהם לאכול מתבואה הישנה הלא בני ישראל היו עדיין בשנת 40 במדבר ולא היה קציר בשנה הקודמת לשנת כניסתם לארץ כנען</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-14 16:54:09'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0108_1.html',
		'<p>ויקרא כג14: &quot;וְלֶחֶם וְקָלִי וְכַרְמֶל....... לֹא תֹאכְלוּ עַד עֶצֶם הַיּוֹם הַזֶּה עַד הֲבִיאֲכֶם אֶת קָרְבַּן אֱלֹהֵיכֶם חֻקַּת עוֹלָם לְדֹרֹתֵיכֶם בְּכֹל מֹשְׁבֹתֵיכֶם&quot;</p><p>יהושע ה11-12: &quot;וַיֹּאכְלוּ מֵעֲבוּר הָאָרֶץ מִמָּחֳרָת הַפֶּסַח מַצּוֹת וְקָלוּי.......בְּעֶצֶם הַיּוֹם הַזֶּה וַיִּשְׁבֹּת הַמָּן מִמָּחֳרַת בְּאָכְלָם מֵעֲבוּר הָאָרֶץ וְלֹא הָיָה עוֹד לִבְנֵי יִשְׂרָאֵל מָן וַיֹּאכְלוּ מִתְּבוּאַת אֶרֶץ כְּנַעַן בַּשָּׁנָה הַהִיא&quot;</p><p>בני ישראל קצרו קציר-שעורים לאפיית מצות לפני פסח --- לאמור כי יום הנפת העומר הוא לפני פסח</p><p>הוא הדבר אשר אמרתי כי יום הנפת העומר ממחרת השבת הראשונה לאחר ראש חודש האביב [סביבות] יום השיויון ולפני חג הפסח וזאת כדי שיוכלו לאכול מצות מקציר השעורים מן התבואה של השנה החדשה ואם יום הנפת העומר היה אחרי חג המצות איכה יוכלו בני ישראל לאכול מצות בפסח מן התבואה של השנה החדשה</p><p>ואם התשובה תהיה שעליהם לאכול מתבואה הישנה הלא בני ישראל היו עדיין בשנת 40 במדבר ולא היה קציר בשנה הקודמת לשנת כניסתם לארץ כנען</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-14 16:55:00'
		)
		;

