		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0108_1.html',
		'<p>חודש מרס בלוח הלועזי מקביל לחודש האביב בלוח השמש</p><p>כאשר פסח-חג המצות הוא יום השיויון באמצע חודש מרס במחצית חודש האביב כפי שכתוב בתורה</p><p>אם 1 למרס הוא הוא ראש חודש האביב כעת 15 למרס חג-המצות אשר כולו באביב כל שבעת ימי חג המצות</p><p>וממחרת השבת שאחרי שביעי של פסח לאמור בתאריך 22 לחודש הוא יום הנפת העומר</p><p>וכעבור 49 יום חג השבועות שיוצא בזמן בחודש מאי</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-15 06:08:01'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

