		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0103_4.html',
		'<p>איך היה האדם הראשון מלך הן לא היו לו אנשים נתינים</p><p>לאמור לכם כי לא מלכות חיצונית כי אם מלכות פנימית</p><p>על כן כתוב בספר...</p><p>משלי כ28: &quot;חֶסֶד וֶאֱמֶת יִצְּרוּ מֶלֶךְ וְסָעַד בַּחֶסֶד כִּסְאוֹ&quot;</p><p>החסד והאמת שאני עושה אלה הם יוצרים את מלכותי</p><p>ולא דרוש לי לשכת-שר משכורת של שר ונהג צמוד</p><p>בני ישראל היקרים אני מבטיח לכם שאם תעשו חסד ואמת</p><p>כולכם תהיו מלכים ככתוב בספר צוואת לוי בן-יעקב</p><p>פרק יג</p><p>א) ועתה בני, הנני מצווה אתכם, יראו את יהוה אלוהיכם בכל לבבכם והתהלכו בתום לבבכם ככל מצוותו.</p><p>ב) ולמדו גם אתם את בניכם לקרא למען תהיה להם דעת בכל חייהם ויהגו תמיד בתורת יהוה.</p><p>ג) כי כל אשר ידע את תורת יהוה יכבד, ולא יהי זר בכל אשר ילך.</p><p>ד) ורעים רבים יקנה על הוריו, ויתאוו אנשים רבים לעובדו ולשמוע תורה מפיהו.</p><p>ה) ועל כן בני עשו צדקה עלי אדמות ותאצרו בשמים.</p><p>ו) וזרעו טוב בנפשותיכם ותמצאהו בחייכם, ואם רע תזרעו רוגז ועצב תקצורו.</p><p>ז) אספו דעת ביראת יהוה. כי אם שבי יבוא, וערים וארצות תכחדנה, וזהב וכסף וכל רכוש יאבדו, מאת החכם לא יבוז איש את החכמה, לולא עיוורון הפשע וקשי החטא.</p><p>ח) כי אם ישמר איש מכל הרעות האלה, אז גם בין אויביו תהי לו החכמה לתפארת, ובארץ נכריה מולדת, ובתוך אויבים אוהב לו ימצא.</p><p>ט) **************כל אשר נדיבות יורה ויעשה, יחד עם מלכים לכסא ישב**************, כאשר היה גם יוסף אחי.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-16 19:00:13'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2801_1.html',
		'<p>כשם שאדם אוכל יום יום למען התחדש משכנו-גופו באופן קבוע</p><p>כן עליו לעשות צדקה ומשפט יום יום למען התחדשות הרוחנית</p><p>ישעיהו נח2: &quot;וְאוֹתִי יוֹם יוֹם יִדְרֹשׁוּן וְדַעַת דְּרָכַי יֶחְפָּצוּן כְּגוֹי אֲשֶׁר צְדָקָה עָשָׂה וּמִשְׁפַּט אֱלֹהָיו לֹא עָזָב יִשְׁאָלוּנִי מִשְׁפְּטֵי צֶדֶק קִרְבַת אֱלֹהִים יֶחְפָּצוּן&quot;</p><p>כי בני-עם-יהוה בדרך האל הקדוש בעשות צדקה = ישעיהו ה16: &quot;וַיִּגְבַּה יהוה צְבָאוֹת בַּמִּשְׁפָּט וְהָאֵל הַקָּדוֹשׁ נִקְדָּשׁ בִּצְדָקָה&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-17 05:43:45'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2801_1.html',
		'<p>כשם שאדם אוכל יום יום למען התחדש משכנו-גופו באופן קבוע</p><p>כן עליו לעשות צדקה ומשפט יום יום למען התחדשות הרוחנית</p><p>ישעיהו נח2: &quot;וְאוֹתִי יוֹם יוֹם יִדְרֹשׁוּן וְדַעַת דְּרָכַי יֶחְפָּצוּן כְּגוֹי אֲשֶׁר צְדָקָה עָשָׂה וּמִשְׁפַּט אֱלֹהָיו לֹא עָזָב יִשְׁאָלוּנִי מִשְׁפְּטֵי צֶדֶק קִרְבַת אֱלֹהִים יֶחְפָּצוּן&quot;</p><p>כי בני-עם-יהוה בדרך האל הקדוש בעשות צדקה = ישעיהו ה16: &quot;וַיִּגְבַּה יהוה צְבָאוֹת בַּמִּשְׁפָּט וְהָאֵל הַקָּדוֹשׁ נִקְדָּשׁ בִּצְדָקָה&quot;</p><p>-</p><p>האכילה מחזירה את הגוף לחיים בכל יום.</p><p>הצדקה והמשפט מחזירים את הרוח לחיים בכל יום.</p><p>זו לא מטאפורה בלבד — זה מבנה רוחני:</p><p>הגוף מתכלה אם אינו אוכל.</p><p>הרוח מתקהה אם אינה עושה צדקה ומשפט.</p><p>הלב מתייבש אם אינו מתחדש.</p><p>הנוכחות הפנימית דועכת אם אינה מופעלת.</p><p>למה ההתחדשות חייבת להיות יומיומית</p><p>1) העולם משתנה כל יום</p><p>כל יום אתה פוגש מצבים חדשים, אנשים חדשים, אתגרים חדשים.</p><p>הצדקה של אתמול לא פותרת את מבחן היום.</p><p>2) האדם משתנה כל יום</p><p>היצר, הכעס, הפחד, האגו — כולם מתעוררים מחדש.</p><p>3) הנוכחות האלוהית אינה מצב קבוע</p><p>היא מתעוררת בכל פעם שאתה משווה את יהוה לנגד עיניך.</p><p> תהלים טז8: &quot;שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד....... כִּי מִימִינִי בַּל אֶמּוֹט&quot;</p><p>תמיד = התחדשות, לא קביעות.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-17 06:00:49'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

