		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>הלוח הלועזי בחודשיו חופף ללוח שכתבתי לכם</p><p>------------------------------------------------------</p><p>מרס -- חופף לחודש הראשון האביב</p><p>אפריל -- חופף לחודש השני</p><p>מאי -- חופף לחודש השלשי</p><p>יוני -- חופף לחודש הרביעי</p><p>יולי -- חופף לחודש החמישי</p><p>אוגוסט -- חופף לחודש הששי</p><p>ספטמ-בר --חופף לחודש השביעי</p><p>אוקטו-בר -- חופף לחודש השמיני</p><p>נובמ-בר -- חופף לחודש התשיעי</p><p>דצמבר -- חופף לחודש העשירי</p><p>ינואר -- חופף לחודש אחד-עשר</p><p>פברואר -- חופף לחודש שנים-עשר</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-18 06:08:22'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0310_2.html',
		'<p>שמות יב9: &quot;אַל תֹּאכְלוּ מִמֶּנּוּ נָא וּבָשֵׁל מְבֻשָּׁל בַּמָּיִם כִּי אִם צְלִי אֵשׁ רֹאשׁוֹ עַל כְּרָעָיו וְעַל קִרְבּוֹ&quot; </p><p>דברי הימים ב לה13: &quot;וַיְבַשְּׁלוּ הַפֶּסַח בָּאֵשׁ כַּמִּשְׁפָּט וְהַקֳּדָשִׁים בִּשְּׁלוּ בַּסִּירוֹת וּבַדְּוָדִים וּבַצֵּלָחוֹת וַיָּרִיצוּ לְכָל בְּנֵי הָעָם&quot;</p><p>בישול הבשר בָּאֵשׁ כַּמִּשְׁפָּט --- זה הדבר הכון לעשות על פי יהוה וזה משפט התורה</p><p>-</p><p>לאחרונה התפרסם שנערים אוכלים בשר חי ---- ואני דיין מודיע לכם כי זה אסור על פי התורה</p><p>https://www.mako.co.il/health-news/Article-390df70a41c3c91026.htm?utm_source=copilot.com</p><p> </p><p>שמואל א ב15: &quot;גַּם בְּטֶרֶם יַקְטִרוּן אֶת הַחֵלֶב וּבָא נַעַר הַכֹּהֵן וְאָמַר לָאִישׁ הַזֹּבֵחַ תְּנָה בָּשָׂר לִצְלוֹת לַכֹּהֵן וְלֹא יִקַּח מִמְּךָ בָשָׂר מְבֻשָּׁל כִּי אִם חָי&quot; </p><p>שמואל א ב16: &quot;וַיֹּאמֶר אֵלָיו הָאִישׁ קַטֵּר יַקְטִירוּן כַּיּוֹם הַחֵלֶב וְקַח לְךָ כַּאֲשֶׁר תְּאַוֶּה נַפְשֶׁךָ וְאָמַר לו[לֹא] כִּי עַתָּה תִתֵּן וְאִם [לֹא] לָקַחְתִּי בְחָזְקָה&quot;</p><p>שמואל א ב17: &quot;וַתְּהִי חַטַּאת הַנְּעָרִים גְּדוֹלָה מְאֹד אֶת פְּנֵי יהוה כִּי נִאֲצוּ הָאֲנָשִׁים אֵת מִנְחַת יהוה&quot;</p><p>-</p><p> </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-18 06:30:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

