		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1201_1.html',
		'<p>https://www.youtube.com/watch?v=F2GvcNxF1F4</p><p> תהלים עז14: ***&quot;אֱלֹהִים בַּקֹּדֶשׁ דַּרְכֶּךָ*** מִי אֵל גָּדוֹל כֵּאלֹהִים&quot;</p><p>תהלים עז20: ***&quot;בַּיָּם דַּרְכֶּךָ*** ושביליך[וּשְׁבִילְךָ] בְּמַיִם רַבִּים וְעִקְּבוֹתֶיךָ לֹא נֹדָעוּ&quot;</p><p>******* אֱלֹהִים בַּקֹּדֶשׁ דַּרְכֶּךָ = בַּיָּם דַּרְכֶּךָ *******</p><p>---------------------------------------------------------</p><p>שמות טו10: &quot;נָשַׁפְתָּ בְרוּחֲךָ ***כִּסָּמוֹ יָם*** צָלֲלוּ כַּעוֹפֶרֶת בְּמַיִם אַדִּירִים&quot;</p><p>משלי י12: &quot;שִׂנְאָה תְּעוֹרֵר מְדָנִים ***וְעַל כָּל פְּשָׁעִים תְּכַסֶּה אַהֲבָה&quot;***</p><p>******* כִּסָּמוֹ יָם = וְעַל כָּל פְּשָׁעִים תְּכַסֶּה אַהֲבָה *******</p><p>------------------------------------------------------------------------------------</p><p>על כן .......קֹּדֶשׁ = יָּם = אַהֲבָה</p><p>וכדי שתדעו לזכור זאת ------- בַּקֹּדֶשׁ = ים אהבה</p><p>על כן גם.......</p><p>שָׁמָיִם = שָׁמָ-יִם = שָׁם-יִם [שם-מים]</p><p>כי............שם-אהבה = שָׁם-יִם [בַּיָּם דַּרְכֶּךָ] = שם בַּקֹּדֶשׁ [דַּרְכֶּךָ]</p><p>******* בַּשָּׁמַיִם = שם בַּקֹּדֶשׁ = שם-ים = שם-אהבה *******</p><p>------------------------------------------------------------------------------</p><p>ואגיד ככה כדי שתזכרו זאת ........ בַּשָּׁמַיִם = שם בַּקֹּדֶשׁ = ים אהבה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-18 07:09:55'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1201_1.html',
		'<p>שיר קודש המדבר על גלי הים</p><p>https://www.youtube.com/watch?v=F2GvcNxF1F4</p><p>תהלים עז14: ***&quot;אֱלֹהִים בַּקֹּדֶשׁ דַּרְכֶּךָ*** מִי אֵל גָּדוֹל כֵּאלֹהִים&quot;</p><p>תהלים עז20: ***&quot;בַּיָּם דַּרְכֶּךָ*** ושביליך[וּשְׁבִילְךָ] בְּמַיִם רַבִּים וְעִקְּבוֹתֶיךָ לֹא נֹדָעוּ&quot;</p><p>******* אֱלֹהִים בַּקֹּדֶשׁ דַּרְכֶּךָ = בַּיָּם דַּרְכֶּךָ *******</p><p>---------------------------------------------------------</p><p>שמות טו10: &quot;נָשַׁפְתָּ בְרוּחֲךָ ***כִּסָּמוֹ יָם*** צָלֲלוּ כַּעוֹפֶרֶת בְּמַיִם אַדִּירִים&quot;</p><p>משלי י12: &quot;שִׂנְאָה תְּעוֹרֵר מְדָנִים ***וְעַל כָּל פְּשָׁעִים תְּכַסֶּה אַהֲבָה&quot;***</p><p>******* כִּסָּמוֹ יָם = וְעַל כָּל פְּשָׁעִים תְּכַסֶּה אַהֲבָה *******</p><p>------------------------------------------------------------------------------------</p><p>על כן .......קֹּדֶשׁ = יָּם = אַהֲבָה</p><p>וכדי שתדעו לזכור זאת ------- בַּקֹּדֶשׁ = ים אהבה</p><p>על כן גם.......</p><p>שָׁמָיִם = שָׁמָ-יִם = שָׁם-יִם [שם-מים]</p><p>כי............שם-אהבה = שָׁם-יִם [בַּיָּם דַּרְכֶּךָ] = שם בַּקֹּדֶשׁ [דַּרְכֶּךָ]</p><p>******* בַּשָּׁמַיִם = שם בַּקֹּדֶשׁ = שם-ים = שם-אהבה *******</p><p>------------------------------------------------------------------------------</p><p>ואגיד ככה כדי שתזכרו זאת ........ בַּשָּׁמַיִם = שם בַּקֹּדֶשׁ = ים אהבה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-18 07:10:56'
		)
		;

