		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0529_4.html',
		'<p>דברי הימים ב לו16: </p><p>&quot;וַיִּהְיוּ מַלְעִבִים בְּמַלְאֲכֵי הָאֱלֹהִים וּבוֹזִים דְּבָרָיו וּמִתַּעְתְּעִים בִּנְבִאָיו עַד עֲלוֹת חֲמַת יהוה בְּעַמּוֹ עַד לְאֵין מַרְפֵּא&quot;</p><p>קהלת ג3: &quot;עֵת לַהֲרוֹג וְעֵת לִרְפּוֹא עֵת לִפְרוֹץ וְעֵת לִבְנוֹת&quot;</p><p>תהלים עח34: &quot;אִם הֲרָגָם וּדְרָשׁוּהוּ וְשָׁבוּ וְשִׁחֲרוּ אֵל&quot;</p><p>-באור לפרש הסבר</p><p> עַד עֲלוֹת חֲמַת יהוה בְּעַמּוֹ עַד לְאֵין מַרְפֵּא --- ואם זו לא עת לִרְפּוֹא אז זאת עֵת לַהֲרוֹג ואִם הֲרָגָם וּדְרָשׁוּהוּ וְשָׁבוּ וְשִׁחֲרוּ אֵל</p><p>סוף דבר</p><p>אלהים ישיב את החוטאים בדרך זו או אחרת</p><p>אני מורה לתורה משה דין כותב לכם בשם אלהים גם אם מבזים דבריו ומתעתעים בנביאיו ואתם שמעוני כי כבר עֲלוֹת חֲמַת יהוה בְּעַמּוֹ</p><p>אני כעבד-יהוה המשקף את רצון יהוה מרגיש זאת היטב וגם האנטישמיות הגואה בגויים מעידה [כנמשל ומשל] על חֲמַת יהוה בְּעַמּוֹ</p><p>תהלים כב29: &quot;כִּי ליהוה הַמְּלוּכָה וּמֹשֵׁל בַּגּוֹיִם&quot; ---- [וזה המשל והנמשל] יהוה כועס על עמו ולכן הגויים כועסים על ישראל </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-18 19:45:19'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

