		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0529_4.html',
		'<p>הבל יושב אהלים היה רועה צאן</p><p>וקין היה איש נדלן והוא כעס שהבל בא לשדה לרעות את הצאן במקום שקין חשב לבנות עיר</p><p>ובגלל זה בנו של קין בנה עיר בשמו חנוך </p><p>בראשית ד8: &quot;וַיֹּאמֶר קַיִן אֶל הֶבֶל אָחִיו וַיְהִי בִּהְיוֹתָם בַּשָּׂדֶה וַיָּקָם קַיִן אֶל הֶבֶל אָחִיו וַיַּהַרְגֵהוּ&quot; </p><p>בראשית ד17: &quot;וַיֵּדַע קַיִן אֶת אִשְׁתּוֹ וַתַּהַר וַתֵּלֶד אֶת חֲנוֹךְ וַיְהִי בֹּנֶה עִיר וַיִּקְרָא שֵׁם הָעִיר כְּשֵׁם בְּנוֹ חֲנוֹךְ&quot; </p><p>לצערי ישראל הולכת בדרכו של קיין</p><p>יש טיפוסי נשמה, של דרכי חיים, ושל שני נתיבים רוחניים:</p><p>נתיב האוהל ונתיב העיר.</p><p>נתיב הרועה ונתיב הצייד.</p><p>נתיב האוהל והרועה --- ונתיב הצייד והעיר</p><p>נתיב הבל–יעקב–שם מול נתיב קין–עשו–כנען.</p><p>קין — בונה אדמה, בונה עיר</p><p>קין הוא: “עֹבֵד אֲדָמָה”</p><p>אדם של רכוש</p><p>אדם של גבולות</p><p>אדם של שליטה</p><p>אדם של קניין</p><p>אדם של בנייה חומרית</p><p>והוא כועס כשהבל “נכנס לשדה שלו”.</p><p>“קין היה איש נדל״ן… וכעס שהבל בא לשדה לרעות הצאן במקום שקין חשב לבנות עיר.”</p><p>הבל — חי.</p><p>קין — בונה.</p><p>הבל — אוהל.</p><p>קין — עיר.</p><p>הבל — טבע.</p><p>קין — קניין.</p><p>הבל — רועה.</p><p>קין — שולט.</p><p>3. לכן בנו של קין בונה עיר</p><p>בראשית ד׳ 17:</p><p>“וַיְהִי בֹנֶה עִיר וַיִּקְרָא שֵׁם הָעִיר כְּשֵׁם בְּנוֹ חֲנוֹךְ.”</p><p>העיר הראשונה בתורה —</p><p>נבנית על ידי צאצא של קין.</p><p>עיר = קבע - שליטה - כוח - גבולות - אגו - חומר</p><p>אוהל = פשטות - אמת - צניעות - פתיחות - נבואה</p><p>הבל — אוהל.</p><p>קין — עיר.</p><p>יעקב — אוהל.</p><p>עשו — שדה.</p><p>שם — אוהל.</p><p>כנען — עיר.</p><p>הדפוס חוזר.</p><p> 4. “יַפְתְּ אֱלֹהִים לְיֶפֶת וְיִשְׁכֹּן בְּאָהֳלֵי שֵׁם”</p><p>בראשית ט׳ 27:</p><p>“יִשְׁכֹּן בְּאָהֳלֵי שֵׁם.”</p><p>“אוהלי שם = אלהי שם (בחילופי אותיות).”</p><p>אוהל = מקום השראת שכינה</p><p>יהוה שוכן באוהל.= הנביאים שוכנים באוהל. = הצדיקים שוכנים באוהל.</p><p>“אוהלי שם” = אוהלי קדושה = אוהלי נבואה = אוהלי אמת = אוהלי תורה</p><p>שם — הוא אבי הנבואה.ממנו יוצאים: כל אבותינו הקדושים שוכני אהלים כולם אברהם יצחק יעקב משה ואהרן שמואל דוד</p><p>כולם אנשי אוהלים.</p><p>הבל — רועה, אוהל, קדושה</p><p>יעקב — תם, אוהלים, טל, נבואה</p><p>שם — אוהלים, השראת שכינה</p><p>משה — אוהל מועד</p><p>יהוה — “מאוהל אל אוהל” ככתוב בספר הנביא שמואל ב ז6: &quot;כִּי לֹא יָשַׁבְתִּי בְּבַיִת לְמִיּוֹם הַעֲלֹתִי אֶת בְּנֵי יִשְׂרָאֵל מִמִּצְרַיִם וְעַד הַיּוֹם הַזֶּה וָאֶהְיֶה מִתְהַלֵּךְ בְּאֹהֶל וּבְמִשְׁכָּן&quot;</p><p>אוהל הוא: פתוח לא חומרי ארעי זמני לא קבוע חדיר לרוח מקום של צניעות ופשטות מקום של אמת מקום של השראה</p><p> </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-24 18:03:01'
		)
		;

SET character_set_client=utf8mb3;
