		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0231_0.html',
		'<p>שמירת שבת בדרכו של איש ישראל </p><p>האידיאל של שבת בישראל הוא בית מלא חיים, משפחה ברוכת ילדים סביב שולחן-השבת ושיחה של תורה על פרשת השבוע.</p><p>אך דרכי החיים אינן אחידות, ויש אנשים ששומרים שבת מתוך מציאות שונה — מציאות שאינה תמיד פשוטה או מוקפת משפחה וקהילה.</p><p>גם במצבים כאלה ניתן לגלות עונג שבת פנימי ולקיים קדושה אמיתית. אצל אנשים כאלה, שמירת השבת אינה תלויה בטקסים חברתיים משפחתיים או במסגרת קבועה, </p><p>אלא במאמץ כן ליצור קשר רוחני: לימוד, התבוננות, מחשבה טובה או עיסוק בדברי תורה — מתוך רצון להוציא יקר מזולל ולמצוא אור בתוך מציאות מורכבת.</p><p>זו אינה חתירה לשלמות חיצונית, אלא נאמנות פנימית.</p><p>זו עבודת-אלהים של אדם הפועל בכל כוחו, כמאמר הכתוב בשם יעקב אבינו: “בְּכָל כֹּחִי עָבַדְתִּי”.</p><p>כך נראית שמירת שבת של אמת: שקטה, פנימית, כנה —ונובעת מלב המבקש קדושה בתוך חייו כפי שהם.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-04 16:49:19'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/daian2_0.html',
		'<p></p><p>המקרא מגיד כי **דֶּרֶךְ יְהוָה בַּמְּרוֹמִים**,  </p><p>כַּאֲשֶׁר נֶאֱמַר:  **“כִּי כֹה אָמַר רָם וְנִשָּׂא שֹׁכֵן עַד וְקָדוֹשׁ שְׁמוֹ: מָרוֹם וְקָדוֹשׁ אֶשְׁכּוֹן וְאֶת־דַּכָּא וּשְׁפַל־רוּחַ.”**  (ישעיהו נ״ז 15)</p><p>וְהָאָרֶץ נִתְּנָה לָאָדָם **לָדַעַת דַּרְכֵי יְהוָה**,  כַּאֲשֶׁר כָּתוּב:  **“לָדַעַת בָּאָרֶץ דַּרְכֶּךָ; בְּכָל־גּוֹיִם יְשׁוּעָתֶךָ.”**  (תהלים ס״ז 3)</p><p>וַיְהִי הָאָדָם חַי בָּאָרֶץ לִלְמֹד אֶת דַּרְכֵי יְהוָה,  </p><p>לַעֲמֹד בַּנִּסָּיוֹן,  לָשׁוּב וּלְתַקֵּן נַפְשׁוֹ, לְמַעַן יִזְכֶּה לָשֶׁבֶת בַּמְּרוֹמִים עִם אֱלֹהָיו.</p><p>וּבְכָל יְמֵי הַהֲלִיכָה הַזֹּאת **יְהוָה לֹא רָחוֹק**,  כַּאֲשֶׁר הֵעִיד יְהוֹשֻׁעַ:  **“בְּזֹאת תֵּדְעוּן כִּי אֵל חַי בְּקִרְבְּכֶם, וְהוֹרֵשׁ יוֹרִישׁ מִפְּנֵיכֶם אֶת הַכְּנַעֲנִי…”**  (יהושע ג׳ 10)</p><p>וַיְהִי יְהוָה אֱלֹהֵי יִשְׂרָאֵל **בְּקֶרֶב עַמּוֹ**,  לְהַנְחוֹתָם בַּדֶּרֶךְ,  לְחַזֵּק יְדֵיהֶם,  וּלְהַחֲיוֹת נַפְשָׁם.</p><p>וְהָעֲרָגָה אֶל יְהוָה — **עֲבוֹדַת הַחַיִּים הִיא**,  </p><p>כַּאֲשֶׁר נֶאֱמַר:  </p><p>**“כְּאַיָּל תַּעֲרֹג עַל־אֲפִיקֵי־מָיִם כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים.  </p><p>צָמְאָה נַפְשִׁי לֵאלֹהִים לְאֵל חָי; מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים?”**  (תהלים מ״ב 2–3)</p><p>וְדָוִד לֹא בִּקֵּשׁ מָוֶת לִרְאוֹת פְּנֵי יְהוָה,  כִּי אִם לִרְאוֹתָם **בְּחַיָּיו**.</p><p>וְהַתִּקְוָה אֶל יְהוָה — **מִצְוַת חַיִּים**,  כַּאֲשֶׁר נֶאֱמַר:  **“קַוֵּה אֶל־יְהוָה; חֲזַק וְיַאֲמֵץ לִבֶּךָ — וְקַוֵּה אֶל־יְהוָה.”**  (תהלים כ״ז 14)</p><p>וְהָיָה הַדָּבָר הַזֶּה לְעֵדוּת:</p><p>דֶּרֶךְ יְהוָה — בַּמְּרוֹמִים.  </p><p>קורס הַהֲכָשָׁרָה — בָּאָרֶץ.  </p><p>יְהוָה — בְּקִרְבֵּנוּ.  </p><p>הָעֲרָגָה — בַּחַיִּים.  </p><p>וְהַתִּקְוָה — מִצְוָה.</p><p>וְאַתָּה, בֶּן־אָדָם אַל־תֹּאמַר נוֹאָשׁ  </p><p>וְקַוֵּה אֶל־יְהוָה — אֶל אֵל חָי.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-05 04:50:40'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

