		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3204_0.html',
		'<p>בספר בראשית פרק לח כתוב:</p><p>כז וַיְהִי בְּעֵת לִדְתָּהּ וְהִנֵּה תְאוֹמִים בְּבִטְנָהּ.  </p><p>כח וַיְהִי בְלִדְתָּהּ וַיִּתֶּן-יָד וַתִּקַּח הַמְיַלֶּדֶת וַתִּקְשֹׁר עַל-יָדוֹ שָׁנִי לֵאמֹר זֶה יָצָא רִאשֹׁנָה.  </p><p>כט וַיְהִי כְּמֵשִׁיב יָדוֹ וְהִנֵּה יָצָא אָחִיו וַתֹּאמֶר מַה-פָּרַצְתָּ עָלֶיךָ פָּרֶץ וַיִּקְרָא שְׁמוֹ פָּרֶץ.  </p><p>ל וְאַחַר יָצָא אָחִיו אֲשֶׁר עַל-יָדוֹ הַשָּׁנִי וַיִּקְרָא שְׁמוֹ זָרַח</p><p>זרח לא בטח באלהים כי מישש בידו לבחון מה קורה בחוץ ואז בחוסר בטחון באלהים השיב את ידו חזרה לרחם</p><p>ובמקומו יצא פרץ אשר ממנו בא המשיח ואתה דע כי אלהים שילם לזרח ופקד עליו עוונו בדור הרביעי</p><p>יהושע ז1: &quot;וַיִּמְעֲלוּ בְנֵי יִשְׂרָאֵל מַעַל בַּחֵרֶם וַיִּקַּח עָכָן בֶּן כַּרְמִי בֶן זַבְדִּי בֶן זֶרַח לְמַטֵּה יְהוּדָה מִן הַחֵרֶם וַיִּחַר אַף יהוה בִּבְנֵי יִשְׂרָאֵל&quot; </p><p>יהושע ז18: &quot;וַיַּקְרֵב אֶת בֵּיתוֹ לַגְּבָרִים וַיִּלָּכֵד עָכָן בֶּן כַּרְמִי בֶּן זַבְדִּי בֶן זֶרַח לְמַטֵּה יְהוּדָה&quot; </p><p>----------</p><p>שמות כ4: &quot;לֹא תִשְׁתַּחְוֶה לָהֶם וְלֹא תָעָבְדֵם כִּי אָנֹכִי יהוה אֱלֹהֶיךָ אֵל קַנָּא פֹּקֵד עון אָבֹת עַל בָּנִים עַל שִׁלֵּשִׁים וְעַל רִבֵּעִים לְשֹׂנְאָי&quot;.......</p><p>מלאכי א3: &quot;וְאֶת עֵשָׂו שָׂנֵאתִי....... וָאָשִׂים אֶת הָרָיו שְׁמָמָה וְאֶת נַחֲלָתוֹ לְתַנּוֹת מִדְבָּר&quot;</p><p>איוב לא יכול להיות דור ראשון שני שלישי או רביעי לעשיו השנוא כי אלהים אהב את איוב ופקד עליו ברכה</p><p>איוב מב12: &quot;ויהוה בֵּרַךְ אֶת אַחֲרִית אִיּוֹב....... מֵרֵאשִׁתוֹ וַיְהִי לוֹ אַרְבָּעָה עָשָׂר אֶלֶף צֹאן וְשֵׁשֶׁת אֲלָפִים גְּמַלִּים וְאֶלֶף צֶמֶד בָּקָר וְאֶלֶף אֲתוֹנוֹת&quot;</p><p>ואם איוב לא היה מבני עשיו אז האופציה היחידה שאיוב היה ממשפחת צאצאי נחור אחי אברהם</p><p>על כן אליהו בן ברכאל הבוזי ממשפחת א-רם מי שהוכיח את איוב הוא ממשפחתו של א-רם בן-נחור אחי אברהם</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-05 10:17:40'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

