		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3109_0.html',
		'<p>קהלת ז12: &quot;כִּי בְּצֵל הַחָכְמָה בְּצֵל הַכָּסֶף וְיִתְרוֹן דַּעַת הַחָכְמָה תְּחַיֶּה בְעָלֶיהָ&quot;</p><p>קהלת ז12: &quot;כִּי בְּצֵל הַחָכְמָה = בְּצֵל הַכָּסֶף </p><p>------------------------ חָכְמָה = כָּסֶף ----------------------- וְהַכֶּסֶף יַעֲנֶה אֶת הַכֹּל</p><p>וְיִתְרוֹן דַּעַת הַחָכְמָה תְּחַיֶּה בְעָלֶיהָ&quot;</p><p>תהלים קיח18: &quot;יַסֹּר יִסְּרַנִּי יָּהּ וְלַמָּוֶת לֹא נְתָנָנִי&quot;</p><p>הייתי קרוב למות אך דעת החכמה נתנה לי חיים</p><p>לא קיבלתי חינם את החכמה</p><p>אלהים נתן לי חכמה למען החיות את נפשי כי ראה בסבלי בעוניי</p><p>ועתה אני כותב לכם דברי חכמה להושיע נַפְשׁוֹת אֶבְיוֹנִים</p><p>תהלים עב13: &quot;יָחֹס עַל דַּל וְאֶבְיוֹן וְנַפְשׁוֹת אֶבְיוֹנִים יוֹשִׁיעַ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-05 18:00:59'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

