		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/daian.html',
		'<p>דַּיָּן־שֵׁם הוֹלֵךְ בְּדֶרֶךְ יְהוָה</p><p>אֵינוֹ נוֹטֵל שָׂכָר עַל דְּבַר־אֱמֶת</p><p>רַק מְקַבֵּל תְּרוּמַת לֵב מִי שֶׁהָאוֹר נָגַע בּוֹ.</p><p>-</p><p>ברכה לתומכי דיין-שם עבד-יהוה</p><p>בספר שמות כ5: &quot;וְעֹשֶׂה חֶסֶד לַאֲלָפִים לְאֹהֲבַי וּלְשֹׁמְרֵי מצותי&quot;</p><p>ודיין שם הולך בדרך יהוה על כן דיין-שם עושה חסד לאוהביו</p><p>תהלים קיט74: &quot;יְרֵאֶיךָ יִרְאוּנִי וְיִשְׂמָחוּ כִּי לִדְבָרְךָ יִחָלְתִּי&quot;</p><p>תהלים לה27: &quot;יָרֹנּוּ וְיִשְׂמְחוּ חֲפֵצֵי צִדְקִי וְיֹאמְרוּ תָמִיד יִגְדַּל יהוה הֶחָפֵץ שְׁלוֹם עַבְדּוֹ&quot;</p><p>http://tora.us.fm/tnk1/daian</p><p>דַיָּן שֵׁם --- דרך הקודש</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 05:43:58'
		)
		;

