		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/ktuv/thlim/th-79-01.html',
		'<p>החרפה שלנו באה מהשכנים שלנו כאן בארץ ובכלל במזרח התיכון</p><p>תהלים עט12: &quot;וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי&quot;</p><p>החרפה כאן היא לא רק על ישראל —אלא על מלכות יהוה בעולם.</p><p>תהלים פט52: &quot;אֲשֶׁר חֵרְפוּ אוֹיְבֶיךָ יהוה אֲשֶׁר חֵרְפוּ עִקְּבוֹת מְשִׁיחֶךָ&quot;</p><p>תהלים סט10: &quot;כִּי קִנְאַת בֵּיתְךָ אֲכָלָתְנִי וְחֶרְפּוֹת חוֹרְפֶיךָ נָפְלוּ עָלָי&quot; </p><p>החרפה שמכוונת כלפי יהוה — נופלת על מי שנושא את שמו.</p><p>-------------------------------------------------------------------------</p><p>במדבר לג55: &quot;וְאִם לֹא תוֹרִישׁוּ אֶת יֹשְׁבֵי הָאָרֶץ מִפְּנֵיכֶם </p><p>וְהָיָה אֲשֶׁר תּוֹתִירוּ מֵהֶם לְשִׂכִּים בְּעֵינֵיכֶם וְלִצְנִינִם בְּצִדֵּיכֶם וְצָרֲרוּ אֶתְכֶם עַל הָאָרֶץ אֲשֶׁר אַתֶּם יֹשְׁבִים בָּהּ&quot;</p><p>-</p><p>לסיכום</p><p>השכנים בארצנו צוררים אותנו</p><p>והשכנים במזרח התיכון מחרפים אותנו</p><p>-</p><p>אבל ברכת אלהי אבותינו הקדושים ככתוב:</p><p>בראשית יב3: &quot;וַאֲבָרֲכָה מְבָרְכֶיךָ וּמְקַלֶּלְךָ אָאֹר....... וְנִבְרְכוּ בְךָ כֹּל מִשְׁפְּחֹת הָאֲדָמָה&quot; </p><p>בראשית כז29: &quot;יַעַבְדוּךָ עַמִּים וישתחו[וְיִשְׁתַּחֲווּ] לְךָ לְאֻמִּים הֱוֵה גְבִיר לְאַחֶיךָ [וְיִשְׁתַּחֲווּ] לְךָ בְּנֵי אִמֶּךָ אֹרְרֶיךָ אָרוּר....... וּמְבָרֲכֶיךָ בָּרוּךְ&quot; </p><p>במדבר כד9: &quot;כָּרַע שָׁכַב כַּאֲרִי וּכְלָבִיא מִי יְקִימֶנּוּ מְבָרֲכֶיךָ בָרוּךְ וְאֹרְרֶיךָ אָרוּר&quot;.......</p><p>------------- אך הברכות האלה רק אם נלך בדרך אלהי אבותינו הקדושים</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 14:25:49'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>אני זוכר שבשנת תשמ&quot;ד אמרו הרבנים שנת תשמ&quot;ד זה השמדה וסוף העולם וגאולה ומשיח</p><p>בכל שנה קמים רבני עם הארץ ומתעתעים בעם דברי כזב על גאולה ומשיח כי עם ישראל סובל ומצפה לסוף יסוריו אבל האמת שעולם כמנהגו נוהג</p><p>לאמור יש מלחמות ויש עוני ללא הפסקה : &quot;כִּי לֹא יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ עַל כֵּן אָנֹכִי מְצַוְּךָ לֵאמֹר פָּתֹחַ תִּפְתַּח אֶת יָדְךָ לְאָחִיךָ לַעֲנִיֶּךָ וּלְאֶבְיֹנְךָ בְּאַרְצֶךָ&quot; (דברים טו11)</p><p>ואם לֹא יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ....... אז לאיזה גאולה אתם מצפים גאולה רק לעשירים?</p><p>מלכים א ח46: &quot;כִּי יֶחֶטְאוּ לָךְ כִּי אֵין אָדָם אֲשֶׁר לֹא יֶחֱטָא....... וְאָנַפְתָּ בָם וּנְתַתָּם לִפְנֵי אוֹיֵב וְשָׁבוּם שֹׁבֵיהֶם אֶל אֶרֶץ הָאוֹיֵב רְחוֹקָה אוֹ קְרוֹבָה&quot;</p><p>דברי הימים ב ו36: &quot;כִּי יֶחֶטְאוּ לָךְ כִּי אֵין אָדָם אֲשֶׁר לֹא יֶחֱטָא....... וְאָנַפְתָּ בָם וּנְתַתָּם לִפְנֵי אוֹיֵב וְשָׁבוּם שׁוֹבֵיהֶם אֶל אֶרֶץ רְחוֹקָה אוֹ קְרוֹבָה&quot;</p><p>-</p><p>******* לכן רק במות האדם זה אחרית הימים אז יחדל החטא &quot;יִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם&quot; :(תהלים קד35:)******* </p><p>  </p><p> ------------------------------------ קהלת ז20: &quot;כִּי אָדָם אֵין צַדִּיק בָּאָרֶץ אֲשֶׁר יַעֲשֶׂה טּוֹב וְלֹא יֶחֱטָא&quot;  ------------------------------------</p><p> </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 16:24:06'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>אני זוכר שבשנת (1984) התשמ&quot;ד אמרו הרבנים שנת תשמ&quot;ד זה השמדה וסוף העולם וגאולה ומשיח</p><p>בכל שנה קמים רבני עם הארץ ומתעתעים בעם דברי כזב על גאולה ומשיח כי עם ישראל סובל ומצפה לסוף יסוריו אבל האמת שעולם כמנהגו נוהג</p><p>לאמור יש מלחמות ויש עוני ללא הפסקה : &quot;כִּי לֹא יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ עַל כֵּן אָנֹכִי מְצַוְּךָ לֵאמֹר פָּתֹחַ תִּפְתַּח אֶת יָדְךָ לְאָחִיךָ לַעֲנִיֶּךָ וּלְאֶבְיֹנְךָ בְּאַרְצֶךָ&quot; (דברים טו11)</p><p>ואם לֹא יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ....... אז לאיזה גאולה אתם מצפים גאולה רק לעשירים?</p><p>מלכים א ח46: &quot;כִּי יֶחֶטְאוּ לָךְ כִּי אֵין אָדָם אֲשֶׁר לֹא יֶחֱטָא....... וְאָנַפְתָּ בָם וּנְתַתָּם לִפְנֵי אוֹיֵב וְשָׁבוּם שֹׁבֵיהֶם אֶל אֶרֶץ הָאוֹיֵב רְחוֹקָה אוֹ קְרוֹבָה&quot;</p><p>דברי הימים ב ו36: &quot;כִּי יֶחֶטְאוּ לָךְ כִּי אֵין אָדָם אֲשֶׁר לֹא יֶחֱטָא....... וְאָנַפְתָּ בָם וּנְתַתָּם לִפְנֵי אוֹיֵב וְשָׁבוּם שׁוֹבֵיהֶם אֶל אֶרֶץ רְחוֹקָה אוֹ קְרוֹבָה&quot;</p><p>-</p><p>******* לכן רק במות האדם זה אחרית הימים אז יחדל החטא &quot;יִתַּמּוּ חַטָּאִים מִן הָאָרֶץ וּרְשָׁעִים עוֹד אֵינָם&quot; :(תהלים קד35:)*******</p><p>------------------------------------ קהלת ז20: &quot;כִּי אָדָם אֵין צַדִּיק בָּאָרֶץ אֲשֶׁר יַעֲשֶׂה טּוֹב וְלֹא יֶחֱטָא&quot; ------------------------------------</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 16:29:03'
		)
		;

