		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2637_0.html',
		'<p>משלי כא21: &quot;רֹדֵף צְדָקָה וָחָסֶד יִמְצָא חַיִּים צְדָקָה וְכָבוֹד&quot;</p><p>תהלים לד11: &quot;כְּפִירִים רָשׁוּ וְרָעֵבוּ וְדֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב&quot;</p><p>זאת עבודת יהוה לרדוף צְדָקָה וָחָסֶד ולדרוש יהוה</p><p>ועל פי הסדר הזה....... </p><p>כי קודם כל לעשות צדקה וחסד עם הדל ואחרי כן לקרוא ליהוה</p><p>כי אם חלילה לא תעשה צדקה וחסד עם הדל הזועק..אז.......</p><p>משלי כא13: &quot;אֹטֵם אָזְנוֹ מִזַּעֲקַת דָּל גַּם הוּא יִקְרָא וְלֹא יֵעָנֶה&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 17:40:20'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0533_4.html',
		'<p>בספר תורת משה כתוב:</p><p>דברים טו7: &quot;כִּי יִהְיֶה בְךָ אֶבְיוֹן מֵאַחַד אַחֶיךָ בְּאַחַד שְׁעָרֶיךָ בְּאַרְצְךָ אֲשֶׁר ה\' אֱלֹהֶיךָ נֹתֵן לָךְ לֹא תְאַמֵּץ אֶת לְבָבְךָ וְלֹא תִקְפֹּץ אֶת יָדְךָ מֵאָחִיךָ הָאֶבְיוֹן&quot; </p><p>דברים טו8: &quot;כִּי פָתֹחַ תִּפְתַּח אֶת יָדְךָ לוֹ וְהַעֲבֵט תַּעֲבִיטֶנּוּ דֵּי מַחְסֹרוֹ אֲשֶׁר יֶחְסַר לוֹ&quot;</p><p>בספר חכמת שלמה כתוב:</p><p>משלי כא21: &quot;רֹדֵף צְדָקָה וָחָסֶד יִמְצָא חַיִּים צְדָקָה וְכָבוֹד&quot;</p><p>בספר תהילות דויד כתוב:</p><p>תהלים לד11: &quot;כְּפִירִים רָשׁוּ וְרָעֵבוּ וְדֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב&quot;</p><p>זאת עבודת יהוה לרדוף צְדָקָה וָחָסֶד ולדרוש יהוה</p><p>ועל פי הסדר הזה.......</p><p>כי קודם כל לעשות צדקה וחסד עם הדל והאביון ואחרי כן לקרוא ליהוה</p><p>כי אם חלילה לא תעשה צדקה וחסד עם הדל הזועק......אז.......</p><p>משלי כא13: &quot;אֹטֵם אָזְנוֹ מִזַּעֲקַת דָּל גַּם הוּא יִקְרָא וְלֹא יֵעָנֶה&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 17:54:21'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

