		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0518_2.html',
		'<p>מלאכי ג10: &quot;הָבִיאוּ אֶת כָּל הַמַּעֲשֵׂר אֶל בֵּית הָאוֹצָר וִיהִי טֶרֶף בְּבֵיתִי וּבְחָנוּנִי נָא בָּזֹאת אָמַר יהוה צְבָאוֹת אִם לֹא אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי&quot; </p><p>יחזקאל א1: &quot;וַיְהִי בִּשְׁלֹשִׁים שָׁנָה בָּרְבִיעִי בַּחֲמִשָּׁה לַחֹדֶשׁ וַאֲנִי בְתוֹךְ הַגּוֹלָה עַל נְהַר כְּבָר נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים&quot;</p><p>אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי =  נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים&quot;</p><p> **************************** בְּרָכָה עַד בְּלִי דָי =  מַרְאוֹת אֱלֹהִים  ****************************</p><p>מַרְאוֹת אֱלֹהִים  ---דרך מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם ---- ולא תקשור עם המתים</p><p>תהלים יט9: &quot;פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-09 04:28:39'
		)
		;

