		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1402_2.html',
		'<p>מאת דיין עבד־האלהים</p><p>“אני מאמין בארץ ישראל השלמה — כל ארץ כנען.</p><p>אבל אינני יכול להעניק אותה לידיים של מי שהחריבו את הארץ שכבר בידיהם.</p><p>הבטון, הצפיפות והנדל״ן של גוש דן אינם אהבת הארץ — הם פגיעה בה.</p><p>אהבת הארץ אינה רק גבולות — היא אחריות על היופי, על הטבע, על הבריאה.”</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-09 09:15:28'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

