		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0526_3.html',
		'<p>דברי הימים ב לא4: &quot;וַיֹּאמֶר לָעָם לְיוֹשְׁבֵי יְרוּשָׁלַים לָתֵת מְנָת הַכֹּהֲנִים וְהַלְוִיִּם לְמַעַן יֶחֶזְקוּ בְּתוֹרַת יהוה&quot;</p><p>הבו לי מְנָת הַכֹּהֲנִים וְהַלְוִיִּם לְמַעַן אחזק בְּתוֹרַת יהוה ואם לא דעו כי יש לי דרך לְהִתְחַזֵּק עִם לְבָבי שָׁלֵם אֵלָיו</p><p>דברי הימים ב טז9: &quot;כִּי יהוה עֵינָיו מְשֹׁטְטוֹת בְּכָל הָאָרֶץ לְהִתְחַזֵּק עִם לְבָבָם שָׁלֵם אֵלָיו&quot;.............................</p><p>------------------------------------------------------------------------------------------------------------------------</p><p>הפסוק הראשון מדבר על כך שהכהנים והלויים זקוקים ל“מנתם” כדי שיוכלו להתחזק בתורת יהוה.</p><p>לעיתים אני מוצא את עצמי מהרהר בפסוק הזה —</p><p>אשר גם אני, בדרכי הצנועה מבקש את חלקי כדי שאוכל להמשיך להתחזק בתורת יהוה.</p><p>ואף על פי כן, גם אם אין מי שייתן, אני זוכר את מה שנאמר:</p><p>“כִּי יהוה עֵינָיו מְשׁוֹטְטוֹת בְּכָל הָאָרֶץ לְהִתְחַזֵּק עִם לְבָבָם שָׁלֵם אֵלָיו”  (דברי הימים ב ט״ז 9) הפסוק הזה מלווה אותי שנים רבות.</p><p>הוא מזכיר לי שהחיזוק האמיתי אינו תלוי בבני אדם, אלא בקשר שבין האדם לבין קונו.</p><p>ואם לבי שלם אליו — הוא ייתן לי את הכוח להמשיך גם בלי “מנת הכהנים והלויים”.</p><p>או שאת מְנָת הַכֹּהֲנִים וְהַלְוִיִּם יתן לי בדרך אחרת בדרך אשר יהוה ימצא לנכון</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-09 17:36:15'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0526_3.html',
		'<p>קהלת ז7: &quot;כִּי הָעֹשֶׁק יְהוֹלֵל חָכָם וִיאַבֵּד אֶת לֵב מַתָּנָה&quot;.......</p><p>במדבר יח7: &quot;וְאַתָּה וּבָנֶיךָ אִתְּךָ תִּשְׁמְרוּ אֶת כְּהֻנַּתְכֶם לְכָל דְּבַר הַמִּזְבֵּחַ וּלְמִבֵּית לַפָּרֹכֶת וַעֲבַדְתֶּם עֲבֹדַת מַתָּנָה....... אֶתֵּן אֶת כְּהֻנַּתְכֶם וְהַזָּר הַקָּרֵב יוּמָת&quot;</p><p> עֲבֹדַת מַתָּנָה = היא עֲבֹדַת לֵב מַתָּנָה ------- כי ככה יש לעבוד את האלהים מכל הלב --- וגם אתם יכולים לקחת חלקכם בתתכם תרומתי מנדבת הלב</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 04:55:14'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0526_3.html',
		'<p>קהלת ז7: &quot;כִּי הָעֹשֶׁק יְהוֹלֵל חָכָם וִיאַבֵּד אֶת לֵב מַתָּנָה&quot;.......</p><p>במדבר יח7: &quot;וְאַתָּה וּבָנֶיךָ אִתְּךָ תִּשְׁמְרוּ אֶת כְּהֻנַּתְכֶם לְכָל דְּבַר הַמִּזְבֵּחַ וּלְמִבֵּית לַפָּרֹכֶת וַעֲבַדְתֶּם עֲבֹדַת מַתָּנָה....... אֶתֵּן אֶת כְּהֻנַּתְכֶם וְהַזָּר הַקָּרֵב יוּמָת&quot;</p><p>עֲבֹדַת מַתָּנָה = היא עֲבֹדַת לֵב מַתָּנָה ------- כי ככה יש לעבוד את האלהים מכל הלב --- וגם אתם יכולים לקחת חלקכם בתתכם תרומתי מנדבת הלב</p><p>----------------------------------------------------------------------------------------------------------------------------------------------------------------------</p><p>עתה אתן לכם דרך נוספת לשמור על ***לֵב-מַתָּנָה*** ----------- שימו לב לפסוקים הבאים:</p><p>קהלת ז7: &quot;כִּי הָעֹשֶׁק יְהוֹלֵל חָכָם וִיאַבֵּד אֶת לֵב מַתָּנָה&quot;.......לכן הייה אתה חכם ועשה הפוך ככתוב:</p><p>תהלים עב4: &quot;יִשְׁפֹּט עֲנִיֵּי עָם יוֹשִׁיעַ לִבְנֵי אֶבְיוֹן וִידַכֵּא עוֹשֵׁק&quot; : &quot;כִּי הָעֹשֶׁק יְהוֹלֵל חָכָם וִיאַבֵּד אֶת לֵב מַתָּנָה&quot;[קהלת ז7]</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 06:50:20'
		)
		;

