		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2655_4.html',
		'<p>תהלים קג5: &quot;הַמַּשְׂבִּיַע בַּטּוֹב עֶדְיֵךְ תִּתְחַדֵּשׁ כַּנֶּשֶׁר נְעוּרָיְכִי&quot;</p><p>ואם יהוה חידש כַּנֶּשֶׁר נְעוּרָיְכִי אל תשיב רעה תחת טובה</p><p>תהלים קיט9: &quot;בַּמֶּה יְזַכֶּה נַּעַר אֶת אָרְחוֹ לִשְׁמֹר כִּדְבָרֶךָ&quot;</p><p>שמואל ב כב22: &quot;כִּי שָׁמַרְתִּי דַּרְכֵי יהוה וְלֹא רָשַׁעְתִּי מֵאֱלֹהָי&quot;</p><p>תהלים יח22: &quot;כִּי שָׁמַרְתִּי דַּרְכֵי יהוה וְלֹא רָשַׁעְתִּי מֵאֱלֹהָי&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 13:30:29'
		)
		;

