		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2701_0.html',
		'<p>שמואל א ג14: &quot;וְלָכֵן נִשְׁבַּעְתִּי לְבֵית עֵלִי אִם יִתְכַּפֵּר עון בֵּית עֵלִי בְּזֶבַח וּבְמִנְחָה עַד עוֹלָם&quot;</p><p>האוכל=המזון מכפר על האדם אם זה זבח הבשר או המנחה של הלחם </p><p>והמים שאנחנו שותים מביאים עלינו רוח אלהים המרחפת על פני המים</p><p>אך ביום הכפורים אנחנו לא מכפרים באוכל למען יכפר עלינו האל לבדו זאת הסיבה שלא אוכלים ולא שותים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-11 17:47:10'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>אתם יודעים כבר מה אני חושב על הרבנים המפורסמים אבל יש גם כאלה שיוצאים מן הכלל</p><p>ואחד מהם שצריך להזכירו לטובה הוא ***כבוד הרב אייל עמרמי*** המלמד אמונה ובטחון</p><p>הרב אייל עמרמי הוא איש ישר דרך חכם צנוע ללא גאוה ושאינו רודף כבוד או כסף חלילה</p><p>ואני אשמח אם תתן לדיין עבד-יהוה את המעשר למען תהיה לך ברכה מצדקתי לפני יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-12 06:26:49'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

