		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0122_10.html',
		'<p> </p><p>קהלת יב13: &quot;סוֹף דָּבָר הַכֹּל נִשְׁמָע אֶת הָאֱלֹהִים יְרָא וְאֶת מצותיו שְׁמוֹר כִּי זֶה כָּל הָאָדָם&quot;</p><p>יש להבין את דבר קהלת כדבר אלהים תרתי משמע לאמור כי הפסוק דו-משמעי</p><p>ככתוב בספר תהלים סב12: &quot;אַחַת דִּבֶּר אֱלֹהִים שְׁתַּיִם זוּ שָׁמָעְתִּי כִּי עֹז לֵאלֹהִים&quot;</p><p>למרות שקהלת מדבר על זה שכל מה שעשית בחיים הכל הבל הבלים מלבד יראת האלהים והמצוות </p><p>אך יש מימד נוסף כי הפסוק מדבר תרתי משמע</p><p> בעולם שבו ה‑AI עושה כמעט הכול, מתברר מה באמת נשאר לאדם. </p><p>כל מה שאפשר להפוך למכני הופך למכני, וכל מה שאפשר למסור למכונה נמסר. ואז נחשפת האמת: הדבר היחיד שאי אפשר להחליף הוא היראה, המצפון, הקשר הפנימי עם מי שברא את האדם. </p><p>כאשר נאמר בקהלת יב13: &quot;סוֹף דָּבָר הַכֹּל נִשְׁמָע אֶת הָאֱלֹהִים יְרָא וְאֶת מצותיו שְׁמוֹר כִּי זֶה כָּל הָאָדָם&quot; </p><p>זה מה שנשאר כשהכול האחר נעלם — הלב, האחריות, והאמת הפנימית של האדם.</p><p>בסופו של דבר בעידן זה --- הכל AI כבר עושה ומה שנשאר באמת זה רק יראת אלהים ומצוותיו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-12 14:30:24'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

