		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>אני רואה את כל הרבנים.....</p><p>רוב רובם של רבני ישראל נוהגים כעם-הארץ</p><p> יש רב שמוכר שעוריו בכסף</p><p>יש רב שהוא איש קטן עם שגעון גדלות</p><p>יש רב שמשחק אותה מנטור ומסתכל על האלהים ככספומט</p><p>יש רב שמשחק אותה נביא אך הוא בסה&quot;כ שופר של הממשלה</p><p>&quot;הנביא&quot; הזה מדבר כבייכול בשם בורא עולם אך בורא עולם לא דיבר איתו </p><p>ירמיהו כג36: &quot;וּמַשָּׂא יהוה לֹא תִזְכְּרוּ עוֹד כִּי הַמַּשָּׂא יִהְיֶה לְאִישׁ דְּבָרוֹ וַהֲפַכְתֶּם אֶת דִּבְרֵי אֱלֹהִים חַיִּים יהוה צְבָאוֹת אֱלֹהֵינוּ&quot;</p><p>-</p><p>בקיצור רבני ישראל הממאנים לקחת מוסר בדור הזה לא למדו מאומה מה הביא את עם ישראל ליום השואה </p><p> </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-14 04:49:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b24_3.html',
		'<p>משלי ג25: &quot;אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא&quot;</p><p> וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא</p><p> וּמִשֹּׁאַת צדיקים לא תָבֹא כי אין דבר כזה</p><p>לכן כל יום השואה הוא בלוף של רשעים</p><p>הביטו אל כבשן האש בספר דניאל אשר הציל יהוה את אהביו</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי שִׁבְטְךָ וּמִשְׁעַנְתֶּךָ הֵמָּה יְנַחֲמֻנִי&quot;</p><p>-</p><p>יום השואה מנוצל על ידי ישראל להצגתה בעיני הגוים כיהודי נרדף</p><p>בתכלס השואה הסתיימה לפני 80 שנה וכבר אין באמת שורדי שואה </p><p>אך זה מנוצל  על ידי עמותות כזב לנגן לך על הרגשות ולגזול ממך תרומה</p><p>-</p><p>ובאשר ליום השואה הזה שבספירת העומר הלא ימי קציר ברינה יקצורו</p><p>אבל נכון אין קציר יש רק נדלן ועוד נדלן ואספלט ובטון אז כן זה יום שואה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-14 08:44:34'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0529_4.html',
		'<p>מבט וזוית ראיה של דיין </p><p>משלי ג25: &quot;אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא&quot;</p><p> וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא</p><p> וּמִשֹּׁאַת צדיקים לא תָבֹא כי אין דבר כזה</p><p>לכן כל יום השואה הוא בלוף של רשעים</p><p>הביטו אל כבשן האש בספר דניאל אשר הציל יהוה את אהביו</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי שִׁבְטְךָ וּמִשְׁעַנְתֶּךָ הֵמָּה יְנַחֲמֻנִי&quot;</p><p>-</p><p>יום השואה מנוצל על ידי ישראל להצגתה בעיני הגוים כיהודי נרדף</p><p>בתכלס השואה הסתיימה לפני 80 שנה וכבר אין באמת שורדי שואה </p><p>אך זה מנוצל  על ידי עמותות כזב לנגן לך על הרגשות ולגזול ממך תרומה</p><p>-</p><p>ובאשר ליום השואה הזה שבספירת העומר הלא ימי קציר ברינה יקצורו</p><p>אבל נכון אין קציר יש רק נדלן ועוד נדלן ואספלט ובטון אז כן זה יום שואה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-14 08:50:08'
		)
		;

