		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>רבני ישראל אני רוצה לראות אתכם עובדים מייצרים ועושים צדקה חסד ואמת </p><p>אני לא רוצה לשמוע את ההרצאות החלולות והרדודות שלכם שלא מועילות לאיש </p><p>בדברכם הגות לבכם נדמה לכם שאתם עושים בזה צדקה ומשפט ולכן אתם מרשים לעצמכם להתרים לשוא </p><p>וגם כשאתם מתרימים את הציבור אתם לוקחים הכל לכיסכם ומחלקים פירורים לאנשי שלומכם המקורבים אליכם</p><p>זה לא התנהלות של צדיקים!! זה בושה וחרפה וכלימה! זה התנהגות של טפילים!</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-15 04:31:09'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>רבני ישראל אני רוצה לראות אתכם עובדים מייצרים ועושים צדקה חסד ואמת </p><p>אני לא רוצה לשמוע את ההרצאות החלולות והרדודות שלכם שלא מועילות לאיש </p><p>בדברכם הגות לבכם נדמה לכם שאתם עושים בזה צדקה ומשפט ולכן אתם מרשים לעצמכם להתרים לשוא</p><p>וגם כשאתם מתרימים את הציבור אתם לוקחים הכל לכיסכם ומחלקים פירורים לאנשי שלומכם המקורבים אליכם</p><p>זה לא התנהלות של צדיקים!! זה בושה וחרפה וכלימה! זה התנהגות של טפילים!</p><p>&quot;חכמי ישראל&quot; ערלי-לב ולא ידעו עשות משפט וצדקה חסד ואמת </p><p>הדרך היחידה שיוכלו לעשות צדקה ומשפט זה לתת לדיין המעשר </p><p>ודיין יעשה עבור כל ישראל משפט וצדקה - זאת האמת</p><p>וכן ברור לי שאין בכוונתכם לתת תרומה וגם אני לא חפצתי קחת זאת מערלי לב</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-15 04:50:54'
		)
		;

