		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>https://www.youtube.com/watch?v=TPwMsMTYoyU</p><p>ועתה תשובה לדברי הרב הראשי הספרדי הגאון רבי דוד יוסף </p><p>דברי הימים ב יג9: </p><p>&quot;הֲלֹא הִדַּחְתֶּם אֶת כֹּהֲנֵי יהוה אֶת בְּנֵי אַהֲרֹן וְהַלְוִיִּם וַתַּעֲשׂוּ לָכֶם כֹּהֲנִים כְּעַמֵּי הָאֲרָצוֹת .......</p><p>כָּל הַבָּא לְמַלֵּא יָדוֹ בְּפַר בֶּן בָּקָר וְאֵילִם שִׁבְעָה וְהָיָה כֹהֵן לְלֹא אֱלֹהִים&quot;.......</p><p>מי שאינו בדרך בני אהרן הלוי </p><p>והדיח את הכהן הגדול לשבת על כסאו עם לבוש של מצנפת ושמלה </p><p>הוא בעל הגאוה ומחלל הקודש הגדול ביותר“</p><p>כי:</p><p>גאווה היא נטילת סמכות שאינה שלך</p><p> אמת ומישרים בעבודת השם — זו ענווה.</p><p>  ובאשר לטענתכם לאמור לנו מונופול על החכמה הרבנים הם החכמים </p><p>אז יש בינינו מחלוקת קשה ועמוקה מאד על שאלת הסמכות והפרשנות —זו מחלוקת לגיטימית.</p><p>אני מביע את דבריי כאן בגלוי ובכבוד,וכל מי שחפץ להגיב — מוזמן.הציבור ישמע, ישווה, וישפוט.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-16 14:50:13'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

