		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>  במדבר כז16: &quot;יִפְקֹד יהוה אֱלֹהֵי הָרוּחֹת לְכָל בָּשָׂר אִישׁ עַל הָעֵדָה&quot;</p><p>הסטטוס האישי שלי ידוע </p><p>ואינו מאפשר לי לאייש תפקיד </p><p>אך כתבתי את תורתי בקודש </p><p>למען יאכלו ענוים וישבעו  </p><p>-</p><p>עתה שימו לב.......</p><p>תהלים כה12: &quot;מִי זֶה הָאִישׁ יְרֵא יהוה יוֹרֶנּוּ בְּדֶרֶךְ יִבְחָר&quot;</p><p>בחרתי ברב איל עמרמי --- </p><p>https://www.youtube.com/@RabbiEyalAmrami</p><p>https://www.youtube.com/shorts/Ptn7Mlcz_5E</p><p>זֶה הָאִישׁ יְרֵא יהוה להורות משפט ליעקב</p><p> http://tora.us.fm/tnk1/daian</p><p>           דַיָּן שֵׁם           </p><p>        מְשָׁרֵת יהוה            </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-19 00:54:02'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1001_4.html',
		'<p>שמואל ב יד28: &quot;וַיֵּשֶׁב אַבְשָׁלוֹם בִּירוּשָׁלַים שְׁנָתַיִם יָמִים וּפְנֵי הַמֶּלֶךְ לֹא רָאָה&quot; </p><p>שמואל ב יד29: &quot;וַיִּשְׁלַח אַבְשָׁלוֹם אֶל יוֹאָב לִשְׁלֹחַ אֹתוֹ אֶל הַמֶּלֶךְ וְלֹא אָבָה לָבוֹא אֵלָיו וַיִּשְׁלַח עוֹד שֵׁנִית וְלֹא אָבָה לָבוֹא&quot; </p><p>שמואל ב יד30: &quot;וַיֹּאמֶר אֶל עֲבָדָיו רְאוּ חֶלְקַת יוֹאָב אֶל יָדִי וְלוֹ שָׁם שְׂעֹרִים לְכוּ וְהַצִּיתוּהָ בָּאֵשׁ וַיַּצִּתוּ עַבְדֵי אַבְשָׁלוֹם אֶת הַחֶלְקָה בָּאֵשׁ&quot; </p><p>שמואל ב יד31: &quot;וַיָּקָם יוֹאָב וַיָּבֹא אֶל אַבְשָׁלוֹם הַבָּיְתָה וַיֹּאמֶר אֵלָיו לָמָּה הִצִּיתוּ עֲבָדֶךָ אֶת הַחֶלְקָה אֲשֶׁר לִי בָּאֵשׁ&quot; </p><p>שמואל ב יד32: &quot;וַיֹּאמֶר אַבְשָׁלוֹם אֶל יוֹאָב הִנֵּה שָׁלַחְתִּי אֵלֶיךָ לֵאמֹר בֹּא הֵנָּה וְאֶשְׁלְחָה אֹתְךָ אֶל הַמֶּלֶךְ לֵאמֹר לָמָּה בָּאתִי מִגְּשׁוּר טוֹב לִי עֹד אֲנִי שָׁם וְעַתָּה אֶרְאֶה פְּנֵי הַמֶּלֶךְ וְאִם יֶשׁ בִּי עון וֶהֱמִתָנִי&quot; </p><p>שמואל ב יד33: &quot;וַיָּבֹא יוֹאָב אֶל הַמֶּלֶךְ וַיַּגֶּד לוֹ וַיִּקְרָא אֶל אַבְשָׁלוֹם וַיָּבֹא אֶל הַמֶּלֶךְ וַיִּשְׁתַּחוּ לוֹ עַל אַפָּיו אַרְצָה לִפְנֵי הַמֶּלֶךְ וַיִּשַּׁק הַמֶּלֶךְ לְאַבְשָׁלוֹם&quot; </p><p>-------------------</p><p> עתה אם רבני ישראל בחרו להיות כיואב ולא יענו לאשר אני דורש בכבוד ככל התורה אשר כתבתי לכם פה </p><p>אז חלקת השדה שלהם תוצת באש מהאיש אשר בְּיָדוֹ אֶת הָאֵשׁ וְאֶת הַמַּאֲכֶלֶת http://tora.us.fm/tnk1/daian</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-19 09:24:11'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

