		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_7.html',
		'<p>פרשת פפושדו</p><p>לפי ההלכה - המצה העשירה כשל&quot;פ כי על פי ההלכה מי פירות אינם מחמיצים</p><p>לפי התורה והמדע --- המצה העשירה היא חמץ כי מיץ ענבים תירוש מכיל מים</p><p>-</p><p>קמח מצות + מיץ ענבים = זה לא תרכובת כי אם תערובת המכילה מים במיץ הענבים </p><p>סוף דבר </p><p>התורה והמדע שניהם יחדיו צודקים</p><p>המצה העשירה היא אינה באמת כשרה לפסח</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-19 13:09:41'
		)
		;

