		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>דף חדש --- כִּי עַתָּה רָאִיתִי בְעֵינָי</p><p>מחבב את הרבנים הבכירים בהנהגה</p><p>את גדולי התורה המובילים את העם</p><p>את המתוקים מדבש בדבריהם ובדרכם.</p><p>את המחזקים את הלבבות ושבים באמת אל יהוה.</p><p>ככתוב..</p><p>איכה ג40: &quot;נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה וְנָשׁוּבָה עַד יהוה&quot;</p><p> </p><p>אשריכם ישראל כי כאלה הם רבניכם</p><p>ואני אייחל בתקווה גדולה שילמדו מתורתי ויוסיפו אור בעולם.</p><p>הסטטוס האישי שלי ידוע ואינו מאפשר לי לאייש תפקיד </p><p>אך כתבתי את תורתי בקודש למען יאכלו ענוים וישבעו</p><p>-----------------------------------------------------------------</p><p>תהלים קלג1: &quot;שִׁיר הַמַּעֲלוֹת לְדָוִד הִנֵּה מַה טּוֹב וּמַה נָּעִים שֶׁבֶת אַחִים גַּם יָחַד&quot;</p><p>תהלים כט11: &quot;יהוה עֹז לְעַמּוֹ יִתֵּן יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-19 16:34:57'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

