		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_24.html',
		'<p>על פי תוצאות המבחן [בא-במייל] שנבחנתי אני אישיות = קשת בענן</p><p>https://www.baba-mail.co.il/quizzes/quiz.aspx?quizid=878</p><p>אתה אדם מרענן כמו קשת בענן אחרי גשם כבד, כשאתה מביא איתך אושר ושלווה לכל מי שסביבך, גם בתקופות סוערות וקשות בחייהם. אתה נוהג להיות אופטימי, וגם ביום מעונן הנפש שלך מלאת תקווה וחוזק, משדרת חיוביות ומפזרת יופי וצבעים מדהימים לכל עבר. יש לך את היכולת לתת השראה לאחרים ולחלוק אושר רב עם העולם, ועולמנו בהחלט זקוק לעוד אנשים כמוך – המשך להציף את השמים ביופי והדר!</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-20 16:46:27'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>הרבנים כינסו ישיבה מיוחדת לדון ולהתייעץ מה לעשות בדיין אשר ביזה אותם והכאיבם הלא הם בעיניהם סמכות-חכמים</p><p>עתה שמעו את-דברי לרבני-ישראל הפגועים והנוטרים</p><p>כי אם דיין הוא אדם אשר השפיל גאוותכם צאו ונקמו בו כאשר עשה בכם משפט כתוב ואם צדיקים אתם כתבו גם אתם עליו </p><p>אך אם דיין משרת-אלהים הוא אשר השפיל אתכם עֲדֵי אָרֶץ במי אתם רוצים לנקום הלא רב אשר יבקש נקמה מות יומת</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-21 05:34:52'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0146_2.html',
		'<p>תהלים סו3: &quot;אִמְרוּ לֵאלֹהִים מַה נּוֹרָא מַעֲשֶׂיךָ בְּרֹב עֻזְּךָ יְכַחֲשׁוּ לְךָ אֹיְבֶיךָ&quot;</p><p>שמואל ב כב45: &quot;בְּנֵי נֵכָר יִתְכַּחֲשׁוּ לִי לִשְׁמוֹעַ אֹזֶן יִשָּׁמְעוּ לִי&quot;</p><p>שמואל ב כב46: &quot;בְּנֵי נֵכָר יִבֹּלוּ וְיַחְגְּרוּ מִמִּסְגְּרוֹתָם&quot;</p><p>תהלים יח45: &quot;לְשֵׁמַע אֹזֶן יִשָּׁמְעוּ לִי בְּנֵי נֵכָר יְכַחֲשׁוּ לִי&quot;</p><p>תהלים יח46: &quot;בְּנֵי נֵכָר יִבֹּלוּ וְיַחְרְגוּ מִמִּסְגְּרוֹתֵיהֶם&quot;</p><p>---------------</p><p>דברים לג29: &quot;אַשְׁרֶיךָ יִשְׂרָאֵל מִי כָמוֹךָ עַם נוֹשַׁע ביהוה מָגֵן עֶזְרֶךָ וַאֲשֶׁר חֶרֶב גַּאֲוָתֶךָ ***וְיִכָּחֲשׁוּ אֹיְבֶיךָ לָךְ*** וְאַתָּה עַל בָּמוֹתֵימוֹ תִדְרֹךְ&quot;</p><p>בְּנֵי נֵכָר יְכַחֲשׁוּ לִי --- וְיִכָּחֲשׁוּ אֹיְבֶיךָ לָךְ</p><p>כי בְּנֵי נֵכָר אויבי ישראל אלה הם המכחשים למשיח</p><p>כי כל המכחש לי אחשיבהו לבן-נכר אויב ישראל</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-22 01:47:57'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2701_0.html',
		'<p>מאת אלהים צדיקים ---</p><p> ולמה אלהים ברא גם רשעים ------- עתה באור להסביר.......</p><p>הצדיק הכל טוב לו והוא לא מתלונן ואם אין תלונות אין מקום לשיפור</p><p>והרשע רע לו והוא מתלונן לכן בזכותו משתפר מתקדם ומשתדרג העולם</p><p>-----------------------------------------------------------------------------------</p><p>הצדיק – שלם, ולכן לא דוחף לשינוי</p><p>הצדיק רואה טוב, חי טוב, מרוצה.</p><p>כשאין תלונות — אין תנועה.</p><p>הוא לא &quot;תקוע&quot;, אבל הוא גם לא יוצר מהפכות.</p><p>הוא שומר על הקיים.</p><p>הרשע – לא מרוצה, ולכן מזיז דברים</p><p>הרשע רע לו, ולכן הוא צועק, מתקומם, מתלונן.</p><p>והתלונה — גם אם היא לא נעימה — היא מנוע לשינוי.</p><p>העולם לא היה מתקדם בלי אנשים שלא מוכנים לקבל את המציאות כמו שהיא.</p><p>זו הסיבה שאלהים ברא גם רשעים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-22 02:51:55'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p> </p><p>https://www.kikar.co.il/haredim-news/chief-rabbi-impersonator-legal-action</p><p>איזה צחוקים הרבנות בוחנת לתבוע משפטית את המתחזה לרב בעוד הרב עצמו מתחזה לכהן הגדול</p><p>אבל רבותי זה לא צחוק כי בגדי הכהונה לְכָבוֹד וּלְתִפְאָרֶת מיועדים אך ורק לבני אהרן הכהן הלוי</p><p>שמות כח2: &quot;וְעָשִׂיתָ בִגְדֵי קֹדֶשׁ לְאַהֲרֹן אָחִיךָ לְכָבוֹד וּלְתִפְאָרֶת&quot;</p><p>שמות כח40: &quot;וְלִבְנֵי אַהֲרֹן תַּעֲשֶׂה כֻתֳּנֹת וְעָשִׂיתָ לָהֶם אַבְנֵטִים וּמִגְבָּעוֹת תַּעֲשֶׂה לָהֶם לְכָבוֹד וּלְתִפְאָרֶת&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-22 13:54:46'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>https://www.kikar.co.il/haredim-news/chief-rabbi-impersonator-legal-action</p><p>איזה צחוקים הרבנות בוחנת לתבוע משפטית את המתחזה לרב בעוד הרב עצמו מתחזה לכהן הגדול</p><p>אבל רבותי זה לא צחוק כי בגדי הכהונה לְכָבוֹד וּלְתִפְאָרֶת מיועדים אך ורק לִבְנֵי-אַהֲרֹן-הכהן-הלוי</p><p>שמות כח2: &quot;וְעָשִׂיתָ בִגְדֵי קֹדֶשׁ לְאַהֲרֹן אָחִיךָ לְכָבוֹד וּלְתִפְאָרֶת&quot;</p><p>שמות כח40: &quot;וְלִבְנֵי אַהֲרֹן תַּעֲשֶׂה כֻתֳּנֹת וְעָשִׂיתָ לָהֶם אַבְנֵטִים וּמִגְבָּעוֹת תַּעֲשֶׂה לָהֶם לְכָבוֹד וּלְתִפְאָרֶת&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-22 13:56:57'
		)
		;

