		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0416_3.html',
		'<p>*** מצוות השבת אבדה ***</p><p>אם מימי בית שני הכהונה אבדה לבני-אהרן-הכהן ואתם הרבנים הפרושים הקמתם &quot;כהונה חליפית&quot; עליכם להשיב את האבדה</p><p>דברים כב3: &quot;וְכֵן תַּעֲשֶׂה לַחֲמֹרוֹ וְכֵן תַּעֲשֶׂה לְשִׂמְלָתוֹ וְכֵן תַּעֲשֶׂה לְכָל אֲבֵדַת אָחִיךָ אֲשֶׁר תֹּאבַד מִמֶּנּוּ וּמְצָאתָהּ לֹא תוּכַל לְהִתְעַלֵּם&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-29 10:26:08'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

