		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>יש כהנים לויים והם נמצאים בעדת השומרונים ובאשר לשופט הקדוש זה אני דיין </p><p>ואני הסמכות הראשונה להוראת התורה לאמור כי כל הכהנים הלוים כולל הכהן הגדול כולם מתחתי </p><p>אני חושב לאחד בין השומרונים והקראים והרבנים כולם לעם-ישראל אחד  </p><p>המטרה להקים ממלכת כהנים שכבר נמצאים בעדת השומרונים </p><p>רק עליהם לשמוע בקולי ככל התורה אשר אצווה אותם במיוחד עם לוח השנה שלי שכתבתי בקודש </p><p>אני יודע שהחזון נראה רחוק אך אלה מחשבות דיין </p><p>אני לא נאיבי ויודע שצריך הסכמות רחבות מצד כולם הן מהשומרונים הן מהקראים והן מהרבנים </p><p>וברור לי שכעת עתה אין את האינטליגנציה הזאת בציבור </p><p>לא אצל הרבנים ולא אצל הקראים ולא אצל השומרונים</p><p>-</p><p>יש דברים שהשומרונים צודקים </p><p>יש דברים שהקראים צודקים </p><p>ויש דברים שהרבנים צודקים - כמו לשים פלטה בשבת </p><p> http://tora.us.fm/tnk1/daian</p><p>     דַיָּן שֵׁם   מְשָׁרֵת יהוה    </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-01 13:14:51'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>יש כהנים לויים והם נמצאים בעדת השומרונים ובאשר לשופט הקדוש זה אני דיין </p><p>ואני הסמכות הראשונה להוראת התורה לאמור כי כל הכהנים הלוים כולל הכהן הגדול כולם מתחתי </p><p>אני חושב לאחד בין השומרונים והקראים והרבנים כולם לעם-ישראל אחד  </p><p>המטרה להקים ממלכת כהנים שכבר נמצאים בעדת השומרונים </p><p>רק עליהם לשמוע בקולי ככל התורה אשר אצווה אותם במיוחד עם לוח השנה שלי שכתבתי בקודש </p><p>אני יודע שהחלום נראה רחוק אך אלה מחשבות דיין </p><p>אני לא נאיבי ויודע שצריך הסכמות רחבות מצד כולם הן מהשומרונים הן מהקראים והן מהרבנים </p><p>וברור לי שכעת עתה אין את האינטליגנציה הזאת בציבור </p><p>לא אצל הרבנים ולא אצל הקראים ולא אצל השומרונים</p><p>-</p><p>יש דברים שהשומרונים צודקים </p><p>יש דברים שהקראים צודקים </p><p>ויש דברים שהרבנים צודקים - כמו לשים פלטה בשבת</p><p>ובאשר ליהודים המשיחיים המצפים למשיח </p><p>אם יכירו בדיין כמשיח אלהים נפתרה הבעיה</p><p>ואם לא יכירו בדיין כמשיח אלהים אז שימשיכו לחכות לישו</p><p> http://tora.us.fm/tnk1/daian</p><p>           דַיָּן שֵׁם   מְשָׁרֵת יהוה    </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-01 13:23:16'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

