		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2823_0.html',
		'<p>תהלים סג7: &quot;אִם זְכַרְתִּיךָ עַל יְצוּעָי בְּאַשְׁמֻרוֹת אֶהְגֶּה בָּךְ&quot;</p><p>לכן אין לשתות יין בלילה כי היין גורם לשכחה ואנחנו עלינו לזכור שם אלהים על היצועים בעת שהולכים לישון בלילה </p><p>אברהם אבינו לא שתה יין בלילה לוט שתה יין בלילה ושכב עם בנותיו </p><p>אני מתכוון שאין לשתות לשכרה בלילה אך טיפה לגימה לברכה מהקידוש וההבדלה זה מותר</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-02 17:20:08'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p> שנה 7 (מתשרי) – שנת הכרזה בלבד: “השנה תחל שנת השבע”.</p><p>שנה 8 (מניסן) – שנת השבע במספר, אך עדיין אין שביתה.</p><p>שנה 8 (מתשרי) – תחילת השמיטה בפועל, כי אז מתחיל החריש.</p><p>אותו מבנה חל גם על שנת היובל</p><p>שנה 49 (מתשרי) – שנת הכרזה ליובל.</p><p>שנה 50 (מניסן) – שנת היובל במספר.</p><p>שנה 50 (מתשרי) – שנת היובל בפועל:</p><p>שביתה חקלאית + דרור + שיבה + החזרת שדות.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-03 08:30:47'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>השנה שמתחלקת במספר 7 היא רק שנת הכרזה אך לא שנת השמיטה</p><p>שנה 7 (מתשרי) – שנת הכרזה בלבד: “השנה תחל שנת השבע”.</p><p>שנה 8 (מניסן) – שנת השבע במספר, אך עדיין אין שביתה.</p><p>שנה 8 (מתשרי) – תחילת השמיטה בפועל, כי אז מתחיל החריש.</p><p>אותו מבנה חל גם על שנת היובל</p><p>שנה 49 (מתשרי) – שנת הכרזה ליובל.</p><p>שנה 50 (מניסן) – שנת היובל במספר.</p><p>שנה 50 (מתשרי) – שנת היובל בפועל:</p><p>שביתה חקלאית + דרור + שיבה + החזרת שדות.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-03 08:32:23'
		)
		;

