		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0215_4.html',
		'<p>הרבי אכל 13 שנה רק חרובים?</p><p>אכילת חרובים בלבד במשך שבוע-ימים בלבד תגרום ל־עצירות קשה משמעותית, בגלל הטאנינים (מכווצים) והסיבים הרבים שמאטים את תנועת המעיים.</p><p>אצל חלק קטן מהאנשים — במיוחד עם מערכת עיכול רגישה — זה יכול לגרום דווקא ל־שלשול, נפיחות וגזים. </p><p>בקיצור--- תזונה כזאת היא בלתי אפשרית מבחינה רפואית ---- אז שלא יעבדו עליכם</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-04 18:20:36'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

