		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0215_4.html',
		'<p>ל&quot;ג בעומר = סיפורי כזבים</p><p>הרבי אכל 13 שנה רק חרובים?</p><p>אכילת חרובים בלבד במשך שבוע-ימים בלבד תגרום ל־עצירות קשה משמעותית, בגלל הטאנינים (מכווצים) והסיבים הרבים שמאטים את תנועת המעיים.</p><p>אצל חלק קטן מהאנשים — במיוחד עם מערכת עיכול רגישה — זה יכול לגרום דווקא ל־שלשול, נפיחות וגזים.</p><p>בקיצור--- תזונה כזאת היא בלתי אפשרית מבחינה רפואית !!!</p><p> מה באמת קורה לגוף בתזונה חד־צדדית —</p><p>כמו לאכול רק חרובים</p><p>הגוף מקבל רק סוג אחד של רכיבים תזונתיים.</p><p>חסרים תזונתיים מתחילים להופיע תוך ימים ספורים.</p><p>מערכת העיכול יוצאת מאיזון.</p><p>תופעות כמו עצירות או שלשול</p><p>יש נפיחות, גזים ותחושת כבדות.</p><p>הגוף מתחיל לפרק שריר כדי לייצר אנרגיה.</p><p>מופיעה חולשה כללית.</p><p>יש ירידה בריכוז ובצלילות המחשבה.</p><p>מצב הרוח נפגע.</p><p>מערכת החיסון נחלשת.</p><p>מאזן הורמונלי נפגע.</p><p>תפקוד הלב והעצבים נפגעים בהמשך.</p><p>הגוף לא מצליח לתחזק את עצמו.</p><p>תזונה חד־צדדית לאורך זמן מובילה לקריסה מערכתית.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-05 02:23:53'
		)
		;

SET character_set_client=utf8mb3;
