		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0216_6.html',
		'<p>תהלים פא17: &quot;וַיַּאֲכִילֵהוּ מֵחֵלֶב חִטָּה וּמִצּוּר דְּבַשׁ אַשְׂבִּיעֶךָ&quot;</p><p>תהלים צ14: &quot;שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ וּנְרַנְּנָה וְנִשְׂמְחָה בְּכָל יָמֵינוּ&quot;</p><p>   וּמִצּוּר דְּבַשׁ אַשְׂבִּיעֶךָ ---  שַׂבְּעֵנוּ בַבֹּקֶר חַסְדֶּךָ</p><p> אכלו דְּבַשׁ בַבֹּקֶר זה מועדו</p><p>הדבש ממריץ ופותח עיניים</p><p>שמואל א יד29: &quot;רְאוּ נָא כִּי אֹרוּ עֵינַי כִּי טָעַמְתִּי מְעַט דְּבַשׁ הַזֶּה&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-07 01:11:06'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2690_2.html',
		'<p>איזה כפיר אתה בנפשך</p><p>משלי כח1: &quot;נָסוּ וְאֵין רֹדֵף רָשָׁע וְצַדִּיקִים כִּכְפִיר יִבְטָח&quot; </p><p>תהלים לד11: &quot;כְּפִירִים רָשׁוּ וְרָעֵבוּ וְדֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב&quot;</p><p>--------------</p><p>זה לא העיקר להיות כפיר כי עליך לדרוש יהוה בכל עת ואם באמת כפיר אז כצדיק לבטוח בו</p><p>ואם כפיר-אריה אתה שאל את עצמך איזה כפיר אתה</p><p>כי אם חלילה כפיר שאינו דורש את יהוה-אלהים -- אז תרעב</p><p>אך אם אתה ככפיר-אריה בוטח ביהוה-אלהים אז צדיק אתה</p><p>ירמיהו נא38: &quot;יַחְדָּו כַּכְּפִרִים יִשְׁאָגוּ נָעֲרוּ כְּגוֹרֵי אֲרָיוֹת&quot;</p><p>יואל ד16: &quot;ויהוה מִצִּיּוֹן יִשְׁאָג וּמִירוּשָׁלַים יִתֵּן קוֹלוֹ וְרָעֲשׁוּ שָׁמַיִם וָאָרֶץ ויהוה מַחֲסֶה לְעַמּוֹ וּמָעוֹז לִבְנֵי יִשְׂרָאֵל&quot;</p><p> http://tora.us.fm/tnk1/daian</p><p>           דַיָּן שֵׁם           </p><p>        מְשָׁרֵת יהוה            </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-07 01:33:56'
		)
		;

SET character_set_client=utf8mb3;
