		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2690_2.html',
		'<p>איזה כפיר אתה בנפשך</p><p>משלי כח1: &quot;נָסוּ וְאֵין רֹדֵף רָשָׁע וְצַדִּיקִים כִּכְפִיר יִבְטָח&quot;</p><p>תהלים לד11: &quot;כְּפִירִים רָשׁוּ וְרָעֵבוּ וְדֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב&quot;</p><p>--------------</p><p>זה לא העיקר להיות כפיר כי עליך לדרוש יהוה בכל עת ואם באמת כפיר אז כצדיק לבטוח בו</p><p>ואם כפיר-אריה אתה שאל את עצמך איזה כפיר אתה</p><p>האם חלילה נוהג כמו איש-עָשָׂקים לעשוק בני-אדם לאכלם</p><p>יחזקאל יט3: &quot;וַתַּעַל אֶחָד מִגֻּרֶיהָ כְּפִיר הָיָה וַיִּלְמַד לִטְרָף טֶרֶף אָדָם אָכָל&quot;</p><p>יחזקאל יט6: &quot;וַיִּתְהַלֵּךְ בְּתוֹךְ אֲרָיוֹת כְּפִיר הָיָה וַיִּלְמַד לִטְרָף טֶרֶף אָדָם אָכָל&quot;</p><p>כי אם חלילה כפיר רשע שאינו דורש את יהוה-אלהים -- אז תרעב</p><p>אך אם אתה ככפיר-אריה בוטח ביהוה-אלהים אז צדיק אתה</p><p>ירמיהו נא38: &quot;יַחְדָּו כַּכְּפִרִים יִשְׁאָגוּ נָעֲרוּ כְּגוֹרֵי אֲרָיוֹת&quot;</p><p>יואל ד16: &quot;ויהוה מִצִּיּוֹן יִשְׁאָג וּמִירוּשָׁלַים יִתֵּן קוֹלוֹ וְרָעֲשׁוּ שָׁמַיִם וָאָרֶץ ויהוה מַחֲסֶה לְעַמּוֹ וּמָעוֹז לִבְנֵי יִשְׂרָאֵל&quot;</p><p>http://tora.us.fm/tnk1/daian</p><p>דַיָּן שֵׁם</p><p>מְשָׁרֵת יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-07 02:06:26'
		)
		;

