		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>גם אני ראיתי את התועבה הזאת באיצטלה של קדושה</p><p>מוכרים לך מופע מתוכנן היטב של רבנים טליתות שופרות נרות בכדים</p><p>והכל למען בצע כסף ---- בושה וחרפה וכלימה לעמותות קבר הרשב&quot;י</p><p>אני דורש מהרבנים הראשיים להוקיע את פעילות המסחרה של הרשב&quot;י</p><p>srugim.co.il/1303566-אין-גבול-לרייטינג-גם-במחיר-של-עבודה-זרה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-10 09:02:45'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0531_1.html',
		'<p>וַיִּכְתֹּב משֶׁה אֶת הַתּוֹרָה הַזֹּאת וַיִּתְּנָהּ אֶל הַכֹּהֲנִים בְּנֵי לֵוִי הַנֹּשְׂאִים אֶת אֲרוֹן בְּרִית יְהֹוָה וְאֶל כָּל זִקְנֵי יִשְׂרָאֵל:</p><p>על כן רק הם הַכֹּהֲנִים בְּנֵי לֵוִי וְאֶל כָּל זִקְנֵי יִשְׂרָאֵל רק הם בלבד יורו את התורה כי התורה עמם בקודש -- אשר נתנה להם מאת משה איש האלהים</p><p> זִקְנֵי יִשְׂרָאֵל -- מגיל 70 ומעלה</p><p>הַכֹּהֲנִים בְּנֵי לֵוִי -- מגיל 30 ומעלה</p><p>-</p><p>ומי שאינם הַכֹּהֲנִים בְּנֵי לֵוִי יחכה עד גיל 70 ומעלה רק אז יוכל להורות תורה לישראל</p><p>וזאת שלא יווצר מצב שעם-הארץ יורה את התורה כאשר התורה לא באמת עמו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-10 10:03:24'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0531_1.html',
		'<p>וַיִּכְתֹּב משֶׁה אֶת הַתּוֹרָה הַזֹּאת וַיִּתְּנָהּ אֶל הַכֹּהֲנִים בְּנֵי לֵוִי הַנֹּשְׂאִים אֶת אֲרוֹן בְּרִית יְהֹוָה וְאֶל כָּל זִקְנֵי יִשְׂרָאֵל:</p><p>על כן רק הם הַכֹּהֲנִים בְּנֵי לֵוִי וְאֶל כָּל זִקְנֵי יִשְׂרָאֵל רק הם בלבד יורו את התורה כי התורה עמם בקודש -- אשר נתנה להם מאת משה איש האלהים</p><p>זִקְנֵי יִשְׂרָאֵל -- מגיל 70 ומעלה</p><p>הַכֹּהֲנִים בְּנֵי לֵוִי -- רק מגיל 30 ומעלה</p><p>-</p><p>ומי שאינם הַכֹּהֲנִים בְּנֵי לֵוִי יחכה עד גיל 70 ומעלה רק אז יוכל להורות תורה לישראל</p><p>מלבד אם מדובר בנביא ליהוה צבאות אלהי-ישראל כִּי בְּיַד יהוה הַמִּצְוָה בְיַד נְבִיאָיו</p><p>וזאת שלא יווצר מצב שעם-הארץ יורה את התורה כאשר התורה לא באמת עמו</p><p> </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-10 10:21:17'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

