		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>ספר מלכים א פרק יב כתוב:</p><p>ו וַיִּוָּעַץ הַמֶּלֶךְ רְחַבְעָם אֶת-הַזְּקֵנִים אֲשֶׁר-הָיוּ עֹמְדִים אֶת-פְּנֵי שְׁלֹמֹה אָבִיו בִּהְיֹתוֹ חַי לֵאמֹר  אֵיךְ אַתֶּם נוֹעָצִים לְהָשִׁיב אֶת-הָעָם-הַזֶּה דָּבָר.  </p><p>ז וידבר (וַיְדַבְּרוּ) אֵלָיו לֵאמֹר אִם-הַיּוֹם תִּהְיֶה-עֶבֶד לָעָם הַזֶּה וַעֲבַדְתָּם וַעֲנִיתָם וְדִבַּרְתָּ אֲלֵיהֶם דְּבָרִים טוֹבִים וְהָיוּ לְךָ עֲבָדִים כָּל-הַיָּמִים</p><p>-</p><p>את הטאקטיקה הזאת אני יודע טוב מאד ובכל זאת לא בחרתי באופציה הזאת לדבר אליכם דְּבָרִים טוֹבִים </p><p>כי אם בחרתי לדבר אליכם דברים קשים דברי תוכחה כי גם כעבדים לא חפצתי בכם כי לא מצאתי בכם תם וישר</p><p>תהלים קא6: &quot;עֵינַי בְּנֶאֶמְנֵי אֶרֶץ לָשֶׁבֶת עִמָּדִי הֹלֵךְ בְּדֶרֶךְ תָּמִים הוּא יְשָׁרְתֵנִי&quot; ------- ואתם לא ראויים למשיח</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-10 18:26:32'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>ספר מלכים א פרק יב כתוב:</p><p>ו וַיִּוָּעַץ הַמֶּלֶךְ רְחַבְעָם אֶת-הַזְּקֵנִים אֲשֶׁר-הָיוּ עֹמְדִים אֶת-פְּנֵי שְׁלֹמֹה אָבִיו בִּהְיֹתוֹ חַי לֵאמֹר אֵיךְ אַתֶּם נוֹעָצִים לְהָשִׁיב אֶת-הָעָם-הַזֶּה דָּבָר.</p><p>ז וידבר (וַיְדַבְּרוּ) אֵלָיו לֵאמֹר אִם-הַיּוֹם תִּהְיֶה-עֶבֶד לָעָם הַזֶּה וַעֲבַדְתָּם וַעֲנִיתָם וְדִבַּרְתָּ אֲלֵיהֶם דְּבָרִים טוֹבִים וְהָיוּ לְךָ עֲבָדִים כָּל-הַיָּמִים</p><p>-</p><p>את הטאקטיקה הזאת אני יודע טוב מאד ובכל זאת לא בחרתי באופציה הזאת לדבר אליכם דְּבָרִים טוֹבִים</p><p>כי אם בחרתי לדבר אליכם דברים קשים דברי תוכחה כי גם כעבדים לא חפצתי בכם כי לא מצאתי בכם תם וישר</p><p>תהלים קא6: &quot;עֵינַי בְּנֶאֶמְנֵי אֶרֶץ לָשֶׁבֶת עִמָּדִי הֹלֵךְ בְּדֶרֶךְ תָּמִים הוּא יְשָׁרְתֵנִי&quot; ------- ואתם לא ראויים למשיח-יהוה</p><p>דברים כח68: &quot;וֶהֱשִׁיבְךָ יהוה מִצְרַיִם בָּאֳנִיּוֹת בַּדֶּרֶךְ אֲשֶׁר אָמַרְתִּי לְךָ לֹא תֹסִיף עוֹד לִרְאֹתָהּ וְהִתְמַכַּרְתֶּם שָׁם לְאֹיְבֶיךָ לַעֲבָדִים וְלִשְׁפָחוֹת וְאֵין קֹנֶה&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-11 00:20:15'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

