		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2823_0.html',
		'<p>תהלים ה6: &quot;לֹא יִתְיַצְּבוּ הוֹלְלִים לְנֶגֶד עֵינֶיךָ שָׂנֵאתָ כָּל פֹּעֲלֵי אָוֶן&quot;</p><p>יין קשור להוללות ואתה אל תשת יין לפני השינה כי לא תוכל להתייצב לפני אלהים באמונה בלילה </p><p>תהלים סג7: &quot;אִם זְכַרְתִּיךָ עַל יְצוּעָי בְּאַשְׁמֻרוֹת אֶהְגֶּה בָּךְ&quot;</p><p>לכן אין לשתות יין בלילה כי היין גורם לשכחה ואנחנו עלינו לזכור שם אלהים על היצועים בעת שהולכים לישון בלילה</p><p>אברהם אבינו לא שתה יין בלילה לוט שתה יין בלילה ושכב עם בנותיו</p><p>אני מתכוון שאין לשתות לשכרה בלילה אך טיפה לגימה לברכה מהקידוש וההבדלה זה מותר</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-12 16:13:59'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

