		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0411_2.html',
		'<p>תהלים לז26: &quot;כָּל הַיּוֹם חוֹנֵן וּמַלְוֶה וְזַרְעוֹ לִבְרָכָה&quot;</p><p>הרבנים מטיפים ל&quot;שמירת הברית&quot; ולא כל כך מצליחים בדבר הזה</p><p>הסיבה היא שאם במקרה הרע אתה עושק וגוזל ובמקרה הטוב אתה לא חוֹנֵן וּמַלְוֶה </p><p>אז אלהים לא יתן זרעך לברכה לכן זאת הסיבה שאתה חוטא בחטאות-נעורים</p><p>רק אם אתה חוֹנֵן וּמַלְוֶה אז כצדיק זרעך יהיה לברכה ולא לקללה</p><p>תהלים כה7: &quot;חַטֹּאות נְעוּרַי וּפְשָׁעַי אַל תִּזְכֹּר כְּחַסְדְּךָ זְכָר לִי אַתָּה לְמַעַן טוּבְךָ יהוה&quot;</p><p>יברך אלהי יעקב את נערי בני-ישראל ולא יחטאו בחטאות נעורים</p><p>תהלים קכט1: &quot;שִׁיר הַמַּעֲלוֹת רַבַּת צְרָרוּנִי מִנְּעוּרַי יֹאמַר נָא יִשְׂרָאֵל&quot;</p><p>תהלים קכט2: &quot;רַבַּת צְרָרוּנִי מִנְּעוּרָי גַּם לֹא יָכְלוּ לִי&quot;</p><p>ואתם אם הבנתם זאת לכו נא בדרך אלהי יִשְׂרָאֵל אבינו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-18 10:37:09'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b23_1.html',
		'<p>מי הוא באמת המנהיג</p><p>משלי י21: &quot;שִׂפְתֵי צַדִּיק יִרְעוּ רַבִּים וֶאֱוִילִים בַּחֲסַר לֵב יָמוּתוּ&quot;</p><p>שמואל ב כג3: &quot;אָמַר אֱלֹהֵי יִשְׂרָאֵל לִי דִבֶּר צוּר יִשְׂרָאֵל מוֹשֵׁל בָּאָדָם צַדִּיק מוֹשֵׁל יִרְאַת אֱלֹהִים&quot;</p><p>-</p><p>הצדיק הוא הרועה הוא המושל - על אחת כמה וכמה שהוא רועה רבים וכולם נוהרים אחריו</p><p>המנהיג הצדיק הרועה המושל הוא לא בהכרח שר בכיר בממשלה </p><p>כי כבר אמר בספר קהלת י7: &quot;רָאִיתִי עֲבָדִים עַל סוּסִים וְשָׂרִים הֹלְכִים כַּעֲבָדִים עַל הָאָרֶץ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-18 14:19:19'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b23_1.html',
		'<p>מי הוא באמת המנהיג</p><p>משלי י21: &quot;שִׂפְתֵי צַדִּיק יִרְעוּ רַבִּים וֶאֱוִילִים בַּחֲסַר לֵב יָמוּתוּ&quot;</p><p>שמואל ב כג3: &quot;אָמַר אֱלֹהֵי יִשְׂרָאֵל לִי דִבֶּר צוּר יִשְׂרָאֵל מוֹשֵׁל בָּאָדָם צַדִּיק מוֹשֵׁל יִרְאַת אֱלֹהִים&quot;</p><p>-</p><p>הצדיק הוא הרועה הוא המושל - על אחת כמה וכמה שהוא רועה רבים וכולם נוהרים אחריו</p><p>המנהיג הצדיק הרועה המושל ירא-האלהים --  הוא לא בהכרח שר בכיר בממשלה</p><p>כי כבר אמר בספר קהלת י7: &quot;רָאִיתִי עֲבָדִים עַל סוּסִים וְשָׂרִים הֹלְכִים כַּעֲבָדִים עַל הָאָרֶץ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-18 14:21:20'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

