		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/nvia/tryasr/xv-02-01.html',
		'<p>אני חשבתי לומר שחוני הראשון הוא חבקוק הנביא.</p><p>וחוני השני הוא בן בנו אין הכוונה שהוא צאצא ישיר שלו אלא שהוא גלגול שלו</p>',
		'115899678644600469918',
		'מנחם גולדשטיין',
		'2026-05-18 20:29:36'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3109_1.html',
		'<p>האיש החכם מכל האדם כתב בחכמת שלמה המלך בספר משלי יא31: &quot;הֵן צַדִּיק בָּאָרֶץ יְשֻׁלָּם אַף כִּי רָשָׁע וְחוֹטֵא&quot;</p><p>לאמור כי שכר הצדיק פה בארץ בעולם הזה ---- אך רבני-חזל שנדמה להם שהם &quot;סמכות חכמים&quot; אמרו ההיפך </p><p>&quot;שְׂכַר מִצְוָה בְּהַאי עָלְמָא לֵיכָּא&quot;  (קידושין ל&quot;ט ע&quot;ב) </p><p>זהו לשון הגמרא בשם רבי יעקב, שאומר : אין שכר מצוות בעולם הזה —כלומר, השכר האמיתי הוא בעולם הבא, לא כאן.</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-19 15:11:15'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3109_1.html',
		'<p>האיש החכם מכל האדם כתב בחכמת שלמה המלך בספר משלי יא31: &quot;הֵן צַדִּיק בָּאָרֶץ יְשֻׁלָּם אַף כִּי רָשָׁע וְחוֹטֵא&quot;</p><p>לאמור כי שכר הצדיק פה בארץ בעולם הזה ---- אך רבני-חזל שנדמה להם שהם &quot;סמכות חכמים&quot; אמרו ההיפך</p><p>&quot;שְׂכַר מִצְוָה בְּהַאי עָלְמָא לֵיכָּא&quot; (קידושין ל&quot;ט ע&quot;ב)</p><p>זהו לשון הגמרא בשם רבי יעקב, שאומר : אין שכר מצוות בעולם הזה —כלומר, השכר האמיתי הוא בעולם הבא, לא כאן.</p><p>לכן הרבנים לא משכילים ליישר את דרכם כי כאשר אלהים מונע את אורם וחשוך להם הם יאמרו כי הטוב רק בעולם הבא</p><p>ולמעשה שכחו את כל משפטי התורה כפסוקים הבאים...המעידים כי לצדיק [איש המצוות] טוב בעולם הזה</p><p>משלי כט6: &quot;בְּפֶשַׁע אִישׁ רָע מוֹקֵשׁ וְצַדִּיק יָרוּן וְשָׂמֵחַ&quot;</p><p>תהלים צז11: &quot;אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי לֵב שִׂמְחָה&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-19 15:18:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

