		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3109_1.html',
		'<p>האיש החכם מכל האדם כתב בחכמת שלמה המלך בספר משלי יא31: &quot;הֵן צַדִּיק בָּאָרֶץ יְשֻׁלָּם אַף כִּי רָשָׁע וְחוֹטֵא&quot;</p><p>לאמור כי שכר הצדיק פה בארץ בעולם הזה ---- אך רבני-חזל שנדמה להם שהם &quot;סמכות חכמים&quot; אמרו ההיפך</p><p>&quot;שְׂכַר מִצְוָה בְּהַאי עָלְמָא לֵיכָּא&quot; (קידושין ל&quot;ט ע&quot;ב)</p><p>זהו לשון הגמרא בשם רבי יעקב, שאומר : אין שכר מצוות בעולם הזה —כלומר, השכר האמיתי הוא בעולם הבא, לא כאן.</p><p>לכן הרבנים לא משכילים ליישר את דרכם כי כאשר אלהים מונע את אורם וחשוך להם הם יאמרו כי הטוב רק בעולם הבא</p><p>ולמעשה שכחו את כל משפטי התורה כפסוקים הבאים...המעידים כי לצדיק [איש המצוות] טוב בעולם הזה</p><p>משלי כט6: &quot;בְּפֶשַׁע אִישׁ רָע מוֹקֵשׁ וְצַדִּיק יָרוּן וְשָׂמֵחַ&quot;</p><p>תהלים צז11: &quot;אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי לֵב שִׂמְחָה&quot;</p><p>-</p><p>על פי מקרא הקודש</p><p>השכר הוא בעולם הזה --- ולא רק זה כי אם....</p><p>גם אין שכר בעולם הבא</p><p>ואם אתה מראה את הפסוק -- והרוח תשוב אל האלהים אשר נתנה</p><p>אז גם המצרים הרשעים שטבעו בים-סוף שבים בסוף אל - האלהים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-20 03:45:10'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

