		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3101_9.html',
		'<p>משלי יג12: &quot;תּוֹחֶלֶת מְמֻשָּׁכָה מַחֲלָה לֵב וְעֵץ חַיִּים תַּאֲוָה בָאָה&quot;</p><p>וְעֵץ חַיִּים תַּאֲוָה בָאָה = ועץ חיים תאוה באה = ועץ חיים ת**אוה-ב**אה</p><p>בצמד המילים : תאוה-באה --- נמצא אוהב [אלהים]</p><p>אם אתה אוהב אלהים אז זה עץ-חיים לאמור יֵשׁ לך הכל</p><p>משלי ח21: &quot;לְהַנְחִיל אֹהֲבַי יֵשׁ וְאֹצְרֹתֵיהֶם אֲמַלֵּא&quot;</p><p>ואם אתה לא אוהב אלהים אז תאלץ להיות בהמתנה כי משאלות-לבך לא יתגשמו</p><p>ואם משאלותיך לא יתגשמו תרגיש מחנק = תּוֹחֶלֶת מְמֻשָּׁכָה מַחֲלָה לֵב </p><p>שמואל ב יז23: &quot;וַאֲחִיתֹפֶל רָאָה כִּי לֹא נֶעֶשְׂתָה עֲצָתוֹ....... וַיַּחֲבֹשׁ אֶת הַחֲמוֹר וַיָּקָם וַיֵּלֶךְ אֶל בֵּיתוֹ אֶל עִירוֹ וַיְצַו אֶל בֵּיתוֹ וַיֵּחָנַק וַיָּמָת וַיִּקָּבֵר בְּקֶבֶר אָבִיו&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-20 08:05:00'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3101_9.html',
		'<p>משלי יג12: &quot;תּוֹחֶלֶת מְמֻשָּׁכָה מַחֲלָה לֵב וְעֵץ חַיִּים תַּאֲוָה בָאָה&quot;</p><p>וְעֵץ חַיִּים תַּאֲוָה בָאָה = ועץ חיים תאוה באה = ועץ חיים ת**אוה-ב**אה</p><p>בצמד המילים : תאוה-באה --- נמצא אוהב [אלהים]</p><p>אם אתה אוהב אלהים אז זה עֵץ חַיִּים לאמור יֵשׁ לך הכל</p><p>משלי ח21: &quot;לְהַנְחִיל אֹהֲבַי יֵשׁ וְאֹצְרֹתֵיהֶם אֲמַלֵּא&quot;</p><p>ואם אתה לא אוהב אלהים אז תאלץ להיות בהמתנה כי משאלות-לבך לא יתגשמו</p><p>ואם משאלותיך לא יתגשמו תרגיש מחנק = תּוֹחֶלֶת מְמֻשָּׁכָה מַחֲלָה לֵב</p><p>שמואל ב יז23: &quot;וַאֲחִיתֹפֶל רָאָה כִּי לֹא נֶעֶשְׂתָה עֲצָתוֹ....... וַיַּחֲבֹשׁ אֶת הַחֲמוֹר וַיָּקָם וַיֵּלֶךְ אֶל בֵּיתוֹ אֶל עִירוֹ וַיְצַו אֶל בֵּיתוֹ וַיֵּחָנַק וַיָּמָת וַיִּקָּבֵר בְּקֶבֶר אָבִיו&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-20 08:05:56'
		)
		;

SET character_set_client=utf8mb3;
