		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2655_5.html',
		'<p>כאשר חיית המחמד שלך גוססת עומדת למות -- שמע דברי</p><p>להיות איתה ברגעיה האחרונים ולא לעזוב אותה בשום אופן</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי</p><p>כאשר המשיח מצפה שאלהים יהיה עימדו בגיא צלמות ברגעיו האחרונים</p><p>גם בעל החיים מצפה שתהיה עימדו ולא תעזוב אותו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-20 08:21:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/daian2_0.html',
		'<p>אם אלהיך הוא יהוה אלהים אז בהחלט הקול הפנימי שלך הוא סמכות אלהים !!!</p><p>אבל אם אלהיך הוא אלהים אחרים אז במצב כזה יתרחש אסון ---</p><p>אם אתה מעניק סמכות אלהים לקול הפנימי הנובע מאלהים אחרים --- אלה הם חולי הנפש ששומעים &quot;קולות&quot; --- אך אני לא כזה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-20 12:47:27'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>https://www.hidabroot.org/article/1209474</p><p>ציטוט מהקישור הזה......</p><p>האילן הקדוש מיוחס מדורי דורות ככוח סגולי רב-עוצמה, </p><p>היכול להגן ולפעול ישועות ורחמים – בתחומים רבים, </p><p>ובפרט לעניין נשיאת חן, הצלחה, שמירה מעין הרע, ופתיחת שערים.[סוף ציטוט]</p><p>-</p><p>זהירות: אין דבר כזה &quot;האילן הקדוש&quot; לא קדוש ולא בטיח --- מדובר בעבודה זרה לכל דבר ועניין</p><p>זה פרי דמיונם של רבנים-מקובלים בטלנים לא יוצלחים שחיפשו דרך לעקוץ את הציבור באמצעות רמייה וכזב</p><p>לפי דבריהם זה מסוגל לישועות ואני מודיע לכם הנאיביים אל תקנו את הסחורה הזאת כי לא אמת</p><p>אם אתם רוצים באמת ישועה לכו בדרך האל ככתוב בעשרת הדברים ביד משה איש האלהים</p><p>תהלים מ5: &quot;אַשְׁרֵי הַגֶּבֶר אֲשֶׁר שָׂם יהוה מִבְטַחוֹ וְלֹא פָנָה אֶל רְהָבִים וְשָׂטֵי כָזָב&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-21 08:01:41'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>https://www.hidabroot.org/article/1209474</p><p>ציטוט מהקישור הזה......</p><p>האילן הקדוש מיוחס מדורי דורות ככוח סגולי רב-עוצמה,</p><p>היכול להגן ולפעול ישועות ורחמים – בתחומים רבים,</p><p>ובפרט לעניין נשיאת חן, הצלחה, שמירה מעין הרע, ופתיחת שערים.[סוף ציטוט]</p><p>-</p><p>זהירות: אין דבר כזה &quot;האילן הקדוש&quot; לא קדוש ולא בטיח --- מדובר בעבודה זרה לכל דבר ועניין</p><p>זה פרי דמיונם של רבנים-מקובלים בטלנים לא יוצלחים שמחפשים כסף-קל לעקוץ את הציבור באמצעות רמייה וכזב</p><p>לפי דבריהם זה מסוגל לישועות ואני מודיע לכם הנאיביים אל תקנו את הסחורה הזאת כי לא אמת</p><p>אם אתם רוצים באמת ישועה לכו בדרך האל ככתוב בעשרת הדברים ביד משה איש האלהים</p><p>תהלים מ5: &quot;אַשְׁרֵי הַגֶּבֶר אֲשֶׁר שָׂם יהוה מִבְטַחוֹ וְלֹא פָנָה אֶל רְהָבִים וְשָׂטֵי כָזָב&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-21 08:03:25'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

