		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26a4_2.html',
		'<p>בראשית יח25: &quot;חָלִלָה לְּךָ מֵעֲשֹׂת כַּדָּבָר הַזֶּה לְהָמִית צַדִּיק עִם רָשָׁע וְהָיָה כַצַּדִּיק כָּרָשָׁע חָלִלָה לָּךְ הֲשֹׁפֵט כָּל הָאָרֶץ לֹא יַעֲשֶׂה מִשְׁפָּט&quot;</p><p>לכן אני דיין -- כאברהם אבינו מסנגר על מדינת סדום בישראל אבל.....</p><p>המצב בישראל כבר רבות בשנים קשה מאד מאד עוד יותר ממה שאתה חושב</p><p>מצעדי גאווה של הומואים בישראל</p><p>שרים וחברי כנסת הומואים</p><p>בכירים הומואים אונסים גברים</p><p>מערכת המשפט רקובה</p><p>צהל מממן ניתוחים לשינוי מין</p><p>הבנקים וחברות האשראי עושקות את העם בהלואות בריבית</p><p>רבני ישראל מתעתעים בעם הדלים ומנצלים את מצוקתם לעשקם</p><p>https://tora.quest/tnk1/messages/prqim_t1502_2.html</p><p>יוקר המחייה בלתי אפשרי לקיום והילדים גרים אצל ההורים הזקנים</p><p>לא ניתן לקנות בית בישראל כי המחירים בשמים</p><p>חסרי הישע בישראל מוכים לעיני המצלמות קשישים בבתי אבות וילדים בגן</p><p>משפחות הפשע יורים חופשי ברחוב ולמשטרה אין מענה</p><p>המוזיקה הישראלית זבל רגשות כסילים</p><p>הרבנות זבל יש גמרא אין תורה</p><p>הפוליטיקאים זבל אין חינוך אין תרבות אין בטחון וכל יום חיילים נופלים</p><p>ערבים בכל הארץ גובים דמי חסות ומי שלא משלם ...משלם</p><p>חקלאות ישראל נהרסה וכמעט נעלמה הכל הופשר לנדל&quot;ן בצע כסף</p><p>החברות הגדולות במשק נוהגות כקרטל ומתאמות מחירים גבוהים</p><p>הרשויות מושחתות</p><p>רשות הטבע והגנים רוצחת בעלי חיים למען בצע כסף למען נדלן ועוד נדלן שמילאו את הארץ בטון ואספלט ואין חי וצומח</p><p>כעת זו מדינת סדום !!!!!! כאשר יור הכנסת הוא מאנשי סדום אך עדיין יש עוד אנשים טובים מכדי להשחית את המדינה הזו</p><p>אבל המצב קשה מאד וכשהמצב יחריף ויהיה בלתי נסבל ותגיע העת לפקודה [וזה יגיע] אז מדינת ישראל תחרב</p><p>רבותי האנטישמיות מוצדקת רק מהסיבות שכתבתי ואני אני איש ימין בעד ארץ ישראל השלמה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-24 08:13:40'
		)
