		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/tora/brejit/clm_wdmut.html',
		'<p>על פי חז&quot;ל והפרשנות המקובלת (כמו רש&quot;י), המילים נאמרו בלשון רבים כביטוי של ענווה והתייעצות.</p><p>המלאכים: אלוהים מתייעץ עם פמליה של מעלה (המלאכים) לפני בריאת האדם, כדי לשתף אותם בהחלטה וללמד את בני האדם דרך ארץ וענווה – שגדול יתייעץ עם קטן ממנו.</p><p>השמיים והארץ: פרשנים אחרים (כמו הרמב&quot;ן) מציעים שהפנייה היא אל מרכיבי הבריאה שכבר קיימים. האדם מורכב מגוף (חומר מן הארץ) ונשמה (רוח מן השמיים), ולכן הבריאה המשותפת היא של האלוהות יחד עם כוחות הטבע.חוקרי מקרא רבים רואים בנוסח זה הד למיתולוגיות המזרח הקדום (כמו המיתולוגיה הבבלית או הכנענית), שבהן הייתה נהוגה מועצת אלים (&quot;עדת אל&quot;). על פי גישה זו, הסיפור המקראי עבר תהליך של מונותאיזציה (מעבר לאל אחד), אך השפה שקלטה את הסיפורים הותירה עקבות לשוניים של אותה מועצה קדומה המקבלת החלטות יחד.</p>',
		'101033181068587250308',
		'אבישי גרנות',
		'2026-05-25 18:08:02'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

