		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b01_2.html',
		'<p>מלאכי א2: &quot;אָהַבְתִּי אֶתְכֶם אָמַר יהוה וַאֲמַרְתֶּם בַּמָּה אֲהַבְתָּנוּ הֲלוֹא אָח עֵשָׂו לְיַעֲקֹב נְאֻם יהוה וָאֹהַב אֶת יַעֲקֹב&quot;</p><p>בלשון עבר - אָהַבְתִּי אֶתְכֶם -   ולא כתוב שאלהים אוהב כעת את ישראל אז את מי אלהים כן אוהב בישראל?</p><p> יהוה אֹהֵב צַדִּיקִים</p><p>תהלים קמו8: &quot;יהוה פֹּקֵחַ עִוְרִים יהוה זֹקֵף כְּפוּפִים יהוה אֹהֵב צַדִּיקִים&quot;</p><p>אז איך כתוב שכל עם ישראל צדיקים? זה מדובר לאחרית הימים לאחר סינון לעם ישראל</p><p>ישעיהו ס21: &quot;וְעַמֵּךְ כֻּלָּם צַדִּיקִים לְעוֹלָם יִירְשׁוּ אָרֶץ נֵצֶר מטעו[מַטָּעַי] מַעֲשֵׂה יָדַי לְהִתְפָּאֵר&quot;</p><p>תהלים לז29: &quot;צַדִּיקִים יִירְשׁוּ אָרֶץ וְיִשְׁכְּנוּ לָעַד עָלֶיהָ&quot; = &quot;בְּנֵי עֲבָדֶיךָ יִשְׁכּוֹנוּ וְזַרְעָם לְפָנֶיךָ יִכּוֹן&quot; [תהלים קב29:]</p><p>כי רק הצדיקים הם עם ישראל וכל שאר הרשעים שהיו בישראל נכרתו מקרב עמם</p><p>תהלים לז9: &quot;כִּי מְרֵעִים יִכָּרֵתוּן וְקֹוֵי יהוה הֵמָּה יִירְשׁוּ אָרֶץ&quot;</p><p>תהלים לז22: &quot;כִּי מְבֹרָכָיו יִירְשׁוּ אָרֶץ וּמְקֻלָּלָיו יִכָּרֵתוּ&quot;</p><p>תהלים לז11: &quot;וַעֲנָוִים יִירְשׁוּ אָרֶץ וְהִתְעַנְּגוּ עַל רֹב שָׁלוֹם&quot;</p><p>“עם ישראל האמיתי = הצדיקים וַהעֲנָוִים וְקֹוֵי יהוה</p><p>אך הרשעים — לא חלק מהעם, גם אם נולדו בו.”</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-31 11:02:41'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b01_2.html',
		'<p>מלאכי א2: &quot;אָהַבְתִּי אֶתְכֶם אָמַר יהוה וַאֲמַרְתֶּם בַּמָּה אֲהַבְתָּנוּ הֲלוֹא אָח עֵשָׂו לְיַעֲקֹב נְאֻם יהוה וָאֹהַב אֶת יַעֲקֹב&quot;</p><p>בלשון עבר - אָהַבְתִּי אֶתְכֶם - ולא כתוב שאלהים אוהב כעת את ישראל אז את מי אלהים כן אוהב בישראל?</p><p>יהוה אֹהֵב צַדִּיקִים</p><p>תהלים קמו8: &quot;יהוה פֹּקֵחַ עִוְרִים יהוה זֹקֵף כְּפוּפִים יהוה אֹהֵב צַדִּיקִים&quot;</p><p>אז איך כתוב שכל עם ישראל צדיקים? זה מדובר לאחרית הימים לאחר סינון לעם ישראל</p><p>ישעיהו ס21: &quot;וְעַמֵּךְ כֻּלָּם צַדִּיקִים לְעוֹלָם יִירְשׁוּ אָרֶץ נֵצֶר מטעו[מַטָּעַי] מַעֲשֵׂה יָדַי לְהִתְפָּאֵר&quot;</p><p>תהלים לז29: &quot;צַדִּיקִים יִירְשׁוּ אָרֶץ וְיִשְׁכְּנוּ לָעַד עָלֶיהָ&quot; = &quot;בְּנֵי עֲבָדֶיךָ יִשְׁכּוֹנוּ וְזַרְעָם לְפָנֶיךָ יִכּוֹן&quot; [תהלים קב29:]</p><p>ישעיהו ד3: &quot;וְהָיָה הַנִּשְׁאָר בְּצִיּוֹן וְהַנּוֹתָר בִּירוּשָׁלַים קָדוֹשׁ יֵאָמֶר לוֹ כָּל הַכָּתוּב לַחַיִּים בִּירוּשָׁלַים&quot;</p><p>כי רק הצדיקים הם עם ישראל וכל שאר הרשעים שהיו בישראל נכרתו מקרב עמם</p><p>תהלים לז9: &quot;כִּי מְרֵעִים יִכָּרֵתוּן וְקֹוֵי יהוה הֵמָּה יִירְשׁוּ אָרֶץ&quot;</p><p>תהלים לז22: &quot;כִּי מְבֹרָכָיו יִירְשׁוּ אָרֶץ וּמְקֻלָּלָיו יִכָּרֵתוּ&quot;</p><p>תהלים לז11: &quot;וַעֲנָוִים יִירְשׁוּ אָרֶץ וְהִתְעַנְּגוּ עַל רֹב שָׁלוֹם&quot;</p><p>“עם ישראל האמיתי = הצדיקים וַהעֲנָוִים וְקֹוֵי יהוה</p><p>אך הרשעים — לא חלק מהעם, גם אם נולדו בו.”</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-31 11:04:59'
		)
		;

SET character_set_client=utf8mb3;
