		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0102_11.html',
		'<p>על פי החזון רצון אלהים לדור הזה שההומואים יתחזקו כדי להשמידם בעתיד כשיהיו בשיאם</p><p>ומצד שני התורה אוסרת על קשר מיני בין גברים אז מה הנכון לפעול בעת הזו </p><p>האם על פי התורה להלחם בהומואים או לפעול על פי החזון לחזק ההומואים????</p><p>משלי כט18: &quot;בְּאֵין חָזוֹן יִפָּרַע עָם וְשֹׁמֵר תּוֹרָה אַשְׁרֵהוּ&quot;</p><p>לכן יש לשמור על התורה ולחנך נגד התועבה הזאת</p><p>ובאשר לרצון אלהים המשתקף בחזון</p><p>דברים כט28: &quot;הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת&quot;</p><p>לאמור כי עלינו בני ישראל להתהלך תמים לפני יהוה בשמירת כל הנגלה שבתורה </p><p>ובאשר לנסתרות וסודות החזון את זה תשאירו ליהוה אלהינו [הוא כבר יטפל בזה]</p><p>לאמור לכם כי גם אם אתם רואים שאנשי סדום צוברים כח אל תיבהלו מזה זה חלק מהחזון -- להשמידם</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-05-31 17:34:23'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0102_11.html',
		'<p>על פי החזון רצון אלהים לדור הזה שההומואים יתחזקו כדי להשמידם בעתיד כשיהיו בשיאם</p><p>ומצד שני התורה אוסרת על קשר מיני בין גברים אז מה הנכון לפעול בעת הזו</p><p>האם על פי התורה להלחם בהומואים או לפעול על פי החזון לחזק ההומואים????</p><p>משלי כט18: &quot;בְּאֵין חָזוֹן יִפָּרַע עָם וְשֹׁמֵר תּוֹרָה אַשְׁרֵהוּ&quot;</p><p>לכן יש לשמור על התורה ולחנך נגד התועבה הזאת</p><p>ובאשר לרצון אלהים המשתקף בחזון</p><p>דברים כט28: &quot;הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת&quot;</p><p>לאמור כי עלינו בני ישראל להתהלך תמים לפני יהוה בשמירת כל הנגלה שבתורה</p><p>ובאשר לנסתרות וסודות החזון את זה תשאירו ליהוה אלהינו [הוא כבר יטפל בזה]</p><p>לאמור לכם כי גם אם אתם רואים שאנשי סדום צוברים כח אל תיבהלו מזה זה חלק מהחזון -- להשמידם</p><p>-</p><p>אני פלורליסט ולא שונא בני אדם</p><p>אבל עם כל הכבוד לפתיחות ולפלורליזם</p><p>אני לא מוכן שיבזו את קדשי ישראל</p><p>אסור לאיש סדום להיות בפוליטיקה בצבא ובהנהגה הדתית</p><p>אם יו&quot;ר הכנסת השוכב עם בן זוגו משכב סדום ובא להנחות חידון תנ&quot;ך</p><p>אז צריך להלחם באנשי הסדום האלה ולבער אותם מישראל</p><p>אם אנשי הסדום האלה בישראל מנצלים פלורליזם להשתלט על קדשי ישראל</p><p>אז יש לשוב לציווי המקורי של התורה</p><p>ויקרא כ13: &quot;וְאִישׁ אֲשֶׁר יִשְׁכַּב אֶת זָכָר מִשְׁכְּבֵי אִשָּׁה תּוֹעֵבָה עָשׂוּ שְׁנֵיהֶם מוֹת יוּמָתוּ דְּמֵיהֶם בָּם&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-01 05:38:44'
		)
		;

