		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26a4_2.html',
		'<p>העיר תל-אביב</p><p>https://www.beinharimtours.com/wwwroot/uploads/articles/temp/a4c8af97-b565-40b1-9767-64c68a2796b1.jpg</p><p>עיר-הבירה ירושלים -- עיר הקודש?</p><p>https://static-cdn.toi-media.com/www/uploads/2019/06/F190604HP01-e1559652113746-640x400.jpg</p><p>העיר חיפה</p><p>https://israelnews.org/wp-content/uploads/2021/06/20210617_074102084_iOS-scaled.jpeg</p><p>העיר ראשל&quot;צ</p><p>https://www.cityrumorsabruzzo.it/wp-content/uploads/2025/09/IMG_1483.jpeg</p><p>העיר רמת השרון</p><p>https://www.facebook.com/photo?fbid=1406879014820137&amp;set=a.326066972901352</p><p>הערים הרצליה גבעתים ועוד הרבה ערים נוספות ....... וכמעט כל ערי ישראל נגועות בתועבה --------------</p><p>לאמור לכם כי יש להכות את כל הערים האלה --- ואם כל המדינה נגועה בתועבה אז מדינת ישראל תושמד</p><p>רבותי האנטישמיות מוצדקת כי חרון-אף יהוה על ישראל</p><p> ואני לא חלילה מארגון BDS  הצועקים Free Free Palestin</p><p>אך אני זועק את זעקת עבדי-יהוה אלהי ישראל</p><p>-----------------------------------------------------------------------------------------------------------------------</p><p>בתורת משה איש האלהים בספר דברים פרק יג כתוב:</p><p> יג כִּי-תִשְׁמַע בְּאַחַת עָרֶיךָ אֲשֶׁר יְהוָה אֱלֹהֶיךָ נֹתֵן לְךָ לָשֶׁבֶת שָׁם לֵאמֹר.  </p><p>יד יָצְאוּ אֲנָשִׁים בְּנֵי-בְלִיַּעַל מִקִּרְבֶּךָ וַיַּדִּיחוּ אֶת-יֹשְׁבֵי עִירָם לֵאמֹר  נֵלְכָה וְנַעַבְדָה אֱלֹהִים אֲחֵרִים אֲשֶׁר לֹא-יְדַעְתֶּם.  </p><p>טו וְדָרַשְׁתָּ וְחָקַרְתָּ וְשָׁאַלְתָּ הֵיטֵב וְהִנֵּה אֱמֶת נָכוֹן הַדָּבָר נֶעֶשְׂתָה הַתּוֹעֵבָה הַזֹּאת בְּקִרְבֶּךָ.  </p><p>טז הַכֵּה תַכֶּה אֶת-יֹשְׁבֵי הָעִיר הַהִוא לְפִי-חָרֶב.......  הַחֲרֵם אֹתָהּ וְאֶת-כָּל-אֲשֶׁר-בָּהּ וְאֶת-בְּהֶמְתָּהּ לְפִי-חָרֶב.  </p><p>יז וְאֶת-כָּל-שְׁלָלָהּ תִּקְבֹּץ אֶל-תּוֹךְ רְחֹבָהּ וְשָׂרַפְתָּ בָאֵשׁ אֶת-הָעִיר וְאֶת-כָּל-שְׁלָלָהּ כָּלִיל לַיהוָה אֱלֹהֶיךָ וְהָיְתָה תֵּל עוֹלָם לֹא תִבָּנֶה עוֹד.  </p><p>יח וְלֹא-יִדְבַּק בְּיָדְךָ מְאוּמָה מִן-הַחֵרֶם לְמַעַן יָשׁוּב יְהוָה מֵחֲרוֹן אַפּוֹ וְנָתַן-לְךָ רַחֲמִים וְרִחַמְךָ וְהִרְבֶּךָ כַּאֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ.  </p><p>יט כִּי תִשְׁמַע בְּקוֹל יְהוָה אֱלֹהֶיךָ לִשְׁמֹר אֶת-כָּל-מִצְו‍ֹתָיו אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם לַעֲשׂוֹת הַיָּשָׁר בְּעֵינֵי יְהוָה אֱלֹהֶיךָ.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-01 10:39:47'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/nvia/tryasr/xv-02-01.html',
		'<p>(אדר&quot;נ ט) ... באותה שעה א&quot;ל אהרן למשה משה אחי כסבור אתה בעצמך שצרעת זו על מרים נתונה אינה נתונה אלא על בשרו של אבא עמרם. אמשול לך משל למה הדבר דומה לאחד שנתן גחלת בתוך ידו אע&quot;פ שהופכה ממקום למקום מ&quot;מ בשרו נכוית שנאמר אל נא תהי כמת </p><p>באותה שעה התחיל אהרן לפייס במשה א&quot;ל משה אחי כלום עשינו רעה עם אחד בעולם א&quot;ל לאו ומה עם אחד בעולם לא עשינו רעה אתה שאחינו אתה האיך נעשה רעה עמך אבל מה אעשה שגגה היא בינותינו ברית שבינינו לבינך (מפני שהברית כרותה לאהרן ולבניו) שנא\' (עמוס א) ולא זכרו ברית אחים </p><p>באותה שעה עג משה עוגה קטנה ועמד בתוכה וביקש רחמים עליה ואמר איני זז מכאן עד שתתרפא מרים אחותי שנאמר (במדבר יב) אל נא רפא נא לה ...</p><p></p>',
		'104379256302550476035',
		'סימה שרייבר',
		'2026-06-02 07:42:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0215_4.html',
		'<p>גבר עם ביצים שים לב זה בשבילך אל תהיה  מְרוֹחַ אָשֶׁךְ </p><p>ויקרא כא20: &quot;אוֹ גִבֵּן אוֹ דַק אוֹ תְּבַלֻּל בְּעֵינוֹ אוֹ גָרָב אוֹ יַלֶּפֶת אוֹ מְרוֹחַ אָשֶׁךְ&quot; </p><p>אם ישך ביצים קשות זה טוב ומראה על בריאות </p><p>ואם ישך ביצים רכות מאד זה לא כל כך טוב </p><p>אבל תוכל לפתור זאת על ידי עשות צדקה [וחסד במיוחד עם בעלי החיים] יום יום </p><p>וזבח ושתיית יין בקידוש יום השבת בארוחה הראשונה בבוקר היא הסעודה השנייה</p><p>לאחר ששותים יין בקודש הבעיה נפתרת ולא תהיה מרוח אשך ואם זה עזר לך</p><p>אל תשכח להודות ליהוה ולדיין עבדו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-03 12:29:47'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

