		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_7.html',
		'<p>שמות יב48: &quot;וְכִי יָגוּר אִתְּךָ גֵּר וְעָשָׂה פֶסַח ליהוה הִמּוֹל לוֹ כָל זָכָר וְאָז יִקְרַב לַעֲשֹׂתוֹ וְהָיָה כְּאֶזְרַח הָאָרֶץ וְכָל עָרֵל לֹא יֹאכַל בּוֹ&quot;</p><p>זכר-נימול ראוי לאכול מבשר-קורבן-הזבח אבל לגבר ערל זה יגרום צרות --- וזה מסביר את העובדה הזאת הדבר הזה שהמנדעים הערלים נמנעים מבשר אדום</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-03 12:54:04'
		)
		;

