		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26a4_2.html',
		'<p>עמוס ה2: &quot;נָפְלָה לֹא תוֹסִיף קוּם בְּתוּלַת יִשְׂרָאֵל נִטְּשָׁה עַל אַדְמָתָהּ אֵין מְקִימָהּ&quot;</p><p>דגלי גאווה במתחם הכנסת</p><p>https://www.facebook.com/MK.YairGolan/photos/%D7%A1%D7%95%D7%A3-%D7%A1%D7%95%D7%A3-%D7%A7%D7%A6%D7%AA-%D7%92%D7%90%D7%95%D7%95%D7%94-%D7%91%D7%9B%D7%A0%D7%A1%D7%AA/1566519955032862/</p><p> </p><p>העיר תל-אביב</p><p>https://www.beinharimtours.com/wwwroot/uploads/articles/temp/a4c8af97-b565-40b1-9767-64c68a2796b1.jpg</p><p>עיר-הבירה ירושלים -- עיר הקודש?</p><p>https://static-cdn.toi-media.com/www/uploads/2019/06/F190604HP01-e1559652113746-640x400.jpg</p><p>העיר חיפה</p><p>https://israelnews.org/wp-content/uploads/2021/06/20210617_074102084_iOS-scaled.jpeg</p><p>העיר ראשל&quot;צ</p><p>https://www.cityrumorsabruzzo.it/wp-content/uploads/2025/09/IMG_1483.jpeg</p><p>העיר רמת השרון</p><p>https://www.facebook.com/photo?fbid=1406879014820137&amp;set=a.326066972901352</p><p>הערים הרצליה גבעתים ועוד הרבה ערים נוספות ....... וכמעט כל ערי ישראל נגועות בתועבה --------------</p><p>לאמור לכם כי יש להכות את כל הערים האלה --- ואם כל המדינה נגועה בתועבה אז מדינת ישראל תושמד</p><p>רבותי האנטישמיות מוצדקת כי חרון-אף יהוה על ישראל</p><p>ואני לא חלילה מארגון BDS הצועקים Free Free Palestin</p><p>אך אני זועק את זעקת עבדי-יהוה אלהי ישראל</p><p>-----------------------------------------------------------------------------------------------------------------------</p><p>בתורת משה איש האלהים בספר דברים פרק יג כתוב:</p><p>יג כִּי-תִשְׁמַע בְּאַחַת עָרֶיךָ אֲשֶׁר יְהוָה אֱלֹהֶיךָ נֹתֵן לְךָ לָשֶׁבֶת שָׁם לֵאמֹר.</p><p>יד יָצְאוּ אֲנָשִׁים בְּנֵי-בְלִיַּעַל מִקִּרְבֶּךָ וַיַּדִּיחוּ אֶת-יֹשְׁבֵי עִירָם לֵאמֹר נֵלְכָה וְנַעַבְדָה אֱלֹהִים אֲחֵרִים אֲשֶׁר לֹא-יְדַעְתֶּם.</p><p>טו וְדָרַשְׁתָּ וְחָקַרְתָּ וְשָׁאַלְתָּ הֵיטֵב וְהִנֵּה אֱמֶת נָכוֹן הַדָּבָר נֶעֶשְׂתָה הַתּוֹעֵבָה הַזֹּאת בְּקִרְבֶּךָ.</p><p>טז הַכֵּה תַכֶּה אֶת-יֹשְׁבֵי הָעִיר הַהִוא לְפִי-חָרֶב....... הַחֲרֵם אֹתָהּ וְאֶת-כָּל-אֲשֶׁר-בָּהּ וְאֶת-בְּהֶמְתָּהּ לְפִי-חָרֶב.</p><p>יז וְאֶת-כָּל-שְׁלָלָהּ תִּקְבֹּץ אֶל-תּוֹךְ רְחֹבָהּ וְשָׂרַפְתָּ בָאֵשׁ אֶת-הָעִיר וְאֶת-כָּל-שְׁלָלָהּ כָּלִיל לַיהוָה אֱלֹהֶיךָ וְהָיְתָה תֵּל עוֹלָם לֹא תִבָּנֶה עוֹד.</p><p>יח וְלֹא-יִדְבַּק בְּיָדְךָ מְאוּמָה מִן-הַחֵרֶם לְמַעַן יָשׁוּב יְהוָה מֵחֲרוֹן אַפּוֹ וְנָתַן-לְךָ רַחֲמִים וְרִחַמְךָ וְהִרְבֶּךָ כַּאֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ.</p><p>יט כִּי תִשְׁמַע בְּקוֹל יְהוָה אֱלֹהֶיךָ לִשְׁמֹר אֶת-כָּל-מִצְו‍ֹתָיו אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם לַעֲשׂוֹת הַיָּשָׁר בְּעֵינֵי יְהוָה אֱלֹהֶיךָ.</p><p>----------------------------------------------------------------------------------------------------------------------------</p><p>עתה כל המדינה תועבה לכן נופלים חללים במלחמה יום יום וזאת כדי לדבר אליכם למען תעורו משנתכם</p><p>מדינת ישראל בתרדמה לא למדו דבר מאסון 7 באוקטובר ------- החורבן הטוטלי לפנינו</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-03 15:23:04'
		)
		;

SET character_set_client=utf8mb3;
