		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0518_2.html',
		'<p>בני-ישראל שמעו בקולי אל תפנו לתקשור המתקשרים הדורשים אל המתים כי אם הייה קשור ליהוה צבאות לבדו</p><p>כי אם קשרת קשר ליהוה אלהים אלהי ישראל אז יש ביניכם קשר לאמור כי גם יהוה אלהים צבאות קשור אליך</p><p>ספר תהילות פרק ט פסוק 11 כתוב: ויבטחו בך יודעי שמך כי לא עזבת דרשיך יהוה: ---בטחו ביהוה אלהים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-04 07:08:18'
		)
		;

