		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2823_0.html',
		'<p> אחיי בני-ישראל אתם האוהבים את דיין לשמוע בקולו</p><p>אגיד לכם כעת כי בדור הזה [להטבי&quot;ם בשלטון ורבנים טפשים] יש שטן על ישראל</p><p>לכן אני מייעץ לכם לבלתי שתות היין -- אל תשתו יין בכלל גם לא בשמחות וארועים כחתונה וכולי וגם לא במועדי-חג מלבד שבתות-יהוה</p><p>רק ביום שבת קודש עשו ברכה בקידוש יום השבת ושתו יין בסעודה החלבית בארוחת הבוקר בתם-הארוחה אחזו בכוס היין וברכו כזאת כדברים הבאים</p><p>ישעיהו סה8: &quot;כֹּה אָמַר יהוה כַּאֲשֶׁר יִמָּצֵא הַתִּירוֹשׁ בָּאֶשְׁכּוֹל וְאָמַר אַל תַּשְׁחִיתֵהוּ כִּי בְרָכָה בּוֹ כֵּן אֶעֱשֶׂה לְמַעַן עֲבָדַי לְבִלְתִּי הַשְׁחִית הַכֹּל&quot;</p><p>ישעיהו נה1: &quot;הוֹי כָּל צָמֵא לְכוּ לַמַּיִם וַאֲשֶׁר אֵין לוֹ כָּסֶף לְכוּ שִׁבְרוּ וֶאֱכֹלוּ וּלְכוּ שִׁבְרוּ בְּלוֹא כֶסֶף וּבְלוֹא מְחִיר יַיִן וְחָלָב&quot;</p><p>בראשית מט12: &quot;חַכְלִילִי עֵינַיִם מִיָּיִן וּלְבֶן שִׁנַּיִם מֵחָלָב&quot;</p><p>שיר השירים ה1: &quot;בָּאתִי לְגַנִּי אֲחֹתִי כַלָּה אָרִיתִי מוֹרִי עִם בְּשָׂמִי אָכַלְתִּי יַעְרִי עִם דִּבְשִׁי שָׁתִיתִי יֵינִי עִם חֲלָבִי אִכְלוּ רֵעִים שְׁתוּ וְשִׁכְרוּ דּוֹדִים&quot;</p><p>שמות כ9: &quot;וְיוֹם הַשְּׁבִיעִי שַׁבָּת ליהוה אֱלֹהֶיךָ לֹא תַעֲשֶׂה כָל מְלָאכָה אַתָּה וּבִנְךָ וּבִתֶּךָ עַבְדְּךָ וַאֲמָתְךָ וּבְהֶמְתֶּךָ וְגֵרְךָ אֲשֶׁר בִּשְׁעָרֶיךָ&quot;</p><p>דברים ה13: &quot;וְיוֹם הַשְּׁבִיעִי שַׁבָּת ליהוה אֱלֹהֶיךָ לֹא תַעֲשֶׂה כָל מְלָאכָה אַתָּה וּבִנְךָ וּבִתֶּךָ וְעַבְדְּךָ וַאֲמָתֶךָ וְשׁוֹרְךָ וַחֲמֹרְךָ וְכָל בְּהֶמְתֶּךָ וְגֵרְךָ אֲשֶׁר בִּשְׁעָרֶיךָ לְמַעַן יָנוּחַ עַבְדְּךָ וַאֲמָתְךָ כָּמוֹךָ&quot;</p><p>כעת אחוז בכוס היין בתם-הארוחה ופתח פיך לאמור: לא להוללות אני שותה כי אם לעונג שבת לְמַעַן יהוה אֱלֹהֶיךָ וְלִקְדוֹשׁ יִשְׂרָאֵל כִּי פֵאֲרָךְ</p><p>https://tora.quest/tnk1/daian</p><p>דַיָּן שֵׁם מְשָׁרֵת יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-05 08:36:03'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

