		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2690_3.html',
		'<p>רוח נבואה = רוח חכמה [חכמת לב]</p><p>תהלים צ12: &quot;לִמְנוֹת יָמֵינוּ כֵּן הוֹדַע וְנָבִא לְבַב חָכְמָה&quot;</p><p>דברים לד9: &quot;וִיהוֹשֻׁעַ בִּן נוּן מָלֵא רוּחַ חָכְמָה....... כִּי סָמַךְ מֹשֶׁה אֶת יָדָיו עָלָיו וַיִּשְׁמְעוּ אֵלָיו בְּנֵי יִשְׂרָאֵל וַיַּעֲשׂוּ כַּאֲשֶׁר צִוָּה יהוה אֶת מֹשֶׁה&quot;</p><p>ספר שמות פרק 31 כתוב:</p><p>( ו)   וַאֲנִי הִנֵּה נָתַתִּי אִתּוֹ אֵת אָהֳלִיאָב בֶּן אֲחִיסָמָךְ לְמַטֵּה דָן ******* וּבְלֵב כָּל חֲכַם לֵב נָתַתִּי חָכְמָה וְעָשׂוּ אֵת כָּל אֲשֶׁר צִוִּיתִךָ.*******</p><p>אם בחכמי-לב יש את החכמה לעשות כאשר ציוה אלהים את משה אבי הנביאים על כן חכמי הלב האלה נביאים כמשה איש האלהים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-05 12:56:10'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1201_1.html',
		'<p>יחזקאל א1: &quot;וַיְהִי בִּשְׁלֹשִׁים שָׁנָה בָּרְבִיעִי בַּחֲמִשָּׁה לַחֹדֶשׁ וַאֲנִי בְתוֹךְ הַגּוֹלָה עַל נְהַר כְּבָר נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים&quot;</p><p>מלאכי ג10: &quot;הָבִיאוּ אֶת כָּל הַמַּעֲשֵׂר אֶל בֵּית הָאוֹצָר וִיהִי טֶרֶף בְּבֵיתִי וּבְחָנוּנִי נָא בָּזֹאת אָמַר יהוה צְבָאוֹת אִם לֹא אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי&quot; </p><p>  נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים = אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי</p><p> וּתְמֻנַת יהוה יַבִּיט - מַרְאוֹת אֱלֹהִים = בְּרָכָה עַד בְּלִי דָי = בִּרְכַּת יהוה הִיא תַעֲשִׁיר וְלֹא יוֹסִף עֶצֶב עִמָּהּ</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-05 16:03:46'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1201_1.html',
		'<p>יחזקאל א1: &quot;וַיְהִי בִּשְׁלֹשִׁים שָׁנָה בָּרְבִיעִי בַּחֲמִשָּׁה לַחֹדֶשׁ וַאֲנִי בְתוֹךְ הַגּוֹלָה עַל נְהַר כְּבָר נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים&quot;</p><p>מלאכי ג10: &quot;הָבִיאוּ אֶת כָּל הַמַּעֲשֵׂר אֶל בֵּית הָאוֹצָר וִיהִי טֶרֶף בְּבֵיתִי וּבְחָנוּנִי נָא בָּזֹאת אָמַר יהוה צְבָאוֹת אִם לֹא אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי&quot;</p><p>נִפְתְּחוּ הַשָּׁמַיִם וָאֶרְאֶה מַרְאוֹת אֱלֹהִים = אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי</p><p>וּתְמֻנַת יהוה יַבִּיט - מַרְאוֹת אֱלֹהִים = בְּרָכָה עַד בְּלִי דָי = בִּרְכַּת יהוה הִיא תַעֲשִׁיר וְלֹא יוֹסִף עֶצֶב עִמָּהּ</p><p>תהלים יז15: &quot;אֲנִי בְּצֶדֶק אֶחֱזֶה פָנֶיךָ אֶשְׂבְּעָה בְהָקִיץ תְּמוּנָתֶךָ&quot; --- וּתְמֻנַת יהוה יַבִּיט - מַרְאוֹת אֱלֹהִים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-05 16:12:27'
		)
		;

