		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2690_2.html',
		'<p>מה בין **וַיְדַבֵּר אֵלָיו** לבין  **יְדַבֶּר בִּי**</p><p>---------------------------------------------</p><p>וַיְדַבֵּר אֵלָיו</p><p>במדבר יא25: &quot;וַיֵּרֶד יהוה בֶּעָנָן וַיְדַבֵּר אֵלָיו....... וַיָּאצֶל מִן הָרוּחַ אֲשֶׁר עָלָיו וַיִּתֵּן עַל שִׁבְעִים אִישׁ הַזְּקֵנִים וַיְהִי כְּנוֹחַ עֲלֵיהֶם הָרוּחַ וַיִּתְנַבְּאוּ וְלֹא יָסָפוּ&quot;</p><p>במדבר ז89: &quot;וּבְבֹא מֹשֶׁה אֶל אֹהֶל מוֹעֵד לְדַבֵּר אִתּוֹ וַיִּשְׁמַע אֶת הַקּוֹל מִדַּבֵּר אֵלָיו מֵעַל הַכַּפֹּרֶת אֲשֶׁר עַל אֲרֹן הָעֵדֻת מִבֵּין שְׁנֵי הַכְּרֻבִים וַיְדַבֵּר אֵלָיו&quot;.......</p><p>-</p><p> יְדַבֶּר בִּי</p><p>שמואל ב כג2: &quot;רוּחַ יהוה דִּבֶּר בִּי....... וּמִלָּתוֹ עַל לְשׁוֹנִי&quot;</p><p>חבקוק ב1: &quot;עַל מִשְׁמַרְתִּי אֶעֱמֹדָה וְאֶתְיַצְּבָה עַל מָצוֹר וַאֲצַפֶּה לִרְאוֹת מַה יְדַבֶּר בִּי....... וּמָה אָשִׁיב עַל תּוֹכַחְתִּי&quot;</p><p>-</p><p>“יְדַבֵּר בִּי” = הבינה הפנימית האישית שלך, השמים הפרטיים שלך, רוח אלהים מתלבשת עליך בתוכך.</p><p>זה הגשמת האלוה שלך התחברות לאני העליון שלך לבינה הפרטית שלך לכן זה נקרא פנימי “יְדַבֵּר בִּי” בתוכי</p><p>ככתוב בספר  איוב כ3: &quot;מוּסַר כְּלִמָּתִי אֶשְׁמָע וְרוּחַ מִבִּינָתִי יַעֲנֵנִי&quot; = זה השמים הפרטיים האישיים שלי שבראשי </p><p>ובינתי תבונתי זה השמים שלי ----- ככתוב בספר משלי ג19: &quot;יהוה בְּחָכְמָה יָסַד אָרֶץ כּוֹנֵן שָׁמַיִם בִּתְבוּנָה&quot; </p><p>-</p><p>וַיְדַבֵּר אֵלָיו = זה השמים החיצונים מעבר לבינתך נשגב מבינתך</p><p>וַיְדַבֵּר אֵלָיו -- זה הבינה הכללית מדברת אליך לאמור השמים הגדולים ולא השמים הפרטיים שלך לכן זה חיצוני </p><p>-</p><p>לסיכום...</p><p>“יְדַבֵּר בִּי” --- זה במסגרת התודעה שלך --- ורק אם התודעה שלך היא דעת-יהוה אז כמו &quot;וַיְדַבֵּר אֵלָיו&quot; </p><p>בראשית ז11: &quot;בִּשְׁנַת שֵׁשׁ מֵאוֹת שָׁנָה לְחַיֵּי נֹחַ בַּחֹדֶשׁ הַשֵּׁנִי בְּשִׁבְעָה עָשָׂר יוֹם לַחֹדֶשׁ בַּיּוֹם הַזֶּה נִבְקְעוּ כָּל מעינות תְּהוֹם רַבָּה וַאֲרֻבֹּת הַשָּׁמַיִם נִפְתָּחוּ&quot; </p><p> נִבְקְעוּ כָּל מעינות תְּהוֹם רַבָּה.......[לאמור דעת אלהים הייתה לנח בימי המבול] וַאֲרֻבֹּת הַשָּׁמַיִם נִפְתָּחוּ</p><p>משלי ג20: &quot;בְּדַעְתּוֹ תְּהוֹמוֹת נִבְקָעוּ....... וּשְׁחָקִים יִרְעֲפוּ טָל&quot; </p><p>[כיום יש מתקשרים מדיומים שנכנסים לטראנס ורוח המת מדבר מגרונם “יְדַבֵּר בִּי” אבל זה אסור!!! כי זה מדרך החושך והטומאה]</p><p>-</p><p>וַיְדַבֵּר אֵלָיו --- זה מגיע מאלהי השמים מהבינה הכללית, השמים הגדולים, מסר שמגיע מעבר לתודעה שלך. כמחשבה מחוץ לקופסה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-07 02:38:13'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

