		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2690_2.html',
		'<p>תהלים יט9: &quot;פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם&quot; </p><p>שמואל א יד29: &quot;וַיֹּאמֶר יוֹנָתָן עָכַר אָבִי אֶת הָאָרֶץ רְאוּ נָא כִּי אֹרוּ עֵינַי .......כִּי טָעַמְתִּי מְעַט דְּבַשׁ הַזֶּה&quot;</p><p>דְּבַשׁ = כמִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם -- כפתיחת העין השלשית בארובות השמים -- מְעַט דְּבַשׁ ולא להגזים</p><p>משלי כד13-14: &quot;אֱכָל בְּנִי דְבַשׁ כִּי טוֹב וְנֹפֶת מָתוֹק עַל חִכֶּךָ כֵּן דְּעֶה חָכְמָה לְנַפְשֶׁךָ אִם מָצָאתָ וְיֵשׁ אַחֲרִית וְתִקְוָתְךָ לֹא תִכָּרֵת&quot; </p><p>על כן נביא האמת האוהב את מִצְוַת יהוה מְאִירַת עֵינָיִם - אוכל מְעַט דְּבַשׁ </p><p>מלכים א יד2-3: &quot;וַיֹּאמֶר יָרָבְעָם לְאִשְׁתּוֹ קוּמִי נָא וְהִשְׁתַּנִּית וְלֹא יֵדְעוּ כִּי אתי[אַתְּ] אֵשֶׁת יָרָבְעָם וְהָלַכְתְּ שִׁלֹה </p><p>הִנֵּה שָׁם אֲחִיָּה הַנָּבִיא....... הוּא דִבֶּר עָלַי לְמֶלֶךְ עַל הָעָם הַזֶּה וְלָקַחַתְּ בְּיָדֵךְ עֲשָׂרָה לֶחֶם וְנִקֻּדִים וּבַקְבֻּק דְּבַשׁ....... וּבָאת אֵלָיו הוּא יַגִּיד לָךְ מַה יִּהְיֶה לַנָּעַר&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-07 04:33:54'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

