		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2674_0.html',
		'<p>אני יודע כי יש הרבה רשעים בעם הזה </p><p>ואני מלחמתי לתת דעת-אלהים להרבות צדיקים </p><p>ואת הצדיקים חפצתי להנהיג לשמור עליהם גם אם יהיו בודדים </p><p>כי מאלה תהיה תקומת ישראל משארית ישראל אשר לא אבדו </p><p> אחיי בני ישראל הצדיקים כל השומעים בקול דיין לעשות דברו </p><p>הנה באתי להצילכם מן העוני </p><p>בעת קומכם השכם-בבקר רחצו במים את כל בשרכם להסיר טומאת המיתה מטומאת המיטה </p><p>התפללו ליהוה אלהים [לא חייב בית כנסת] שתו מלוא הספל מים להשיב רוח אלהים המרחפת על פני המים </p><p>וכעבור שעה קחו סילאן-תמרים ביחד עם חלב או לבן [גיל-אשל] ואמרו כזאת לכבוד הנביא   </p><p>צַדִּיק כַּתָּמָר יִפְרָח !!! &quot;בּוֹטֵחַ בְּעָשְׁרוֹ הוּא יִפֹּל וְכֶעָלֶה צַדִּיקִים יִפְרָחוּ&quot; כי בטחו ביהוה    </p><p>מִי הִגִּיד מֵרֹאשׁ וְנֵדָעָה וּמִלְּפָנִים וְנֹאמַר צַדִּיק ----ואז לאכול התמרים על הב[ו]קר לקבל מסר לנשמהו </p><p>זאת המשמעות של משלי ו21: &quot;קָשְׁרֵם עַל לִבְּךָ תָמִיד עָנְדֵם עַל גַּרְגְּרֹתֶךָ&quot; [לא מדובר בתפילין] </p><p>ישעיהו ב20: &quot;בַּיּוֹם הַהוּא יַשְׁלִיךְ הָאָדָם אֵת אֱלִילֵי כַסְפּוֹ וְאֵת אֱלִילֵי זְהָבוֹ אֲשֶׁר עָשׂוּ לוֹ להשתחות לַחְפֹּר פֵּרוֹת וְלָעֲטַלֵּפִים&quot;</p><p>ישעיהו לא7: &quot;כִּי בַּיּוֹם הַהוּא יִמְאָסוּן אִישׁ אֱלִילֵי כַסְפּוֹ וֶאֱלִילֵי זְהָבוֹ אֲשֶׁר עָשׂוּ לָכֶם יְדֵיכֶם חֵטְא&quot;</p><p>                </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-08 09:00:18'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

