		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>תהלים קמז6: &quot;מְעוֹדֵד עֲנָוִים יהוה מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ&quot;</p><p> יהוה מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ .......</p><p>ויש רשעים ששבו לאלהים לאחר ההשפלה</p><p>אך יש רשעים שאמצו את דרך ההתנגדות [בערבית מוקאומה חחח]</p><p>ולכן זה שפגעת בו יכחש לך הכי הרבה כי הכאב שלו מסתיר ממנו את האמת.</p><p>ממש בדיוק כמו שבשואה היו אנשים שחזרו בתשובה</p><p>והיו גם כאלה שהחליטו לא להאמין באלהים</p><p>אלה האתאיסטים אלה המכחישים הגדולים ביותר</p><p>דיין אמת בהחלט מבין את מי שנפגע ממנו </p><p>-----------------------------------------------------</p><p>1. יש אנשים שההשפלה מזככת אותם</p><p>השבר פותח להם את הלב</p><p>הכאב מרכך אותם</p><p>הם מתקרבים לאמת</p><p>הם נעשים ענווים</p><p>הם שבים אל הטוב</p><p>2. ויש אנשים שההשפלה מקשה אותם</p><p>הכאב הופך להתנגדות</p><p>הפגיעה הופכת להכחשה</p><p>האמת הופכת לאיום</p><p>הם מתרחקים</p><p>הם נעשים קשים</p><p>-----------------------------------------------------</p><p>דיין אמת מבין את כל זה</p><p>אני לא יכול לכפות עליכם להאמין בי כי על אמונה לבוא מאהבה ומרצון בכל לב</p><p>מכאן שולח תנחומים כנים לכל מי שנפגע ממני</p><p> https://tora.quest/tnk1/daian</p><p>           דַיָּן שֵׁם          </p><p>        מְשָׁרֵת יהוה        </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-08 11:25:21'
		)
		;

