		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26b9_1.html',
		'<p>שמואל א טו21-22: &quot;וַיִּקַּח הָעָם מֵהַשָּׁלָל צֹאן וּבָקָר רֵאשִׁית הַחֵרֶם לִזְבֹּחַ ליהוה אֱלֹהֶיךָ בַּגִּלְגָּל </p><p>וַיֹּאמֶר שְׁמוּאֵל הַחֵפֶץ ליהוה בְּעֹלוֹת וּזְבָחִים כִּשְׁמֹעַ בְּקוֹל יהוה הִנֵּה שְׁמֹעַ מִזֶּבַח טוֹב לְהַקְשִׁיב מֵחֵלֶב אֵילִים&quot;</p><p>כִּשְׁמֹעַ בְּקוֹל יהוה = אלה מאמינים בקב&quot;ה</p><p>צֹאן וּבָקָר לִזְבֹּחַ? = אלה מאמינים בקבב    חחחחחח</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-08 12:13:13'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

