		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0108_1.html',
		'<p>ממחרת השבת = ממחרת השבת הראשונה בלוח השנה כי הלוח ניתן בראשית השנה בראש השנה בראש חודש האביב בלוח השמש</p><p>אם ראש חודש האביב .......</p><p>שחל ביום שבת - הלא בשבת אין קציר לכן רק ממחרת השבת הבאה לאמור בעוד 8 ימים יהיה יום הנפת העומר</p><p>אם ביום ראשון - אז ממחרת השבת זה רק עוד שבוע ימים</p><p>אם ביום שני - אז ממחרת השבת רק בעוד ששה ימים</p><p>אם ביום שלשי - אז ממחרת השבת רק בעוד חמישה ימים</p><p>אם ביום רביעי - אז ממחרת השבת זה רק בעוד ארבעה ימים</p><p>אם ביום חמשי - אז ממחרת השבת זה רק בעוד שלושה ימים</p><p>אם ביום ששי - אז ממחרת השבת זה רק בעוד יומים</p><p>ואם ביום שבת - הלא בשבת אין קציר לכן רק ממחרת השבת הבאה לאמור בעוד 8 ימים יהיה יום הנפת העומר</p><p>-</p><p>הפרש הימים בין ראש חודש האביב עד ממחרת השבת ------- אלה הם הימים שאסור לאכול מן התבואה</p><p>ויקרא כג14: &quot;וְלֶחֶם וְקָלִי וְכַרְמֶל לֹא תֹאכְלוּ עַד עֶצֶם הַיּוֹם הַזֶּה עַד הֲבִיאֲכֶם אֶת קָרְבַּן אֱלֹהֵיכֶם חֻקַּת עוֹלָם לְדֹרֹתֵיכֶם בְּכֹל מֹשְׁבֹתֵיכֶם&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-08 17:14:28'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

