		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0416_3.html',
		'<p>מגוחך ביותר שהרבנים אשר מדברים על פרשת קורח כל פעם נדמה להם שהם משה</p><p>אך הם אינם מבינים שמאז חורבן בית שני הם כקורח אשר ניסה לגזול הכהונה מבני אהרן הלוי</p><p>---------------------------------------------------------------------------------------------------------</p><p>בדור הזה הרבנים מתחמקים ובורחים מן המחלוקת לא בגלל שהם משה</p><p>לא בגלל שהם צדיקים בגלל שהם יודעים שהם אשמים ואין להם תשובות</p><p>הם מבינים שאם בויכוח במחלוקת יוודע שהם טועים הם יאבדו את פרנסתם</p><p>-----------------------------------------------------------------------------------------</p><p>כשמנהיג דתי מלמד על פרשת קורח, יש לו פיתוי טבעי לזהות את עצמו עם:</p><p>משה — הצד הצודק</p><p>ולא עם:</p><p>קורח — הצד שטעה</p><p>זו תופעה פסיכולוגית ידועה:</p><p>מנהיגים נוטים לראות את עצמם כצודקים מראש.</p><p>אבל — וזה חשוב —</p><p>המקרא עצמו מזהיר בדיוק מהדבר הזה.</p><p>“וְהָאִישׁ מֹשֶׁה עָנָו מְאֹד”</p><p>משה לא ראה את עצמו כצודק — הוא פחד מהכוח שלו.</p><p>מי שמזהה את עצמו אוטומטית עם משה —כבר לא דומה למשה.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-09 04:12:58'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

