		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>יש מרחק קצר בין הראש ללב, אבל לפעמים זהו המרחק הארוך ביותר שאדם צריך לעבור.</p><p>יש אנשים שבוחרים לחיות רק עם הראש — לסגור את הלב, להקשיח אותו, להדחיק את מה שהוא מרגיש. הם קוראים לזה חכמה.</p><p>הם מתגאים בכך שהם פועלים “רק לפי השכל”, כאילו הרגש הוא חולשה, כאילו הלב הוא אויב שצריך להשתיק.</p><p>ויש אחרים שחיים רק עם הלב — נותנים לרגש להוביל אותם לכל מקום, בלי גבולות, בלי מחשבה, בלי עוגן.</p><p>גם זה נראה לפעמים יפה, אבל זה מסוכן. כי לב בלי ראש יכול לסחוף אדם למקומות שהוא לא התכוון להגיע אליהם.</p><p>אבל האמת, רבותיי, היא שהחכמה האמיתית אינה בראש לבד ואינה בלב לבד. החכמה האמיתית נמצאת בדיוק במקום שבו שניהם נפגשים.</p><p>במקום שבו הראש נותן כיוון והלב נותן משמעות. במקום שבו השכל שומר שלא ניפול, והלב מזכיר למה בכלל אנחנו הולכים. במקום שבו אנחנו לא רק חושבים נכון — אלא גם מרגישים נכון.</p><p>מי שפועל רק מהראש — ערל-לב</p><p>מי שפועל רק מהלב — לא חכם</p><p>אבל מי שמצליח לשלב ביניהם — זהו אדם שלם. זהו אדם שמבין את עצמו, את האחרים, ואת העולם.</p><p>זהו אדם שיודע מתי לעצור ומתי להעז, מתי לחשוב ומתי להרגיש, מתי להקשיב ללב ומתי לתת לראש להוביל.</p><p>הברכה האמיתית מגיעה כשאנחנו מפסיקים להילחם בין שני החלקים שבתוכנו. כשאנחנו נותנים לראש לחשוב וללב להרגיש,</p><p>ומבינים ששניהם לא אויבים — אלא שותפים. שותפים לדרך, שותפים להחלטות, שותפים לחיים.</p><p>לאמור כמשל כי יש לתת צדקה מאהבה ויראת-אלהים כמשולבים יחדיו</p><p>יש אדם שנותן צדקה רק מטוב לב ולא מיראת אלהים</p><p>ויש אדם שנותן צדקה רק מיראת אלהים כאשר לבו לא שלם עמו</p><p>כי אדם שמקשיב רק לראש חי אמנם חיים נכונים — אבל לא חיים מלאים.</p><p>ואדם שמקשיב רק ללב חי חיים רגשיים מלאים — אבל לא תמיד נכונים.</p><p>ואדם שמקשיב לשניהם — חי חיים שלמים.</p><p>זאת משמעות הברית החדשה באחרית הימים</p><p>ככתוב בספר הנביא ירמיהו פרק 31</p><p>ל הִנֵּה יָמִים בָּאִים נְאֻם-יְהוָה וְכָרַתִּי אֶת-בֵּית יִשְׂרָאֵל וְאֶת-בֵּית יְהוּדָה בְּרִית חֲדָשָׁה.</p><p>לא לֹא כַבְּרִית אֲשֶׁר כָּרַתִּי אֶת-אֲבוֹתָם בְּיוֹם הֶחֱזִיקִי בְיָדָם לְהוֹצִיאָם מֵאֶרֶץ מִצְרָיִם אֲשֶׁר-הֵמָּה הֵפֵרוּ אֶת-בְּרִיתִי וְאָנֹכִי בָּעַלְתִּי בָם נְאֻם-יְהוָה.</p><p>לב כִּי זֹאת הַבְּרִית אֲשֶׁר אֶכְרֹת אֶת-בֵּית יִשְׂרָאֵל אַחֲרֵי הַיָּמִים הָהֵם נְאֻם-יְהוָה נָתַתִּי אֶת-תּוֹרָתִי בְּקִרְבָּם וְעַל-לִבָּם אֶכְתְּבֶנָּה וְהָיִיתִי לָהֶם לֵאלֹהִים וְהֵמָּה יִהְיוּ-לִי לְעָם.</p><p>לג וְלֹא יְלַמְּדוּ עוֹד אִישׁ אֶת-רֵעֵהוּ וְאִישׁ אֶת-אָחִיו לֵאמֹר דְּעוּ אֶת-יְהוָה כִּי-כוּלָּם יֵדְעוּ אוֹתִי לְמִקְּטַנָּם וְעַד-גְּדוֹלָם נְאֻם-יְהוָה כִּי אֶסְלַח לַעֲו‍ֹנָם וּלְחַטָּאתָם לֹא אֶזְכָּר-עוֹד.</p><p>-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- </p><p>נָתַתִּי אֶת-תּוֹרָתִי בְּקִרְבָּם וְעַל-לִבָּם אֶכְתְּבֶנָּה</p><p>לא עוד תורה שנמצאת רק בראש, ולא עוד אמונה שנמצאת רק בלב — </p><p>אלא כתיבה פנימית, חיבור שלם בין השכל לבין הלב, בין הידיעה לבין ההרגשה, בין האדם לבין אלוהיו.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-10 17:25:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

