		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>היום הקצר ביותר 10.10 בלוח דיין [לוח שמשי כלוח היובלים]</p><p>---------------------- 1.1 יום שיוויון האביב בין היום והלילה -- לא האסטרונומי</p><p>יום השוויון האביבי 10.1 [לאמור שוויון האביב האסטרונומי יהיה לאחר 9 ימים מראש חודש השעורה אביב]</p><p>היום הארוך בשנה 10.4</p><p>ויום שיוויון הסתיו 15.7 הוא חג-הסכות בלוח דיין --- הוא ראש השנה לשמיטין ויובלים --- יום השיוויון בין היום והלילה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-10 17:35:36'
		)
		;

SET character_set_client=utf8mb3;
