		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/daian2_0.html',
		'<p>******* הליכה עם אלוהים בתבונה יוצרת בהירות, ובהירות יוצרת בחירות נכונות.*******</p><p>כשאדם מתהלך עם אלוהים בתבונה — הוא רואה. הוא מבחין. הוא יודע לבחור. שום דבר לא מבלבל אותו, שום עטיפה יפה לא מטעה אותו.</p><p>אפילו בסופרמרקט, מול מדף מלא פיתויים, הוא יודע מיד מה טוב ומה רע. לא בגלל שהוא חכם יותר מאחרים — אלא בגלל שהאמת שבתוכו חדה כמו סכין.</p><p>וכשאדם הולך כך, באור, אלוהים מציל אותו מצרות עוד לפני שהן מתקרבות אליו.</p><p>אבל מי שבוחר בדרך השקר — הולך בחושך. הוא לא יודע להבדיל בין טוב לרע, בין אמת לזיוף, בין ברכה למלכודת. ואז הוא נופל. לא במקרה — אלא מפני שהוא עיוור.</p><p>וכשאדם עיוור, תמיד יהיה מישהו שיפיל אותו. תמיד יהיה פיתוי, תמיד יהיה שקר שיתלבש כמו אמת.והוא לא ידע להבחין</p><p>האמת פשוטה:</p><p>מי שהולך עם אלוהים — הולך בבירור.</p><p>מי שהולך עם שקר — הולך לאיבוד.</p><p>זה לא עניין של מזל. זה עניין של דרך.</p><p>תהלים א6: &quot;כִּי יוֹדֵעַ יהוה דֶּרֶךְ צַדִּיקִים וְדֶרֶךְ רְשָׁעִים תֹּאבֵד&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-11 10:38:14'
		)
		;

