		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0416_3.html',
		'<p>https://www.facebook.com/photo/?fbid=987657377353704&amp;set=a.132962562823194</p><p>זה הדור במדינת סדום עתה אמור לי מי הם אלה כל גדולי הדור?  מי הם אלה כָּל-רָאשֵׁי הָעָם?</p><p>כי בספר במדבר כה כתוב:</p><p>א וַיֵּשֶׁב יִשְׂרָאֵל בַּשִּׁטִּים וַיָּחֶל הָעָם לִזְנוֹת אֶל-בְּנוֹת מוֹאָב.  [זנות להטבי&quot;ם עוון גדול שבעתיים]</p><p>ב וַתִּקְרֶאןָ לָעָם לְזִבְחֵי אֱלֹהֵיהֶן וַיֹּאכַל הָעָם וַיִּשְׁתַּחֲווּ לֵאלֹהֵיהֶן.  </p><p>ג וַיִּצָּמֶד יִשְׂרָאֵל לְבַעַל פְּעוֹר וַיִּחַר-אַף יְהוָה בְּיִשְׂרָאֵל.  </p><p>ד וַיֹּאמֶר יְהוָה אֶל-מֹשֶׁה קַח אֶת-כָּל-רָאשֵׁי הָעָם וְהוֹקַע אוֹתָם לַיהוָה נֶגֶד הַשָּׁמֶשׁ וְיָשֹׁב חֲרוֹן אַף-יְהוָה מִיִּשְׂרָאֵל</p><p>על פי התורה יש להוציא להורג את כל גדולי הדור רבנים ופוליטקאים בכירים ככתוב: כָּל-רָאשֵׁי הָעָם</p><p>-</p><p>אני לא קורא לרצח של איש חלילה אבל בהחלט מביא לעדות את דברי התורה</p><p>שידעו כָּל-רָאשֵׁי הָעָם --- כל גדולי הדור רבנים ופוליטקאים בכירים כי הם בני מות </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-11 15:24:57'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0416_3.html',
		'<p>https://www.facebook.com/photo/?fbid=987657377353704&amp;set=a.132962562823194</p><p>זה הדור במדינת סדום עתה אמור לי מי הם אלה כל גדולי הדור? מי הם אלה כָּל-רָאשֵׁי הָעָם?</p><p>כי בספר במדבר כה כתוב:</p><p>א וַיֵּשֶׁב יִשְׂרָאֵל בַּשִּׁטִּים וַיָּחֶל הָעָם לִזְנוֹת אֶל-בְּנוֹת מוֹאָב. [זנות להטבי&quot;ם עוון גדול שבעתיים]</p><p>ב וַתִּקְרֶאןָ לָעָם לְזִבְחֵי אֱלֹהֵיהֶן וַיֹּאכַל הָעָם וַיִּשְׁתַּחֲווּ לֵאלֹהֵיהֶן.</p><p>ג וַיִּצָּמֶד יִשְׂרָאֵל לְבַעַל פְּעוֹר וַיִּחַר-אַף יְהוָה בְּיִשְׂרָאֵל.</p><p>ד וַיֹּאמֶר יְהוָה אֶל-מֹשֶׁה קַח אֶת-כָּל-רָאשֵׁי הָעָם וְהוֹקַע אוֹתָם לַיהוָה נֶגֶד הַשָּׁמֶשׁ וְיָשֹׁב חֲרוֹן אַף-יְהוָה מִיִּשְׂרָאֵל</p><p>על פי התורה יש להוציא להורג את כל גדולי הדור רבנים ופוליטקאים בכירים ככתוב: כָּל-רָאשֵׁי הָעָם</p><p>-</p><p>אני לא קורא לרצח של איש חלילה אבל בהחלט מביא לעדות את דברי התורה</p><p>שידעו כָּל-רָאשֵׁי הָעָם --- כל גדולי הדור רבנים ופוליטקאים בכירים כי הם בני מות</p><p>“אני מצטט את פרשת בעל פעור כדי להראות עד כמה התורה מטילה אחריות מוסרית כבדה על מנהיגים. </p><p>הפסוקים אינם הוראה מעשית לימינו, אלא תזכורת רוחנית לכך שמנהיגות דורשת טוהר מידות. </p><p>אין כאן שום קריאה לפגיעה באיש, אלא לימוד רעיוני בלבד.” אסור במפורש  לקחת את החוק לידיים</p>',
