		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1030_2.html',
		'<p>יחזקאל טו7: &quot;וְנָתַתִּי אֶת פָּנַי בָּהֶם מֵהָאֵשׁ יָצָאוּ וְהָאֵשׁ תֹּאכְלֵם וִידַעְתֶּם כִּי אֲנִי יהוה בְּשׂוּמִי אֶת פָּנַי בָּהֶם&quot;.......</p><p>ירמיהו ג12: &quot;הָלֹךְ וְקָרָאתָ אֶת הַדְּבָרִים הָאֵלֶּה צָפוֹנָה וְאָמַרְתָּ שׁוּבָה מְשֻׁבָה יִשְׂרָאֵל נְאֻם יהוה לוֹא אַפִּיל פָּנַי בָּכֶם כִּי חָסִיד אֲנִי נְאֻם יהוה לֹא אֶטּוֹר לְעוֹלָם&quot;</p><p>כִּי אֲנִי יהוה בְּשׂוּמִי אֶת פָּנַי בָּהֶם  --- או ---  לוֹא אַפִּיל פָּנַי בָּכֶם כִּי חָסִיד אֲנִי</p><p>---------------------------------------------------------------------</p><p>1.כשהעם מתעקש על עוול → “שׂוּמִי אֶת פָּנַי בָּהֶם”</p><p> [כשהעם או הממסד מסרבים לתקן]</p><p>2.כשהעם מבקש לשוב → “לֹא אַפִּיל פָּנַי בָּכֶם”</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-12 14:27:48'
		)
		;

SET character_set_client=utf8mb3;
