		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1030_2.html',
		'<p>יחזקאל טו7: &quot;וְנָתַתִּי אֶת פָּנַי בָּהֶם מֵהָאֵשׁ יָצָאוּ וְהָאֵשׁ תֹּאכְלֵם וִידַעְתֶּם כִּי אֲנִי יהוה בְּשׂוּמִי אֶת פָּנַי בָּהֶם&quot;.......</p><p>ירמיהו ג12: &quot;הָלֹךְ וְקָרָאתָ אֶת הַדְּבָרִים הָאֵלֶּה צָפוֹנָה וְאָמַרְתָּ שׁוּבָה מְשֻׁבָה יִשְׂרָאֵל נְאֻם יהוה לוֹא אַפִּיל פָּנַי בָּכֶם כִּי חָסִיד אֲנִי נְאֻם יהוה לֹא אֶטּוֹר לְעוֹלָם&quot;</p><p>כִּי אֲנִי יהוה בְּשׂוּמִי אֶת פָּנַי בָּהֶם --- או --- לוֹא אַפִּיל פָּנַי בָּכֶם כִּי חָסִיד אֲנִי</p><p>-----------------------------------------------------------------------------------</p><p>שני המשפטים נכונים תלוי בנסיבות</p><p>1.כשהעם מתעקש על עוול → “שׂוּמִי אֶת פָּנַי בָּהֶם” [כשהעם או הממסד מסרבים לתקן]</p><p>תהלים לד17: &quot;פְּנֵי יהוה בְּעֹשֵׂי רָע לְהַכְרִית מֵאֶרֶץ זִכְרָם&quot; ------- </p><p>2.כשהעם מבקש לשוב → “לֹא אַפִּיל פָּנַי בָּכֶם”</p><p>בְּעֹשֵׂי טוב וחסד נאמר עליהם לוֹא אַפִּיל פָּנַי בָּכֶם כִּי חָסִיד-אני כי עם חסיד תתחסד</p><p>שמואל ב כב26: &quot;עִם חָסִיד תִּתְחַסָּד....... עִם גִּבּוֹר תָּמִים תִּתַּמָּם&quot;</p><p>תהלים יח26: &quot;עִם חָסִיד תִּתְחַסָּד....... עִם גְּבַר תָּמִים תִּתַּמָּם&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-12 14:35:56'
		)
		;

