		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2619_1.html',
		'<p></p><p>ירמיהו נ20: &quot;בַּיָּמִים הָהֵם וּבָעֵת הַהִיא נְאֻם יהוה יְבֻקַּשׁ אֶת עון יִשְׂרָאֵל וְאֵינֶנּוּ וְאֶת חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאינָה כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר&quot;.......</p><p>צפניה ג13: &quot;שְׁאֵרִית יִשְׂרָאֵל....... לֹא יַעֲשׂוּ עַוְלָה וְלֹא יְדַבְּרוּ כָזָב וְלֹא יִמָּצֵא בְּפִיהֶם לְשׁוֹן תַּרְמִית כִּי הֵמָּה יִרְעוּ וְרָבְצוּ וְאֵין מַחֲרִיד&quot;</p><p>ישעיהו ד3: &quot;וְהָיָה הַנִּשְׁאָר בְּצִיּוֹן....... וְהַנּוֹתָר בִּירוּשָׁלַים קָדוֹשׁ יֵאָמֶר לוֹ כָּל הַכָּתוּב לַחַיִּים בִּירוּשָׁלַים&quot;</p><p>מלכים ב יט31: &quot;כִּי מִירוּשָׁלַים תֵּצֵא שְׁאֵרִית....... וּפְלֵיטָה מֵהַר צִיּוֹן קִנְאַת יהוה תַּעֲשֶׂה זֹּאת&quot;</p><p>ישעיהו לז32: &quot;כִּי מִירוּשָׁלַים תֵּצֵא שְׁאֵרִית....... וּפְלֵיטָה מֵהַר צִיּוֹן קִנְאַת יהוה צְבָאוֹת תַּעֲשֶׂה זֹּאת&quot;</p><p>מיכה ז18: &quot;מִי אֵל כָּמוֹךָ נֹשֵׂא עון וְעֹבֵר עַל פֶּשַׁע --- לִשְׁאֵרִית נַחֲלָתוֹ....... לֹא הֶחֱזִיק לָעַד אַפּוֹ כִּי חָפֵץ חֶסֶד הוּא&quot;</p><p>----------------------------------------------------------------------------------------------------------------------------------------------------------</p><p>כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר....... לִשְׁאֵרִית נַחֲלָתוֹ.......שְׁאֵרִית יִשְׂרָאֵל.......וְהָיָה הַנִּשְׁאָר בְּצִיּוֹן....... וְהַנּוֹתָר בִּירוּשָׁלַים.......</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-12 15:46:48'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

