		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_6.html',
		'<p>היום הקצר ביותר 10.10 בלוח דיין [לוח שמשי כלוח היובלים]---------------------- 1.1 יום שיוויון האביב בין היום והלילה -- לא האסטרונומייום השוויון האביבי 10.1 [לאמור שוויון האביב האסטרונומי יהיה לאחר 9 ימים מראש חודש השעורה אביב]היום הארוך בשנה 10.4ויום שיוויון הסתיו 15.7 הוא חג-הסכות בלוח דיין --- הוא ראש השנה לשמיטין ויובלים --- יום השיוויון בין היום והלילה     </p><p> https://tora.quest/tnk1/daian</p><p>           דַיָּן שֵׁם                   מְשָׁרֵת יהוה          </p><p>מועד השעורה אביב בראש החודש הראשון המועד המדויק של קציר שעורים 9 ימים לפני יום השיוויון האביב האסטרונומי</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-13 17:40:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1201_1.html',
		'<p>תהלים קב26: &quot;לְפָנִים הָאָרֶץ יָסַדְתָּ וּמַעֲשֵׂה יָדֶיךָ שָׁמָיִם&quot;</p><p>על כן גם ידי האדם הם השמים הפרטיים האישיים שלו</p><p>ואם ידך פתוחה גם השמים פתוחים לך ---- </p><p>יד פתוחה → שמים פתוחים</p><p>יד קפוצה → שמים סגורים</p><p>ספר דברים פרק ט&quot;ו כתוב:</p><p>ז כִּי-יִהְיֶה בְךָ אֶבְיוֹן מֵאַחַד אַחֶיךָ בְּאַחַד שְׁעָרֶיךָ בְּאַרְצְךָ אֲשֶׁר-יְהוָה אֱלֹהֶיךָ נֹתֵן לָךְ לֹא תְאַמֵּץ אֶת-לְבָבְךָ וְלֹא תִקְפֹּץ אֶת-יָדְךָ מֵאָחִיךָ הָאֶבְיוֹן.  </p><p>ח כִּי-פָתֹחַ תִּפְתַּח אֶת-יָדְךָ לוֹ וְהַעֲבֵט תַּעֲבִיטֶנּוּ דֵּי מַחְסֹרוֹ אֲשֶׁר יֶחְסַר לוֹ.  </p><p>ט הִשָּׁמֶר לְךָ פֶּן-יִהְיֶה דָבָר עִם-לְבָבְךָ בְלִיַּעַל לֵאמֹר קָרְבָה שְׁנַת-הַשֶּׁבַע שְׁנַת הַשְּׁמִטָּה וְרָעָה עֵינְךָ בְּאָחִיךָ הָאֶבְיוֹן וְלֹא תִתֵּן לוֹ וְקָרָא עָלֶיךָ אֶל-יְהוָה וְהָיָה בְךָ חֵטְא.  </p><p>י נָתוֹן תִּתֵּן לוֹ וְלֹא-יֵרַע לְבָבְךָ בְּתִתְּךָ לוֹ  כִּי בִּגְלַל הַדָּבָר הַזֶּה יְבָרֶכְךָ יְהוָה אֱלֹהֶיךָ בְּכָל-מַעֲשֶׂךָ וּבְכֹל מִשְׁלַח יָדֶךָ.  </p><p>יא כִּי לֹא-יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ עַל-כֵּן אָנֹכִי מְצַוְּךָ לֵאמֹר פָּתֹחַ תִּפְתַּח אֶת-יָדְךָ לְאָחִיךָ לַעֲנִיֶּךָ וּלְאֶבְיֹנְךָ בְּאַרְצֶךָ.</p><p>מלאכי ג10: &quot;הָבִיאוּ אֶת כָּל הַמַּעֲשֵׂר אֶל בֵּית הָאוֹצָר [לעשות צדקה עם האביונים] וִיהִי טֶרֶף בְּבֵיתִי וּבְחָנוּנִי נָא בָּזֹאת אָמַר יהוה צְבָאוֹת אִם לֹא אֶפְתַּח לָכֶם אֵת אֲרֻבּוֹת הַשָּׁמַיִם וַהֲרִיקֹתִי לָכֶם בְּרָכָה עַד בְּלִי דָי&quot; </p><p>כאן נכנס נחמיה י״ג 13, המתאר מהפכה מוסרית נדירה: </p><p>נחמיה יג13: &quot;וָאוֹצְרָה עַל אוֹצָרוֹת שֶׁלֶמְיָה הַכֹּהֵן וְצָדוֹק הַסּוֹפֵר וּפְדָיָה מִן הַלְוִיִּם וְעַל יָדָם חָנָן בֶּן זַכּוּר בֶּן מַתַּנְיָה כִּי נֶאֱמָנִים נֶחְשָׁבוּ וַעֲלֵיהֶם לַחֲלֹק לַאֲחֵיהֶם&quot;</p><p>נחמיה יג13: &quot;------------------------------------------------------------------------------------------------------- כִּי נֶאֱמָנִים נֶחְשָׁבוּ וַעֲלֵיהֶם לַחֲלֹק לַאֲחֵיהֶם&quot;</p><p>נחמיה לא בהכרח בחר אותם בגלל ייחוס, תפקיד או סמכות, אלא מפני שהיו נאמנים. הוא ידע שהאוצר אינו רכוש של הממסד אלא של החלשים — לוי, גר, יתום ואלמנה — </p><p>ולכן לא נתן “לחתול לשמור על השמנת”. הוא בחר אנשים ישרים, ולא בהכרח אנשים בכירים חשובים. </p><p>המקרא מכיר היטב את הסכנה של שחיתות במוסדות דתיים: כהנים יכולים לקחת לעצמם, לויים יכולים לקחת לעצמם, מנהיגים יכולים לנצל את מעמדם. </p><p>לכן נחמיה קובע עיקרון: כספי ציבור צריכים להיות בידיים של אנשים ישרים — לא בהכרח של אנשים בעלי תפקיד. כהן הוא כהן, ישר הוא ישר — ולא תמיד זה אותו דבר.</p><p>מכאן עולה מסקנה מקראית חדה: יד פתוחה שווה שמים פתוחים — אבל רק אם הידיים שמנהלות את האוצר הן ידיים נאמנות. </p><p>ברכת-אלהים אינה יורדת במקום שבו הצדקה מתערבבת בשחיתות. השמים נפתחים כאשר האדם נותן באמת, וכאשר המנהלים את כספי הציבור עושים זאת ביושר. </p><p>כך מתחברים שני היסודות: נדיבות האדם פותחת את השמים, ונאמנות המנהלים שומרת שהברכה לא תתבזבז ולא תיגזל. </p><p>זהו החיבור העמוק בין מוסר אנושי לברכת השם : יושר + נדיבות = שמים פתוחים.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-13 18:11:55'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0231_0.html',
		'<p>שבוע טוב ומבורך לכל אוהבי אלהי-ישראל באשר הם </p><p>בתם השבת [במוצ&quot;ש] יש אנשים אשר בעת גשתם לערוך את טקס ההבדלה ישר מדליקים את הנר אבל זה כחילול שבת</p><p>כל עוד לא ברכת בהבדלה כאומר מפורשות &quot;ברוך המבדיל בין קודש לחול&quot; הלא אתה עדיין ביום שבת ואסור לך להדליק הנר</p><p>קודם כל עליך לאמור מפורשות &quot;ברוך המבדיל בין קודש לחול&quot; ורק אז אחרי כן תוכל להדליק את הנר -- לשבוע טוב ומבורך</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-13 18:25:58'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

