		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/ljon_jorj_mra_0.html',
		'<p>ומריא יכול להיות כבש- ראה תר\' אונקלוס את הכבש האחד/ית אמרא חד. אמר בהיפוך אותיות מרא מריא.</p>',
