		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/daian2_0.html',
		'<p>לך לישון מוקדם בלילה כדי שתוכל גם לקום ממיטתך מוקדם לפנות בוקר בטרם השחר בעוד חושך לילה</p><p>וכן כתוב על אשת חיל.......</p><p>משלי לא15: &quot;וַתָּקָם בְּעוֹד לַיְלָה....... וַתִּתֵּן טֶרֶף לְבֵיתָהּ וְחֹק לְנַעֲרֹתֶיהָ&quot;</p><p>אם קמת ממיטתך בְּעוֹד לַיְלָה כחצי שעה לפני השחר העולה אז תוכל לברך על &quot;עַפְעַפֵּי שָׁחַר&quot;</p><p>זו ברכה גדולה ומסר עצום לנשמה כי זאת אמונה לראות בשחר את האור הפורץ מן החושך </p><p>איוב מא10: &quot;עֲטִישֹׁתָיו תָּהֶל אוֹר וְעֵינָיו כְּעַפְעַפֵּי שָׁחַר&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-16 02:40:31'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

