		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0226_0.html',
		'<p>אחיי בני ישראל</p><p>כדי להיות קדושים כארץ הקודש עליכם להיות קדושים ולאכול מטובה </p><p>ככתוב בספר דברים ח8: &quot;אֶרֶץ חִטָּה וּשְׂעֹרָה וְגֶפֶן וּתְאֵנָה וְרִמּוֹן אֶרֶץ זֵית שֶׁמֶן וּדְבָשׁ&quot;</p><p>אך כדי להיות נביאים וכהנים כמשכן אהל-מועד עליכם להיות קדושים לשמוע דבר-יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-16 14:40:39'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

