		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0226_0.html',
		'<p>אחיי בני ישראל</p><p>כדי להיות קדושים כארץ הקודש עליכם להיות קדושים ולאכול מטובה</p><p>ככתוב בספר דברים ח8: &quot;אֶרֶץ חִטָּה וּשְׂעֹרָה וְגֶפֶן וּתְאֵנָה וְרִמּוֹן אֶרֶץ זֵית שֶׁמֶן וּדְבָשׁ&quot;</p><p>אך כדי להיות נביאים וכהנים כמשכן אהל-מועד עליכם להיות קדושים לשמוע דבר-יהוה</p><p>----------------------------------------------------------------------------------------------------</p><p>1.קדוש --- זה מבני ישראל</p><p>2.קֹדֶשׁ קָדָשִׁים -- זה הכהנים --- ככתוב בספר דברי הימים א כג13:</p><p> &quot;בְּנֵי עַמְרָם אַהֲרֹן וּמֹשֶׁה וַיִּבָּדֵל אַהֲרֹן לְהַקְדִּישׁוֹ ***קֹדֶשׁ קָדָשִׁים*** הוּא וּבָנָיו עַד עוֹלָם לְהַקְטִיר לִפְנֵי יהוה לְשָׁרְתוֹ וּלְבָרֵךְ בִּשְׁמוֹ עַד עוֹלָם&quot;</p><p>3.  קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ --- זה יהוה אלהים צבאות אלהי ישראל --- ככתוב בספר הנביא</p><p>ישעיהו ו3: &quot;וְקָרָא זֶה אֶל זֶה וְאָמַר קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ יהוה צְבָאוֹת מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-16 15:06:06'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0218_5.html',
		'<p>נחמיה ט30: &quot;וַתִּמְשֹׁךְ עֲלֵיהֶם שָׁנִים רַבּוֹת </p><p>וַתָּעַד בָּם ***בְּרוּחֲךָ = בְּיַד נְבִיאֶיךָ*** וְלֹא הֶאֱזִינוּ וַתִּתְּנֵם בְּיַד עַמֵּי הָאֲרָצֹת&quot;</p><p>דברים כט28: &quot;הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ --- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת&quot;</p><p>הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ = ללא בנים [על כן הנביא ללא ילדים] ------- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ</p><p>במיוחד בדור שאין שלום על ישראל --- לנביא בישראל אין בנים</p><p>אך בדור של ברכת-שלום אתה רואה גם בני בנים</p><p>תהלים קכח6: &quot;וּרְאֵה בָנִים לְבָנֶיךָ שָׁלוֹם עַל יִשְׂרָאֵל&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-17 01:53:18'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0218_5.html',
		'<p>נחמיה ט30: &quot;וַתִּמְשֹׁךְ עֲלֵיהֶם שָׁנִים רַבּוֹת</p><p>וַתָּעַד בָּם ***בְּרוּחֲךָ = בְּיַד נְבִיאֶיךָ*** וְלֹא הֶאֱזִינוּ וַתִּתְּנֵם בְּיַד עַמֵּי הָאֲרָצֹת&quot;</p><p>דברים כט28: &quot;הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ --- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת&quot;</p><p>הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ = ללא בנים [על כן הנביא ללא ילדים] ------- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ</p><p>במיוחד בדור שאין שלום על ישראל --- לנביא בישראל אין בנים</p><p>ספר הנביא ירמיהו טז2: &quot;לֹא תִקַּח לְךָ אִשָּׁה וְלֹא יִהְיוּ לְךָ בָּנִים וּבָנוֹת בַּמָּקוֹם הַזֶּה&quot;</p><p>אך בדור של ברכת-שלום אתה רואה גם בני בנים</p><p>תהלים קכח6: &quot;וּרְאֵה בָנִים לְבָנֶיךָ שָׁלוֹם עַל יִשְׂרָאֵל&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-17 01:56:46'
		)
		;

SET character_set_client=utf8mb3;
