		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0218_5.html',
		'<p>נחמיה ט30: &quot;וַתִּמְשֹׁךְ עֲלֵיהֶם שָׁנִים רַבּוֹת</p><p>וַתָּעַד בָּם ***בְּרוּחֲךָ = בְּיַד נְבִיאֶיךָ*** וְלֹא הֶאֱזִינוּ וַתִּתְּנֵם בְּיַד עַמֵּי הָאֲרָצֹת&quot;</p><p>דברים כט28: &quot;הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ --- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ עַד עוֹלָם לַעֲשׂוֹת אֶת כָּל דִּבְרֵי הַתּוֹרָה הַזֹּאת&quot;</p><p>הַנִּסְתָּרֹת ליהוה אֱלֹהֵינוּ = ללא בנים [על כן הנביא ללא ילדים] ------- וְהַנִּגְלֹת לָנוּ וּלְבָנֵינוּ</p><p>במיוחד בדור שאין שלום על ישראל --- לנביא בישראל אין בנים</p><p>ספר הנביא ירמיהו טז2: &quot;לֹא תִקַּח לְךָ אִשָּׁה וְלֹא יִהְיוּ לְךָ בָּנִים וּבָנוֹת בַּמָּקוֹם הַזֶּה&quot;</p><p>אך בדור של ברכת-שלום אתה רואה גם בני בנים</p><p>תהלים קכח6: &quot;וּרְאֵה בָנִים לְבָנֶיךָ שָׁלוֹם עַל יִשְׂרָאֵל&quot;</p><p>----------------------------------------------------------</p><p>לא לוקחים אשה בדור תרבות של עמי כנען כי אם רק מחו&quot;ל</p><p>בראשית כד3: &quot;וְאַשְׁבִּיעֲךָ ביהוה אֱלֹהֵי הַשָּׁמַיִם וֵאלֹהֵי הָאָרֶץ אֲשֶׁר לֹא תִקַּח אִשָּׁה לִבְנִי מִבְּנוֹת הַכְּנַעֲנִי אֲשֶׁר אָנֹכִי יוֹשֵׁב בְּקִרְבּוֹ&quot;</p><p>על אחת כמה וכמה לא לוקחים אשה בדור של מצעדי גאוה במדינת סדום</p><p>ירמיהו טז9: &quot;כִּי כֹה אָמַר יהוה צְבָאוֹת אֱלֹהֵי יִשְׂרָאֵל הִנְנִי מַשְׁבִּית מִן הַמָּקוֹם הַזֶּה לְעֵינֵיכֶם וּבִימֵיכֶם קוֹל שָׂשׂוֹן וְקוֹל שִׂמְחָה קוֹל חָתָן וְקוֹל כַּלָּה&quot;</p><p>זו גם הסיבה לרווקות המאוחרת בישראל וכן גם לגירושין המכה בעמינו</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-17 02:12:52'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

