		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0526_3.html',
		'<p>מאת: דַיָּן שֵׁם  מְשָׁרֵת יהוה  </p><p>אז מה הסיפור של ברכת כהנים ובמיוחד הברכה מאת הכהן הגדול הוא כֹּהֵן הָרֹאשׁ    </p><p>תהלים קב26: &quot;לְפָנִים הָאָרֶץ יָסַדְתָּ וּמַעֲשֵׂה יָדֶיךָ שָׁמָיִם&quot;.......</p><p>תהלים ח4: &quot;כִּי אֶרְאֶה שָׁמֶיךָ מַעֲשֵׂי אֶצְבְּעֹתֶיךָ .......יָרֵחַ וְכוֹכָבִים אֲשֶׁר כּוֹנָנְתָּה&quot;</p><p>ויקרא ט22: &quot;וַיִּשָּׂא אַהֲרֹן אֶת ידו[יָדָיו] אֶל הָעָם וַיְבָרְכֵם....... וַיֵּרֶד מֵעֲשֹׂת הַחַטָּאת וְהָעֹלָה וְהַשְּׁלָמִים&quot;</p><p>דברים יא21: &quot;לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ&quot;</p><p>וּמַעֲשֵׂה יָדֶיךָ שָׁמָיִם --- וַיִּשָּׂא אַהֲרֹן אֶת ידו[יָדָיו] אֶל הָעָם וַיְבָרְכֵם ---  כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ&quot;</p><p>הכהן הגדול כהן הראש מעשה יָדָיו שָׁמָיִם והוא נושא אצבעות ידיו כשמים אל העם אל עַם-הָאָרֶץ לבָרְכֵם כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ זאת </p><p>-----------------------------------------------------------------------------------------------------------------------------------------------------------</p><p>ופרוש לבאר לכם למען תבינו כי המושג &quot;עַם הָאָרֶץ&quot; ---לא &quot;בור ועם-הארץ&quot; במובן של חזל אלא זה ביטוי לאנשים דלים-פשוטים מבני-ישראל</p><p>ככתוב בספר ...</p><p>מלכים ב כד14: &quot;וְהִגְלָה אֶת כָּל יְרוּשָׁלַים וְאֶת כָּל הַשָּׂרִים וְאֵת כָּל גִּבּוֹרֵי הַחַיִל עשרה[עֲשֶׂרֶת] אֲלָפִים גּוֹלֶה וְכָל הֶחָרָשׁ וְהַמַּסְגֵּר לֹא נִשְׁאַר זוּלַת דַּלַּת עַם הָאָרֶץ&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-17 06:20:37'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

