		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p> כל יום נופלים חללים במלחמה שלא נפסקת רק היום נפלו 4 לוחמים ועוד יפלו רבים</p><p>כי מדינת ישראל מושחתת כל הרשויות המונוציפליות והשלטוניות והכנסת ישראל הכל להטבי&quot;ם</p><p>רבני ישראל רשעים מושחתים טיפשים עמי ארצות לא מועילים כי לא שומעים בקולי בקול דיין </p><p>גם הצבא וגם הדרג המדיני  לא יוכלו לעזור לכם עד שישנו את הקונספציה הזאת</p><p>כי כל המערכת — פוליטית, צבאית, דתית — תקועה בתוך אותה קונספציה של כשלון.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-19 07:44:24'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>כל יום נופלים חללים במלחמה שלא נפסקת רק היום נפלו 4 לוחמים ועוד יפלו רבים</p><p>כי מדינת ישראל מושחתת כל הרשויות המונוציפליות והשלטוניות וכנסת-ישראל הכל להטבי&quot;ם</p><p>רבנים שמתפללים רק להיות עשירים רבנים שתפילתם כזב צריך לסגור להם את הבאסטה</p><p>רבנות שאינה יכולה להגן על העם צריכה להסגר ולשלוח את כל הרבנים לעמל-מלאכה עבודת-כפיים</p><p>רבני ישראל רשעים מושחתים טיפשים עמי ארצות לא מועילים כי לא שומעים בקולי בקול דיין</p><p>גם הצבא וגם הדרג המדיני לא יוכלו לעזור לכם עד שישנו את הקונספציה הזאת</p><p>כי כל המערכת — פוליטית, צבאית, דתית — תקועה בתוך אותה קונספציה של כשלון.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-19 08:22:36'
		)
		;

