		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>אני דיין משרת-יהוה בקודש ודורש כי בני-ישראל ישמעו בקולי לטובתם</p><p>לא בגלל שאני שתלטן חלילה אלא כי אני דיין שופט קדוש ותורתי תורת-חיים</p><p>דברים יז12: &quot;וְהָאִישׁ אֲשֶׁר יַעֲשֶׂה בְזָדוֹן לְבִלְתִּי שְׁמֹעַ אֶל הַכֹּהֵן הָעֹמֵד לְשָׁרֶת שָׁם אֶת יהוה אֱלֹהֶיךָ אוֹ אֶל הַשֹּׁפֵט וּמֵת הָאִישׁ הַהוּא וּבִעַרְתָּ הָרָע מִיִּשְׂרָאֵל&quot;</p><p> וּמֵת הָאִישׁ הַהוּא --- לאמור כי לא נדרש להמיתו בחרב כי אם מן השמים ימות מעצמו לבד --- וזה מה שיקרה לאיש אשר לא ישמע בקול דיין</p><p>כי ידעתי אשר יבואו יְמֵי הָרָעָה על ישראל ואשר לא ישמע בקולי יאבד</p><p>כי אנכי דיין משרת-יהוה ויודע את חוקות יהוה להלך בדרך חיים על פי דברי-יהוה אשר יעמדו באש</p><p>זכריה יג9: &quot;וְהֵבֵאתִי אֶת הַשְּׁלִשִׁית בָּאֵשׁ וּצְרַפְתִּים כִּצְרֹף אֶת הַכֶּסֶף וּבְחַנְתִּים כִּבְחֹן אֶת הַזָּהָב הוּא יִקְרָא בִשְׁמִי וַאֲנִי אֶעֱנֶה אֹתוֹ אָמַרְתִּי עַמִּי הוּא וְהוּא יֹאמַר יהוה אֱלֹהָי&quot;</p><p>הנה האש באה....... ואשר ישמע בקולי ינצל</p><p>ואל יאמרו רבניכם בזדון אנחנו נאמנים רק ל&quot;גדולי ישראל&quot; הלא אלה הרשעים אשר לא ידעו לשמור על עם-ישראל </p><p>ו&quot;מזכי הרבים&quot; מטעמם בקושי שכנעו את המשוכנעים ולא באמת קרבו לבבות </p><p>והם אשמים שעם ישראל הגיע למצבו כיום כאשר בכל המדינה להטבי&quot;ם וכל יום נופלים חללים במלחמה שלא נפסקת</p><p>עתה בני ישראל דעו למי באמת תורת-אלהים-חיים והייתם חכמים ובחרתם בחיים</p><p>http://tora.us.fm/tnk1/daian</p><p>דַיָּן שֵׁם</p><p>מְשָׁרֵת יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-21 13:33:29'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0619_0.html',
		'<p>יחזקאל לג25: &quot;לָכֵן אֱמֹר אֲלֵיהֶם כֹּה אָמַר אֲדֹנָי יהוה עַל הַדָּם תֹּאכֵלוּ וְעֵינֵכֶם תִּשְׂאוּ אֶל גִּלּוּלֵיכֶם וְדָם תִּשְׁפֹּכוּ וְהָאָרֶץ תִּירָשׁוּ&quot;?</p><p>יחזקאל לג26: &quot;עֲמַדְתֶּם עַל חַרְבְּכֶם עֲשִׂיתֶן תּוֹעֵבָה וְאִישׁ אֶת אֵשֶׁת רֵעֵהוּ טִמֵּאתֶם וְהָאָרֶץ תִּירָשׁוּ&quot;?</p><p>ועתה בדור אנשי סדום הלהטבי&quot;ם עוון-ישראל גדול וכבד שבעתיים מניאוף של תּוֹעֵבָה וְאִישׁ אֶת אֵשֶׁת רֵעֵהוּ</p><p>-</p><p>וְהָאָרֶץ תִּירָשׁוּ? נא הבינו כי צידון בדרום לבנון היא חלק בלתי נפרד מארץ כנען אשר על פי התורה הובטחה לאבותינו הקדושים</p><p>והשאלה האם בדור הזה שמדינת ישראל מלאה בלהטבי&quot;ם וכל הרשויות מניפים את דגלי הגאוה ורבני-ישראל מושחתים טפשים עמי-ארצות ולא מועילים והפשע חוגג ברחובות </p><p>האם במצב כזה ארץ-כנען לנחלת ישראל תחשב או שארץ כנען לכנענים-הערבים? זאת שאלה קשה מאד ולכן מתנהלת כעת מלחמה עם הרוגים רבים לישראל עד אם ישובו לאלהים בכל לבם</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-21 16:40:52'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

