		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>פסיכיאטרים וחוקרי מוח בחנו את בדיקות הדם שלי ועשו לי גם צילום רשתית העין ומסקנתם על פי אבחון ריאיון פסיכיאטרי ועל פי נבירה במאמרי באתר הניווט בתנ&quot;ך </p><p>כי אני פסיכופת וזאת רק בגלל שאני לא מתאים לאג\'נדה שלהם</p><p>אם המדע אשר יוכוון על ידי מדיניות להטבי&quot;ת מבקש להחליט מי הוא פסיכופת ורצונו להתערב בשינויים במבנה מוח האדם </p><p>אז הנה מדרון חלקלק ומסוכן עד להחריד בהתערבות המדע בבני אדם אשר השקפתם שונה!! ואיפה הכבוד לאחר ולשונה? אה זה רק ללהטבי&quot;ם </p><p>אם הלהטבי&quot;ם יעלו לשלטון הם יממשו את המדע הנאצי על בני ישראל הצדיקים --- שהוגדרו פסיכופתים רק בגלל שהשקפתם יראת-אלהים וללא מורא אחר </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-22 02:21:07'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

