		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>פסיכיאטרים וחוקרי מוח בחנו את בדיקות הדם שלי ועשו לי גם צילום רשתית העין</p><p>ומסקנתם החליטו על פי אבחון ריאיון פסיכיאטרי ועל פי נבירה במאמרי באתר הניווט בתנ&quot;ך</p><p>כי אני פסיכופת וזאת רק בגלל שאני לא מתאים לאג\'נדה שלהם</p><p>אם המדע אשר יוכוון על ידי מדיניות להטבי&quot;ת מבקש להחליט מי הוא פסיכופת ורצונו להתערב בשינויים במבנה מוח האדם</p><p>אז הנה לכם מדרון חלקלק מאד ומסוכן עד להחריד בהתערבות המדע בבני אדם אשר השקפתם שונה!! ואיפה הכבוד לאחר ולשונה? אה זה רק ללהטבי&quot;ם</p><p>אם הלהטבי&quot;ם יעלו לשלטון הם יממשו את המדע הנאצי על בני ישראל הצדיקים --- שהוגדרו פסיכופתים רק בגלל שהשקפתם יראת-אלהים וללא מורא אחר</p><p>-</p><p>ישפט יהוה ביני ובין כל הרשעים שהכריזו עלי פסיכופת </p><p>אני בכוונה פרסמתי לציבור שהייתי מאושפז במרכז לבריאות הנפש וזאת כדי להרחיק ממני אנשים החושבים על פי סטיגמה </p><p>מחלת הסטיגמה לא פוסחת גם על אנשים בכירים ואני לא מעוניין בכאלה שיחברו אלי כי אם רק בחכמים באמת עם לב פתוח</p><p>-</p><p>ישעיהו נג3: &quot;נִבְזֶה וַחֲדַל אִישִׁים אִישׁ מַכְאֹבוֹת וִידוּעַ חֹלִי וּכְמַסְתֵּר פָּנִים מִמֶּנּוּ נִבְזֶה וְלֹא חֲשַׁבְנֻהוּ&quot; </p><p>ישעיהו נג4: &quot;אָכֵן חֳלָיֵנוּ הוּא נָשָׂא וּמַכְאֹבֵינוּ סְבָלָם וַאֲנַחְנוּ חֲשַׁבְנֻהוּ נָגוּעַ מֻכֵּה אֱלֹהִים וּמְעֻנֶּה&quot;.......</p><p>ירמיהו כט26: &quot;יהוה נְתָנְךָ כֹהֵן תַּחַת יְהוֹיָדָע הַכֹּהֵן לִהְיוֹת פְּקִדִים בֵּית יהוה לְכָל אִישׁ מְשֻׁגָּע וּמִתְנַבֵּא.......</p><p> וְנָתַתָּה אֹתוֹ אֶל הַמַּהְפֶּכֶת וְאֶל הַצִּינֹק&quot; --- ואותי אשפזו במחלקות סגורות עשרות פעמים -- </p><p>כן אחיי מדינת ישראל בלי דעת-אלהים לא בריאה ולא שפויה וזה כשל סדרתי ולא חד-פעמי</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-22 04:55:29'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

