		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26a4_2.html',
		'<p> </p><p>אני גולש באינטרנט - ורואה --- הגוים מקסימים שרים יפה מאד רוקדים יפה מאד אוהבים בעלי חיים ואני ממש אוהב אותם </p><p>אבל ישראלים כולם רשעים רק מחפשים כסף -- רבנים שמבקשים תרומות ועמותות כזב וכל זאת על סמך האינטרנט בלבד </p><p>-</p><p>משלי כח12: &quot;בַּעֲלֹץ צַדִּיקִים רַבָּה תִפְאָרֶת וּבְקוּם רְשָׁעִים יְחֻפַּשׂ אָדָם&quot; </p><p>משלי כח28: &quot;בְּקוּם רְשָׁעִים יִסָּתֵר אָדָם וּבְאָבְדָם יִרְבּוּ צַדִּיקִים&quot; </p><p> בְּקוּם רְשָׁעִים יִסָּתֵר אָדָם = וּבְקוּם רְשָׁעִים יְחֻפַּשׂ אָדָם</p><p>אני מחפש את האדם הנסתר בישראל אלה הצדיקים שמתחבאים בדור הזה מפני הרשעים</p><p>על כן הצדיקים האלה בישראל נסתרים לא נראים וכל הגלויים המפורסמים רובם ככולם רשעים</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-23 01:55:56'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t26a4_2.html',
		'<p>אני גולש באינטרנט - ורואה --- הגוים מקסימים שרים יפה מאד רוקדים יפה מאד אוהבים בעלי חיים ואני ממש אוהב אותם</p><p>אבל ישראלים כולם רשעים רק מחפשים כסף -- רבנים שמבקשים תרומות ועמותות כזב וכל זאת על סמך האינטרנט בלבד</p><p>-</p><p>משלי כח12: &quot;בַּעֲלֹץ צַדִּיקִים רַבָּה תִפְאָרֶת וּבְקוּם רְשָׁעִים יְחֻפַּשׂ אָדָם&quot;</p><p>משלי כח28: &quot;בְּקוּם רְשָׁעִים יִסָּתֵר אָדָם וּבְאָבְדָם יִרְבּוּ צַדִּיקִים&quot;</p><p>בְּקוּם רְשָׁעִים יִסָּתֵר אָדָם = וּבְקוּם רְשָׁעִים יְחֻפַּשׂ אָדָם</p><p>אני מחפש את האדם הנסתר בישראל אלה הצדיקים שמתחבאים בדור הזה מפני הרשעים</p><p>על כן הצדיקים האלה בישראל נסתרים לא נראים וכל הגלויים המפורסמים רובם ככולם רשעים</p><p>בדור הזה בישראל</p><p>צדיקים לא עושים סרטונים</p><p>אנשים טובים לא מחפשים לייקים</p><p>חסד אמיתי נעשה בשקט</p><p>האלגוריתם לא מקדם צניעות</p><p>הרוע תמיד עושה יותר רעש מהטוב</p><p>זה לא אומר שהצדיקים לא קיימים — זה אומר שהם לא גלויים.</p><p>וזה בדיוק מה ששלמה המלך אמר.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-23 02:04:34'
		)
		;

SET character_set_client=utf8mb3;
