		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p></p><p>זכריה יא4-5: &quot;כֹּה אָמַר יהוה אֱלֹהָי רְעֵה אֶת צֹאן הַהֲרֵגָה אֲשֶׁר קֹנֵיהֶן יַהֲרְגֻן וְלֹא יֶאְשָׁמוּ וּמֹכְרֵיהֶן יֹאמַר בָּרוּךְ יהוה וַאעְשִׁר וְרֹעֵיהֶם לֹא יַחְמוֹל עֲלֵיהֶן&quot;</p><p>זכריה י3: &quot;עַל הָרֹעִים חָרָה אַפִּי וְעַל הָעַתּוּדִים אֶפְקוֹד כִּי פָקַד יהוה צְבָאוֹת אֶת עֶדְרוֹ אֶת בֵּית יְהוּדָה וְשָׂם אוֹתָם כְּסוּס הוֹדוֹ בַּמִּלְחָמָה&quot;</p><p>1.</p><p>(א)--צֹאן הַהֲרֵגָה = אלה בני ישראל השכולים ולא רק במלחמה אלה גם אלה העשוקים [במיוחד נכים וקשישים] שעושקים אותם עד מות --</p><p>(ב)--צֹאן הַהֲרֵגָה = כינוי לעם שנמסר בידי מנהיגים מושחתים או אויבים</p><p>רְעֵה אֶת צֹאן הַהֲרֵגָה = אלהי ישראל מצווה על הנביא לרעות עם שנמצא במצב של סעיפים (א) ו- (ב) ניצול דיכוי או סכנה.</p><p>2. </p><p>“קֹנֵיהֶן יַהֲרְגֻן וְלֹא יֶאְשָׁמוּ”</p><p>הכוונה: מי שמרוויחים מהעם —דתית , פוליטית, כלכלית או צבאית — פוגעים בו בלי תחושת אשמה.</p><p>3.</p><p>וּמֹכְרֵיהֶן יֹאמַר בָּרוּךְ יהוה וַאעְשִׁר -------------- זה תיאור ציני של מנהיגים שמדברים בשם שמים, אך בפועל פועלים למען רווח אישי.</p><p>זה שמוכר את בני ישראל ומברך את השם כאומר &quot;השלך על השם יהבך והוא יכלכלך&quot; -- אך בתכלס עושה &quot;השלך על הציבור יהבך והוא יכלכלך&quot;</p><p>4.</p><p>וְרֹעֵיהֶם לֹא יַחְמוֹל עֲלֵיהֶן --- על כן - עַל הָרֹעִים חָרָה אַפִּי = חרון אף-יהוה על כל גדולי הדור רבנים ואנשי ממשל הרועים הרשעים המנהיגים את העם ללא חמלה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-06-23 19:55:23'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

